-- Poems batch 36
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('70dd722d-46ab-4b0c-a711-ceaf6d82555a','顧道士亡弟子以束帛乞銘于余魯望因賦戲贈日休奉和','皮日休','唐','唐诗','tang','','[]','師去東華卻鍊形，門人求我誌金庭。',64,'全唐诗/poet.tang.33000.json','["師去東華卻鍊形，門人求我誌金庭。", "大椿枯後新爲記，仙鶴亡來始有銘。", "瓊板欲刊知不朽，冰紈將受恐通靈。", "君才莫歎無茲分，合注神玄劒解經。"]'),
('155a53e9-12ae-4b30-92c2-a37055f0b5bf','秋夕文宴得遙字','皮日休','唐','唐诗','tang','','[]','啼螿衰葉共蕭蕭，文宴無喧夜轉遙。',64,'全唐诗/poet.tang.33000.json','["啼螿衰葉共蕭蕭，文宴無喧夜轉遙。", "高韻最宜題雪讚，逸才偏稱和雲謠。", "風吹翠蠟應難刻，月照清香太易消。", "無限玄言一杯酒，可能容得蓋寬饒。"]'),
('7983376d-f8af-42ba-a39e-6e20933e57bc','南陽廣文欲於荆襄卜居因而有贈','皮日休','唐','唐诗','tang','','[]','地脉從來是福鄉，廣文高致更無雙。',67,'全唐诗/poet.tang.33000.json','["地脉從來是福鄉，廣文高致更無雙。", "青精飯熟雲侵竈，白{衤劫}裘成雪濺窗。", "度日竹書千萬字，經冬朮煎兩三缸。", "鱸魚自是君家味，莫背松江憶漢江。"]'),
('dfe03fe0-b069-4dcc-b283-cf8cd6e3fc0d','寄毘陵魏處士朴','皮日休','唐','唐诗','tang','','[]','文籍先生不肯官，絮巾衝雪把魚竿。',66,'全唐诗/poet.tang.33000.json','["文籍先生不肯官，絮巾衝雪把魚竿。", "一堆方冊爲侯印，三級幽巖是將[壇]。", "醉少最因吟月冷，瘦多偏爲臥雲寒。", "兔皮衾暖篷舟穩，欲共誰遊七里灘。"]'),
('9d02643b-5365-4118-bf32-06a361a849fd','初冬偶作寄南陽潤卿','皮日休','唐','唐诗','tang','','[]','寓居無事入清冬，雖設樽罍酒半空。',64,'全唐诗/poet.tang.33000.json','["寓居無事入清冬，雖設樽罍酒半空。", "白菊爲霜翻帶紫，蒼苔因雨卻成紅。", "迎潮預遣收魚笱，防雪先教蓋鶴籠。", "唯待支硎最寒夜，共君披氅訪林公。"]'),
('6e019882-6413-489e-b549-8b6d4f7d4238','冬曉章上人院','皮日休','唐','唐诗','tang','','[]','山堂冬曉寂無聞，一句清言憶領軍。',64,'全唐诗/poet.tang.33000.json','["山堂冬曉寂無聞，一句清言憶領軍。", "琥珀珠黏行處雪，椶櫚箒掃臥來雲。", "松扉欲啓如鳴鶴，石鼎初煎若聚蚊。", "不是戀師終去晚，陸機茸內足毛羣。"]'),
('461135a3-239b-4147-a1e1-190cc89ddc07','寄題鏡巖周尊師所居','皮日休','唐','唐诗','tang','','[]','八十餘年住鏡巖，鹿皮巾下雪髟髟。',64,'全唐诗/poet.tang.33000.json','["八十餘年住鏡巖，鹿皮巾下雪髟髟。", "牀寒不奈雲縈枕，經潤何妨雨滴函。", "飲澗猨迴窺絕洞，緣梯人歇倚危杉。", "如何計吏窮於鳥，欲望仙都舉一帆。"]'),
('5716cfa5-dd43-4784-9f97-c4bb3a83e4bc','寒夜文宴得泉字','皮日休','唐','唐诗','tang','','[]','分明競襞七香牋，王郎風姿盡列仙。',64,'全唐诗/poet.tang.33000.json','["分明競襞七香牋，王郎風姿盡列仙。", "盈篋共開華頂藥，滿缾同坼惠山泉。", "蟹因霜重金膏溢，橘爲風多玉腦鮮。", "吟罷不知詩首數，隔林明月過中天。"]'),
('d9b2586c-c6c8-4432-9bf0-a0436690869d','庚寅歲十一月新羅弘惠上人與本國同書請日休爲靈鷲山周禪師碑將還以詩送之','皮日休','唐','唐诗','tang','','[]','三十麻衣弄渚禽，豈知名字徹雞林。',64,'全唐诗/poet.tang.33000.json','["三十麻衣弄渚禽，豈知名字徹雞林。", "勒銘雖即多遺草，越海還能抵萬金。", "鯨鬣曉掀峰正燒，鼇睛夜沒島還陰。", "二千餘字終天別，東望辰韓淚灑襟。"]'),
('68392941-41d8-4d1d-825f-b6da6488f05d','送潤卿博士還華陽','皮日休','唐','唐诗','tang','','[]','雪打篷舟離酒旗，華陽居士半酣歸。',64,'全唐诗/poet.tang.33000.json','["雪打篷舟離酒旗，華陽居士半酣歸。", "逍遙只恐逢雲將，恬澹真應降月妃。", "仙市鹿胎如錦嫩，陰宮燕肉似酥肥。", "公車草合蒲輪壞，爭不教他白日飛。"]'),
('a6d738da-1ef0-4317-a435-ad2740825278','寒日書齋即事三首 一','皮日休','唐','唐诗','tang','','[]','參佐三間似草堂，恬然無事可成忙。',64,'全唐诗/poet.tang.33000.json','["參佐三間似草堂，恬然無事可成忙。", "移時寂歷燒松子，盡日殷勤拂乳牀。", "將近道齋先衣褐，欲清詩思更焚香。", "空庭好待中宵月，獨禮星辰學步罡。"]'),
('7fe88c0b-4b17-45a7-bdce-e572cfab8244','寒日書齋即事三首 二','皮日休','唐','唐诗','tang','','[]','不知何事有生涯，皮褐親裁學道家。',64,'全唐诗/poet.tang.34000.json','["不知何事有生涯，皮褐親裁學道家。", "深夜數甌唯柏葉，清晨一器是雲華。", "盆池有鷺窺蘋沫，石版無人掃桂花。", "江漢欲歸應未得，夜來頻夢赤城霞。"]'),
('a89434e3-a9e5-4ab0-9bdf-aadcb3e296eb','寒日書齋即事三首 三','皮日休','唐','唐诗','tang','','[]','方朔家貧未有車，肯從榮利捨樵漁。',64,'全唐诗/poet.tang.34000.json','["方朔家貧未有車，肯從榮利捨樵漁。", "從公未怪多侵酒，見客唯求轉借書。", "暫聽松風生意足，偶看溪月世情疎。", "如鉤得貴非吾事，合向煙波爲五魚。"]'),
('719ef17d-c4f2-4db5-a003-20563e43357c','臘後送內大德從勗遊天台','皮日休','唐','唐诗','tang','','[]','講散重雲下九天，大君恩賜許隨緣。',63,'全唐诗/poet.tang.34000.json','["講散重雲下九天，大君恩賜許隨緣。", "霜中一鉢無辭乞，湖上孤舟不廢禪。", "夢入瓊樓寒有月，行過石樹凍無煙他時瓜鏡知何用，吳越風光滿御筵。"]'),
('7d43e3ff-6078-4459-a640-27d32c61e8ea','寄題玉霄峰葉涵象尊師所居','皮日休','唐','唐诗','tang','','[]','青冥向上玉霄峰，元始先生戴紫蓉。',64,'全唐诗/poet.tang.34000.json','["青冥向上玉霄峰，元始先生戴紫蓉。", "曉案瓊文光洞壑，夜壇香氣惹杉松。", "閑迎仙客來爲鶴，靜噀靈符去是龍。", "子細捫心無偃骨，欲隨師去肯相容。"]'),
('994c3a5d-d60b-4534-b83b-092fce9f9ec9','奉和魯望寄南陽廣文次韻','皮日休','唐','唐诗','tang','','[]','春彩融融釋凍塘，日精閑嚥坐巖房。',64,'全唐诗/poet.tang.34000.json','["春彩融融釋凍塘，日精閑嚥坐巖房。", "瓊函靜啓從猨覰，金液初開與鶴嘗。", "八會舊文多搭寫，七真遺語剩思量。", "不知夢到爲何處，紅藥滿山煙月香。"]'),
('8b399661-7243-43fa-af6a-a818009d30ff','題支山南峰僧','皮日休','唐','唐诗','tang','','[]','雲侵壞衲重隈肩，不下南峰不記年。',64,'全唐诗/poet.tang.34000.json','["雲侵壞衲重隈肩，不下南峰不記年。", "池裏羣魚曾受戒，林間孤鶴欲參禪。", "雞頭竹上開危徑，鴨脚花中擿廢泉。", "無限吳都堪賞事，何如來此看師眠。"]'),
('4d4fbbd2-6462-4408-bd0e-70d395800562','送董少卿游茅山','皮日休','唐','唐诗','tang','','[]','名卿風度足杓斜，一舸閑尋二許家。',64,'全唐诗/poet.tang.34000.json','["名卿風度足杓斜，一舸閑尋二許家。", "天影曉通金井水，山靈深護玉門沙。", "空壇禮後銷香母，陰洞緣時觸乳花。", "盡待于公作廷尉，不須從此便餐霞。"]'),
('32d4ad43-6744-4942-9dc1-0723ad56f7e0','詶魯望見迎綠罽次韻','皮日休','唐','唐诗','tang','','[]','輕裁鴨綠任金刀，不怕西風斷野蒿。',64,'全唐诗/poet.tang.34000.json','["輕裁鴨綠任金刀，不怕西風斷野蒿。", "詶贈既無青玉案，纖華猶欠赤霜袍。", "煙披怪石難同逸，竹映仙禽未勝高。", "成後料君無別事，只應酣飲詠離騷。"]'),
('ca4dba9f-e1c1-41c3-9a91-e0d1f7825aa7','寄懷南陽潤卿','皮日休','唐','唐诗','tang','','[]','鹿門山下捕魚郎，今向江南作渴羌。',64,'全唐诗/poet.tang.34000.json','["鹿門山下捕魚郎，今向江南作渴羌。", "無事只陪看藕樣，有錢唯欲買湖光。", "醉來渾忘移花處，病起空聞焙藥香。", "何事對君猶有媿，一篷衝雪返華陽。"]'),
('0ee1e079-46f0-4c94-ade0-b3617e03a6e5','魯望憫承吉之孤爲詩序邀予屬和欲用予道振其孤而利之噫承吉之困身後乎魯望視予困與承吉生前孰若哉未有已困而能振人者抑爲之辭用塞良友','皮日休','唐','唐诗','tang','','[]','先生清骨葬煙霞，業破孤存孰爲嗟。',64,'全唐诗/poet.tang.34000.json','["先生清骨葬煙霞，業破孤存孰爲嗟。", "幾篋詩編分貴位，一林石笋散豪家。", "兒過舊宅啼楓影，姬繞荒田泣稗花。", "唯我共君堪便戒，莫將文譽作生涯。"]'),
('fd329561-421d-4b5e-b0a3-ff4deabb3b56','寄潤卿博士','皮日休','唐','唐诗','tang','','[]','高眠可爲要玄纁，鵲尾金爐一世焚。',64,'全唐诗/poet.tang.34000.json','["高眠可爲要玄纁，鵲尾金爐一世焚。", "塵外鄉人爲許掾，山中地主是茅君。", "將收芝菌唯防雪，欲曬圖書不奈雲。", "若使華陽終臥去，漢家封禪用誰文。"]'),
('6b1fa7eb-4658-477b-9a58-622ca51385b5','奉和魯望白菊','皮日休','唐','唐诗','tang','','[]','已過重陽半月天，琅華千點照寒煙。',64,'全唐诗/poet.tang.34000.json','["已過重陽半月天，琅華千點照寒煙。", "蘂香亦似浮金靨，花樣還如鏤玉錢。", "玩影馮妃堪比豔，鍊形蕭史好爭妍。", "無由擿向牙箱裏，飛上方諸贈列仙。"]'),
('36e62f6f-b341-4e1d-9696-f02732fc1e6b','華亭鶴聞之舊矣及來吳中以錢半千得一隻養之殆經歲不幸爲飲啄所誤經夕而卒悼之不已遂繼以詩南陽潤卿博士浙東德師侍御毘陵魏不琢處士東吳陸魯望秀才及厚於予者悉寄之請垂見和','皮日休','唐','唐诗','tang','','[]','池上低摧病不行，誰教仙魄反層城。',64,'全唐诗/poet.tang.34000.json','["池上低摧病不行，誰教仙魄反層城。", "陰苔尚有前朝跡，皎月新無昨夜聲。", "菰米正殘三日料，筠籠休礙九霄程。", "不知此恨何時盡，遇著雲泉即愴情。"]'),
('ef09f295-4911-43d2-a86f-69bf36315a04','傷開元觀顧道士','皮日休','唐','唐诗','tang','','[]','協晨宮上啓金扉，詔使先生坐蛻歸。',64,'全唐诗/poet.tang.34000.json','["協晨宮上啓金扉，詔使先生坐蛻歸。", "鶴有一聲應是哭，丹無餘粒恐潛飛。", "煙淒玉笥封雲篆，月慘琪花葬羽衣。", "腸斷雷平舊遊處，五芝無影草微微。"]'),
('db480703-258d-4f0a-b209-cc82ba3350b7','醉中即席贈潤卿博士','皮日休','唐','唐诗','tang','','[]','適越遊吳一散仙，銀缾玉柄兩翛然。',64,'全唐诗/poet.tang.34000.json','["適越遊吳一散仙，銀缾玉柄兩翛然。", "茅山頂上攜書簏，笠澤心中漾酒船。", "桐木布溫吟倦後，桃花飯熟醉醒前。", "謝安四十餘方起，猶自高閑得數年。"]'),
('78939f21-3c87-4a39-8954-51086fc6830c','偶留羊振文先輩及一二文友小飲日休以眼病初平不敢飲酒遣侍密歡因成四韻','皮日休','唐','唐诗','tang','','[]','謝莊初起恰花晴，強侍紅筵不避觥。',64,'全唐诗/poet.tang.34000.json','["謝莊初起恰花晴，強侍紅筵不避觥。", "久斷杯盂華蓋喜，忽聞歌吹谷神驚。", "䙰褷正重新開柳，呫囁難通乍囀鶯。", "猶有僧虔多蜜炬，不辭相伴到天明。"]'),
('0e70f181-d336-4125-b8e3-11b280d38fe2','奉送浙東德師侍御罷府西歸','皮日休','唐','唐诗','tang','','[]','建安才子太微仙，暫上金臺許二年。',64,'全唐诗/poet.tang.34000.json','["建安才子太微仙，暫上金臺許二年。", "形影欲歸溫室樹，夢魂猶傍越溪蓮。", "空將海月爲京信，尚使樵風送酒船。", "從此受恩知有處，免爲傖鬼恨吳天。"]'),
('60558d98-1895-4b5d-bc3e-5bed6d5c313e','送羊振文先輩往桂陽歸覲','皮日休','唐','唐诗','tang','','[]','桂陽新命下彤墀，彩服行當欲雪時。',64,'全唐诗/poet.tang.34000.json','["桂陽新命下彤墀，彩服行當欲雪時。", "登第已聞傳禰賦，問安猶聽講韓詩。", "竹人臨水迎符節，風母穿雲避信旗。", "無限湘中悼騷恨，憑君此去謝江蘺。"]'),
('1c8f4370-5613-40cf-8c28-a6d4536cf314','褚家林亭','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','廣亭遙對舊娃宮，竹島蘿溪委曲通。',64,'全唐诗/poet.tang.34000.json','["廣亭遙對舊娃宮，竹島蘿溪委曲通。", "茂苑樓臺低檻外，太湖魚鳥徹池中。", "蕭疎桂影移茶具，狼籍蘋花上釣筒。", "爭得共君來此住，便披鶴氅對清風。"]'),
('e268c498-ac2c-46bb-b1db-76f43de3eeb2','送圓載上人歸日本國','皮日休','唐','唐诗','tang','','[]','講殿談餘著賜衣，椰帆卻返舊禪扉。',64,'全唐诗/poet.tang.34000.json','["講殿談餘著賜衣，椰帆卻返舊禪扉。", "貝多紙上經文動，如意缾中佛爪飛。", "颶母影邊持戒宿，波神宮裏受齋歸。", "家山到日將何入，白象新秋十二圍。"]'),
('e905c088-2149-446f-b6da-0361f0f1e9c9','重送','皮日休','唐','唐诗','tang','','[]','雲濤萬里最東頭，射馬臺深玉署秋。',64,'全唐诗/poet.tang.34000.json','["雲濤萬里最東頭，射馬臺深玉署秋。", "無限屬城爲躶國，幾多分界是亶州。", "取經海底開龍藏，誦咒空中散蜃樓。", "不奈此時貧且病，乘桴直欲伴師遊。"]'),
('c6ba1830-90f1-46ec-9c0d-d5061bd43cce','潤卿遺青䭀飯兼之一絕聊用荅謝','皮日休','唐','唐诗','tang','','[]','傳得三元䭀飯名，大宛聞說有仙卿。',64,'全唐诗/poet.tang.34000.json','["傳得三元䭀飯名，大宛聞說有仙卿。", "分泉過屋舂青稻，拂霧彯衣折紫莖。", "蒸處不教雙鶴見，服來唯怕五雲生。", "草堂空坐無飢色，時把金津漱一聲。"]'),
('72806c1c-61a0-41e1-a694-12b1a1598ca0','鴛鴦二首 一','皮日休','唐','唐诗','tang','','[]','雙絲絹上爲新樣，連理枝頭是故園。',64,'全唐诗/poet.tang.34000.json','["雙絲絹上爲新樣，連理枝頭是故園。", "翠浪萬迴同過影，玉沙千處共棲痕。", "若非足恨佳人魄，即是多情年少魂。", "應念孤飛爭別宿，蘆花蕭瑟雨黃昏。"]'),
('6be1e1c0-de13-4551-b30c-66955ac3c8f6','鴛鴦二首 二','皮日休','唐','唐诗','tang','','[]','鈿𨯥雕鏤費深功，舞妓衣邊繡莫窮。',64,'全唐诗/poet.tang.34000.json','["鈿𨯥雕鏤費深功，舞妓衣邊繡莫窮。", "無日不來湘渚上，有時還在鏡湖中。", "煙濃共拂芭蕉雨，浪細雙遊菡萏風。", "應笑豪家鸚鵡伴，年年徒被鎖金籠。"]'),
('b2326c5f-68bc-41d0-ba00-6fba3cb629f8','傷小女','皮日休','唐','唐诗','tang','','[]','一歲猶未滿，九泉何太深。',24,'全唐诗/poet.tang.34000.json','["一歲猶未滿，九泉何太深。", "唯餘卷書草，相對共傷心。"]'),
('8be95a0c-7676-49f2-bf54-441d9a1b2a56','秋江曉望','皮日休','唐','唐诗','tang','','[]','萬頃湖天碧，一星飛鷺白。',24,'全唐诗/poet.tang.34000.json','["萬頃湖天碧，一星飛鷺白。", "此時放懷望，不厭爲浮客。"]'),
('3771b63b-bb2e-4e63-afed-12ddc6d1e539','閑夜酒醒','皮日休','唐','唐诗','tang','','[]','醒來山月高，孤枕羣書裏。',24,'全唐诗/poet.tang.34000.json','["醒來山月高，孤枕羣書裏。", "酒渴漫思茶，山童呼不起。"]'),
('f56a36fe-6139-4ffd-a38f-afcce31c6ef6','和魯望風人詩三首 一','皮日休','唐','唐诗','tang','','[]','刻石書離恨，因成別後悲。',24,'全唐诗/poet.tang.34000.json','["刻石書離恨，因成別後悲。", "莫言春繭薄，猶有萬重思。"]'),
('2b94b546-cf83-458b-9a02-a4f2c270e622','和魯望風人詩三首 二','皮日休','唐','唐诗','tang','','[]','鏤出容刀飾，親逢巧笑難。',24,'全唐诗/poet.tang.34000.json','["鏤出容刀飾，親逢巧笑難。", "日中騷客佩，爭奈即闌干。"]'),
('1e2cf08f-fc4e-4c8e-a4de-251895a51d42','和魯望風人詩三首 三','皮日休','唐','唐诗','tang','','[]','江上秋聲起，從來浪得名。',24,'全唐诗/poet.tang.34000.json','["江上秋聲起，從來浪得名。", "逆風猶挂席，若不會凡情。"]'),
('806923da-4389-4936-8191-07798c192e10','古函關','皮日休','唐','唐诗','tang','','[]','破落古關城，猶能扼帝京。',24,'全唐诗/poet.tang.34000.json','["破落古關城，猶能扼帝京。", "今朝行客過，不待曉雞鳴。"]'),
('20edc4ff-7afd-4a52-a5ec-905b4b486d8a','聰明泉','皮日休','唐','唐诗','tang','','[]','一勺如瓊液，將愚擬望賢。',24,'全唐诗/poet.tang.34000.json','["一勺如瓊液，將愚擬望賢。", "欲知心不變，還似飲貪泉。"]'),
('18728bd3-126c-41e7-a794-deea2b067e51','史處士','皮日休','唐','唐诗','tang','','[]','山期須早赴，世累莫遲留。',24,'全唐诗/poet.tang.34000.json','["山期須早赴，世累莫遲留。", "忽遇狂風起，閑心不自由。"]'),
('57b36469-4476-4d60-80b8-738e051e8124','芳草渡','皮日休','唐','唐诗','tang','','[]','溪南越鄉音，古柳渡江深。',24,'全唐诗/poet.tang.34000.json','["溪南越鄉音，古柳渡江深。", "日晚無來客，閑船繫綠陰。"]'),
('b0eac395-46d4-4f8a-a084-adac771db81c','古宮詞三首 一','皮日休','唐','唐诗','tang','','[]','樓殿倚明月，參差如亂峰。',24,'全唐诗/poet.tang.34000.json','["樓殿倚明月，參差如亂峰。", "宮花半夜發，不待景陽鐘。"]'),
('0f31b462-6701-4f9c-864b-7369d2ac512c','古宮詞三首 二','皮日休','唐','唐诗','tang','','[]','閑騎小步馬，獨遶萬年枝。',24,'全唐诗/poet.tang.34000.json','["閑騎小步馬，獨遶萬年枝。", "盡日看花足，君王自不知。"]'),
('919ba400-76f3-49a1-aa14-c9acbad68553','古宮詞三首 三','皮日休','唐','唐诗','tang','','[]','玉枕寐不足，宮花空觸簷。',24,'全唐诗/poet.tang.34000.json','["玉枕寐不足，宮花空觸簷。", "梁間燕不睡，應怪夜明簾。"]'),
('59b9c7dd-04ba-446d-95e9-cfdeb477d767','春日陪崔諫議櫻桃園宴','皮日休','唐','唐诗','tang','','[]','萬樹香飄水麝風，蠟燻花雪盡成紅。',32,'全唐诗/poet.tang.34000.json','["萬樹香飄水麝風，蠟燻花雪盡成紅。", "夜深歡態狀不得，醉客圖開明月中。"]'),
('1e01d799-ea31-44b9-beda-39f919271104','松江早春','皮日休','唐','唐诗','tang','','[]','松陵清淨雪消初，見底新安恐未如。',32,'全唐诗/poet.tang.34000.json','["松陵清淨雪消初，見底新安恐未如。", "穩凭船舷無一事，分明數得鱠殘魚。"]'),
('eb2c63be-c0e6-4780-be8f-922644353b70','女墳湖','皮日休','唐','唐诗','tang','','[]','萬貴千奢已寂寥，可憐幽憤爲誰嬌。',32,'全唐诗/poet.tang.34000.json','["萬貴千奢已寂寥，可憐幽憤爲誰嬌。", "須知韓重相思骨，直在芙蓉向下消。"]'),
('fbe62480-4dbf-44bd-adee-6686095afa8a','泰伯廟','皮日休','唐','唐诗','tang','','[]','一廟爭祠兩讓君，幾千年後轉清[芬]。',34,'全唐诗/poet.tang.34000.json','["一廟爭祠兩讓君，幾千年後轉清[芬]。", "當時盡解稱高義，誰敢教他莽卓聞。"]'),
('c28d617b-cd14-40bd-a004-6b49bfd89bfd','宿木蘭院','皮日休','唐','唐诗','tang','','[]','木蘭院裏雙棲鶴，長被金鉦聒不眠。',32,'全唐诗/poet.tang.34000.json','["木蘭院裏雙棲鶴，長被金鉦聒不眠。", "今夜宿來還似爾，到明無計夢雲泉。"]'),
('80a56e85-7a2a-443f-9c5c-de4f6623b245','重題薔薇','皮日休','唐','唐诗','tang','','[]','濃似猩猩初染素，輕如燕燕欲凌空。',32,'全唐诗/poet.tang.34000.json','["濃似猩猩初染素，輕如燕燕欲凌空。", "可憐細麗難勝日，照得深紅作淺紅。"]'),
('0f347949-2a6a-447c-9e8a-60f9b6094f0a','春夕酒醒','皮日休','唐','唐诗','tang','','[]','四弦纔罷醉蠻奴，酃醁餘香在翠爐。',32,'全唐诗/poet.tang.34000.json','["四弦纔罷醉蠻奴，酃醁餘香在翠爐。", "夜半醒來紅蠟短，一枝寒淚作珊瑚。"]'),
('b56dbedd-5899-4ff1-a954-ea40534388ad','青門閑泛','皮日休','唐','唐诗','tang','','[]','青翰虛徐夏思清，愁煙漠漠荇花平。',32,'全唐诗/poet.tang.34000.json','["青翰虛徐夏思清，愁煙漠漠荇花平。", "醉來欲把田田葉，盡裹當時醒酒鯖。"]'),
('210076fa-9033-40c3-8a90-0cc079083d43','木蘭後池三詠 重臺蓮花','皮日休','唐','唐诗','tang','','[]','欹紅婑媠力難任，每葉頭邊半米金。',32,'全唐诗/poet.tang.34000.json','["欹紅婑媠力難任，每葉頭邊半米金。", "可得教他水妃見，兩重元是一重心。"]'),
('26de7702-1236-4736-8e37-9bc5098d5c0a','木蘭後池三詠 浮萍','皮日休','唐','唐诗','tang','','[]','嫩似金脂颺似煙，多情渾欲擁紅蓮。',32,'全唐诗/poet.tang.34000.json','["嫩似金脂颺似煙，多情渾欲擁紅蓮。", "明朝擬附南風信，寄與湘妃作翠鈿。"]'),
('cf9a0162-36c9-4ca6-bed6-b98152f96764','木蘭後池三詠 白蓮','皮日休','唐','唐诗','tang','','[]','但恐醍醐難並潔，秖應薝蔔可齊香。',32,'全唐诗/poet.tang.34000.json','["但恐醍醐難並潔，秖應薝蔔可齊香。", "半垂金粉知何似，靜婉臨溪照額黃。"]'),
('244d56ad-693a-4d59-8f78-4733f43ea221','重題後池','皮日休','唐','唐诗','tang','','[]','細雨闌珊眠鷺覺，鈿波悠漾並鴛嬌。',32,'全唐诗/poet.tang.34000.json','["細雨闌珊眠鷺覺，鈿波悠漾並鴛嬌。", "適來會得荆王意，秖爲蓮莖重細腰。"]'),
('7e4b14f8-93bf-4f8c-b2ee-74e5235fe359','庭中初植松桂魯望偶題奉和次韻','皮日休','唐','唐诗','tang','','[]','毿毿綠髪垂輕露，獵獵丹華動細風。',32,'全唐诗/poet.tang.34000.json','["毿毿綠髪垂輕露，獵獵丹華動細風。", "恰似青童君欲會，儼然相向立庭中。"]'),
('c6f5a26c-b3d4-43e7-a521-5912808eb1b1','魯望戲題書印囊奉和次韻','皮日休','唐','唐诗','tang','','[]','金篆方圓一寸餘，可憐銀艾未思渠。',32,'全唐诗/poet.tang.34000.json','["金篆方圓一寸餘，可憐銀艾未思渠。", "不知夫子將心印，印破人間萬卷書。"]'),
('81fa525b-ae2e-4d86-8397-85757c742433','館娃宮懷古五絕 一','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','綺閤飄香下太湖，亂兵侵曉上姑蘇。',32,'全唐诗/poet.tang.34000.json','["綺閤飄香下太湖，亂兵侵曉上姑蘇。", "越王大有堪羞處，秖把西施賺得吳。"]'),
('cf213c77-954f-4d7d-8e08-a61a34b898d1','館娃宮懷古五絕 二','皮日休','唐','唐诗','tang','','[]','鄭妲無言下玉墀，夜來飛箭滿罘罳。',32,'全唐诗/poet.tang.34000.json','["鄭妲無言下玉墀，夜來飛箭滿罘罳。", "越王定指高臺笑，却見當時金鏤楣。"]'),
('f21805fb-39a6-42d4-8413-6beb7d99fd6c','館娃宮懷古五絕 三','皮日休','唐','唐诗','tang','','[]','半夜娃宮作戰場，血腥猶雜宴時香。',32,'全唐诗/poet.tang.34000.json','["半夜娃宮作戰場，血腥猶雜宴時香。", "西施不及燒殘蠟，猶爲君王泣數行。"]'),
('ea347ec7-2a68-49a9-8a60-899ce81320df','館娃宮懷古五絕 四','皮日休','唐','唐诗','tang','','[]','素襪雖遮未掩羞，越[兵]猶怕伍員頭。',34,'全唐诗/poet.tang.34000.json','["素襪雖遮未掩羞，越[兵]猶怕伍員頭。", "吳王恨魄今如在，只合西施瀨上遊。"]'),
('f77143ba-7c54-4583-95b3-f9d5d849aeba','館娃宮懷古五絕 五','皮日休','唐','唐诗','tang','','[]','響屧廊中金玉步，采蘋山上綺羅身。',32,'全唐诗/poet.tang.34000.json','["響屧廊中金玉步，采蘋山上綺羅身。", "不知水葬今何處，溪月彎彎欲效顰。"]'),
('a7f3281f-280e-4ac0-bef9-1cdd8e3f6580','虎丘寺西小溪閑泛三絕 一','皮日休','唐','唐诗','tang','','[]','鼓子花明白石岸，桃枝竹覆翠嵐溪。',32,'全唐诗/poet.tang.34000.json','["鼓子花明白石岸，桃枝竹覆翠嵐溪。", "分明似對天台洞，應厭頑仙不肯迷。"]'),
('51fcf8cd-5248-4d18-9ef9-0065da1a61e5','虎丘寺西小溪閑泛三絕 二','皮日休','唐','唐诗','tang','','[]','絕壑秖憐白羽傲，窮溪唯覺錦鱗癡。',32,'全唐诗/poet.tang.34000.json','["絕壑秖憐白羽傲，窮溪唯覺錦鱗癡。", "更深尚有通樵處，或是秦人未可知。"]'),
('78e6f208-9a90-42f7-ba00-09ca6ba96259','虎丘寺西小溪閑泛三絕 三','皮日休','唐','唐诗','tang','','[]','高下不驚紅翡翠，淺深還礙白薔薇。',32,'全唐诗/poet.tang.34000.json','["高下不驚紅翡翠，淺深還礙白薔薇。", "船頭繫箇松根上，欲待逢仙不擬歸。"]'),
('46c8b568-e69e-4eb8-aa49-cb808e316dbe','天竺寺八月十五日夜桂子','皮日休','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u4e2d\u79cb", "\u6842\u82b1", "\u516d\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','玉顆珊珊下月輪，殿前拾得露華新。',32,'全唐诗/poet.tang.34000.json','["玉顆珊珊下月輪，殿前拾得露華新。", "至今不會天中事，應是嫦娥擲與人。"]'),
('d0e91183-38bc-4a69-b254-31bff930267e','釣侶二章 一','皮日休','唐','唐诗','tang','','[]','趁眠無事避風濤，一斗霜鱗換濁醪。',32,'全唐诗/poet.tang.34000.json','["趁眠無事避風濤，一斗霜鱗換濁醪。", "驚怪兒童呼不得，盡衝煙雨漉車螯。"]'),
('0266d93d-fad5-4ef1-8497-6ce6bd347771','釣侶二章 二','皮日休','唐','唐诗','tang','','[]','嚴陵灘勢似雲崩，釣具歸來放石層。',32,'全唐诗/poet.tang.34000.json','["嚴陵灘勢似雲崩，釣具歸來放石層。", "煙浪濺篷寒不睡，更將枯蚌點漁燈。"]'),
('075e544d-2f69-4806-9759-394fa94efad0','寄同年韋校書','皮日休','唐','唐诗','tang','','[]','二年疎放飽江潭，水物山容盡足躭。',32,'全唐诗/poet.tang.34000.json','["二年疎放飽江潭，水物山容盡足躭。", "唯有故人憐未替，欲封乾鱠寄終南。"]'),
('7750ef1e-6f7c-4777-80b0-b762f321e59e','初冬偶作','皮日休','唐','唐诗','tang','','[]','豹皮茵下百餘錢，劉墮閑沽盡醉眠。',32,'全唐诗/poet.tang.34000.json','["豹皮茵下百餘錢，劉墮閑沽盡醉眠。", "酒病校來無一事，鶴亡松老似經年。"]'),
('ac8c6926-70af-4abd-b4aa-d61502f9de22','醉中寄魯望一壺幷一絕','皮日休','唐','唐诗','tang','','[]','門巷寥寥空紫苔，先生應渴解酲杯。',32,'全唐诗/poet.tang.34000.json','["門巷寥寥空紫苔，先生應渴解酲杯。", "醉中不得親相倚，故遣青州從事來。"]'),
('86321e27-a244-4e5b-a420-f9d355b1be2f','更次來韻寄魯望','皮日休','唐','唐诗','tang','','[]','蕭蕭紅葉擲蒼苔，玄晏先生欠一杯。',32,'全唐诗/poet.tang.34000.json','["蕭蕭紅葉擲蒼苔，玄晏先生欠一杯。", "從此問君還酒債，顏延之送幾錢來。"]'),
('74f30293-8c39-4d14-a0cb-f3e0df2998f9','重玄寺雙矮檜','皮日休','唐','唐诗','tang','','[]','撲地枝回是翠鈿，碧絲籠細不成煙。',32,'全唐诗/poet.tang.34000.json','["撲地枝回是翠鈿，碧絲籠細不成煙。", "應如天竺難陀寺，一對狻猊相枕眠。"]'),
('e1f5c39e-d0a2-46c2-98c9-cfd74c7a61fa','奉酬魯望醉中戲贈','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','秦吳風俗昔難同，唯有才情事事通。',32,'全唐诗/poet.tang.34000.json','["秦吳風俗昔難同，唯有才情事事通。", "剛戀水雲歸不得，前身應是太湖公。"]'),
('ddbe127b-6fe1-482b-a1ea-bbf1fb4879e7','臯橋','皮日休','唐','唐诗','tang','','[]','臯橋依舊綠楊中，閭里猶生隱士風。',32,'全唐诗/poet.tang.34000.json','["臯橋依舊綠楊中，閭里猶生隱士風。", "唯我到來居上館，不知何道勝梁鴻。"]'),
('2fa17eef-441f-4e0f-bb10-37d2d71f601c','軍事院霜菊盛開因書一絕寄上諫議','皮日休','唐','唐诗','tang','','[]','金華千點曉霜凝，獨對壺觴又不能。',32,'全唐诗/poet.tang.34000.json','["金華千點曉霜凝，獨對壺觴又不能。", "已過重陽三十日，至今猶自待王弘。"]'),
('22b86d4c-932e-49d1-aca4-bb5fed4074a1','悼鶴','皮日休','唐','唐诗','tang','','[]','莫怪朝來淚滿衣，墜毛猶傍水花飛。',32,'全唐诗/poet.tang.34000.json','["莫怪朝來淚滿衣，墜毛猶傍水花飛。", "遼東舊事今千古，却向人間葬令威。"]'),
('3e0e51e1-c2be-41b4-aa64-cf4bd190e8ab','醉中先起李縠戲贈走筆奉詶','皮日休','唐','唐诗','tang','','[]','麝煙苒苒生銀兔，蠟淚漣漣滴繡閨。',32,'全唐诗/poet.tang.34000.json','["麝煙苒苒生銀兔，蠟淚漣漣滴繡閨。", "舞袖莫欺先醉去，醒來還解驗金泥。"]'),
('050d0475-3bdb-462f-bba7-6c8b7fbbbf1b','奉和魯望招潤卿博士辭以道侶將至之作','皮日休','唐','唐诗','tang','','[]','癭木樽前地胏圖，爲君偏輟俗功夫。',32,'全唐诗/poet.tang.34000.json','["癭木樽前地胏圖，爲君偏輟俗功夫。", "靈真散盡光來此，莫戀安妃在後無。"]'),
('27e06205-1ea4-47ed-b00d-45cb6f1654de','奉和再招','皮日休','唐','唐诗','tang','','[]','飆御已應歸杳眇，博山猶自對氛氳。',32,'全唐诗/poet.tang.34000.json','["飆御已應歸杳眇，博山猶自對氛氳。", "不知入夜能來否，紅蠟先教刻五分。"]'),
('014d8d62-78db-454c-80cb-ab0289c4739c','酒病偶作','皮日休','唐','唐诗','tang','','[]','鬱林步障晝遮明，一炷濃香養病酲。',32,'全唐诗/poet.tang.34000.json','["鬱林步障晝遮明，一炷濃香養病酲。", "何事晚來還欲飲，隔牆聞賣蛤蜊聲。"]'),
('e8a99793-6762-452e-8a28-a16010ccc08b','潤卿魯望寒夜見訪各惜其志遂成一絕','皮日休','唐','唐诗','tang','','[]','世外爲交不是親，醉吟俱岸白綸巾。',32,'全唐诗/poet.tang.34000.json','["世外爲交不是親，醉吟俱岸白綸巾。", "清風月白更三點，未放華陽鶴上人。"]'),
('18ff95b7-7c2d-4060-8d7d-784e8ec18af8','奉和魯望玩金鸂鶒戲贈','皮日休','唐','唐诗','tang','','[]','鏤羽彫毛迥出羣，溫黁飄出麝臍熏。',32,'全唐诗/poet.tang.34000.json','["鏤羽彫毛迥出羣，溫黁飄出麝臍熏。", "夜來曾吐紅茵畔，猶似溪邊睡不聞。"]'),
('84f67de6-d3d8-4029-a846-435dd3175d41','友人許惠酒以詩徵之','皮日休','唐','唐诗','tang','','[]','野客蕭然訪我家，霜威白菊兩三花。',32,'全唐诗/poet.tang.34000.json','["野客蕭然訪我家，霜威白菊兩三花。", "子山病起無餘事，只望蒲臺酒一車。"]'),
('5126a8b4-f3a5-4a0f-b422-7167bc73ae7e','寒夜文讌潤卿有期不至','皮日休','唐','唐诗','tang','','[]','草堂虛灑待高真，不意清齋避世塵。',32,'全唐诗/poet.tang.34000.json','["草堂虛灑待高真，不意清齋避世塵。", "料得焚香無別事，存心應降月夫人。"]'),
('71fc38f0-e40f-48ac-a0f0-68e0f275a90e','汴河懷古二首 一','皮日休','唐','唐诗','tang','','[]','萬艘龍舸綠絲間，載到揚州盡不還。',32,'全唐诗/poet.tang.34000.json','["萬艘龍舸綠絲間，載到揚州盡不還。", "應是天教開汴水，一千餘里地無山。"]'),
('92f88db8-3548-4e2e-87f7-aa0aac87af2c','汴河懷古二首 二','皮日休','唐','唐诗','tang','','[]','盡道隋亡爲此河，至今千里賴通波。',32,'全唐诗/poet.tang.34000.json','["盡道隋亡爲此河，至今千里賴通波。", "若無水殿龍舟事，共禹論功不較多。"]'),
('1faf9880-47a4-4130-930d-cf2786f2ae9c','寄題天台國清寺齊梁體','皮日休','唐','唐诗','tang','','[]','十里松門國清路，飯猨臺上菩提樹。',32,'全唐诗/poet.tang.34000.json','["十里松門國清路，飯猨臺上菩提樹。", "怪來煙雨落晴天，元是海風吹瀑布。"]'),
('e4d5bb73-c562-4b1a-9834-4e72ebeb2679','詠蟹','皮日休','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u8783\u87f9", "\u548f\u7269\u8bd7"]','未遊滄海早知名，有骨還從肉上生。',32,'全唐诗/poet.tang.34000.json','["未遊滄海早知名，有骨還從肉上生。", "莫道無心畏雷電，海龍王處也橫行。"]'),
('9082684d-25bf-40f4-a186-c6224c5d42e8','金錢花','皮日休','唐','唐诗','tang','','[]','陰陽爲炭地爲爐，鑄出金錢不用模。',32,'全唐诗/poet.tang.34000.json','["陰陽爲炭地爲爐，鑄出金錢不用模。", "莫向人間逞顏色，不知還解濟貧無。"]'),
('fa70e811-8631-4efa-bb6b-3dfb29196e35','惠山聽松菴','皮日休','唐','唐诗','tang','','[]','千葉蓮花舊有香，半山金剎照方塘。',32,'全唐诗/poet.tang.34000.json','["千葉蓮花舊有香，半山金剎照方塘。", "殿前日暮高風起，松子聲聲打石牀。"]'),
('f3a096aa-a4f9-468e-938a-d61271f6835d','雜體詩 苦雨雜言寄魯望','皮日休','唐','唐诗','tang','','[]','吳中十日涔涔雨，歊蒸庳下豪家苦。',213,'全唐诗/poet.tang.34000.json','["吳中十日涔涔雨，歊蒸庳下豪家苦。", "可憐臨頓陸先生，獨自翛然守環堵。", "兒飢僕病漏空廚，無人肯典破衣裾。", "{果/虫虫}蠃時時上几案，鼃黽往往跳琴書。", "桃花米斗半百錢，枯荒濕壞炊不然。", "兩牀苮席一素几，仰臥高聲吟太玄。", "知君志氣如鐵石，甌冶雖神銷不得。", "乃知苦雨不復侵，枉費畢星無限力。", "鹿門人作州從事，周章似鼠唯知醉。", "府金廩粟虛請來，憶著先生便知媿。", "媿多饋少真徒然，相見唯知攜酒錢。", "豪華滿眼語不信，不如直上天公牋。", "天公牋，方修次，且榜鳴篷來一醉。"]'),
('ccc8b3bf-c8af-4198-b66b-ddb8becf1558','雜體詩 奉和魯望齊梁怨別次韻','皮日休','唐','唐诗','tang','','[]','芙蓉泣恨紅鉛落，一朵別時煙似幕。',32,'全唐诗/poet.tang.34000.json','["芙蓉泣恨紅鉛落，一朵別時煙似幕。", "鴛鴦剛解惱離心，夜夜飛來櫂邊泊。"]'),
('9cfbb9e3-7474-4e17-9375-a6d8541c07a7','雜體詩 奉和魯望曉起迴文','皮日休','唐','唐诗','tang','','[]','孤煙曉起初原曲，碎樹微分半浪中。',64,'全唐诗/poet.tang.34000.json','["孤煙曉起初原曲，碎樹微分半浪中。", "湖後釣筒移夜雨，竹傍眠几側晨風。", "圖梅帶潤輕霑墨，畫蘚經蒸半失紅。", "無事有杯持永日，共君惟好隱牆東。"]'),
('86bab490-295d-4808-845e-16d1e0d84293','雜體詩 奉詶魯望夏日四聲四首 平聲','皮日休','唐','唐诗','tang','','[]','塘平芙蓉低，庭閑梧桐高。',48,'全唐诗/poet.tang.34000.json','["塘平芙蓉低，庭閑梧桐高。", "清煙埋陽烏，藍空含秋毫。", "冠傾慵移簪，杯乾將餔糟。", "翛然非隨時，夫君真吾曹。"]'),
('59ea2a09-bbec-45da-a65d-cf5f1dfb8f79','雜體詩 奉詶魯望夏日四聲四首 平上聲','皮日休','唐','唐诗','tang','','[]','溝渠通疎荷，浦嶼隱淺篠。',48,'全唐诗/poet.tang.34000.json','["溝渠通疎荷，浦嶼隱淺篠。", "舟閑攢輕蘋，槳動起靜鳥。", "陰稀餘桑閑，縷盡晚繭小。", "吾徒當斯時，此道可以了。"]'),
('f385ef5a-727d-4d27-bcaf-457ae8df8c34','雜體詩 奉詶魯望夏日四聲四首 平去聲','皮日休','唐','唐诗','tang','','[]','怡神時高吟，快意乍四顧。',48,'全唐诗/poet.tang.34000.json','["怡神時高吟，快意乍四顧。", "村深啼愁鵑，浪霽醒睡鷺。", "書疲行終朝，罩困臥至暮。", "吁嗟當今交，暫貴便異路。"]'),
('be00cab6-aced-4f37-b75b-c6dd3785e8d4','雜體詩 奉詶魯望夏日四聲四首 平入聲','皮日休','唐','唐诗','tang','','[]','先生何違時，一室習寂歷。',48,'全唐诗/poet.tang.34000.json','["先生何違時，一室習寂歷。", "松聲將飄堂，岳色欲壓席。", "彈琴奔玄雲，斸藥折白石。", "如教題君詩，若得札玉冊。"]'),
('4981a848-c045-4c18-9ff9-10b04e94ce4c','雜體詩 苦雨中又作四聲詩寄魯望 平聲','皮日休','唐','唐诗','tang','','[]','涔涔將經旬，昏昏空迷天。',48,'全唐诗/poet.tang.34000.json','["涔涔將經旬，昏昏空迷天。", "鸕鷀成羣嬉，芙蓉相偎眠。", "魚通蓑衣城，帆過菱花田。", "秋收吾無望，悲之真徒然。"]'),
('fe40c635-f913-401a-962c-8a929ef40b0d','雜體詩 苦雨中又作四聲詩寄魯望 平上聲','皮日休','唐','唐诗','tang','','[]','河平州橋危，壘晚水鳥上。',48,'全唐诗/poet.tang.34000.json','["河平州橋危，壘晚水鳥上。", "衝崖搜松根，點沼寫芡響。", "舟輕通縈紆，棧墮阻指掌。", "攜橈將尋君，渚滿坐可往。"]'),
('28fa5a1b-4299-4bfe-bc7a-2617026f987c','雜體詩 苦雨中又作四聲詩寄魯望 平去聲','皮日休','唐','唐诗','tang','','[]','狂霖昏悲吟，瘦桂對病臥。',48,'全唐诗/poet.tang.34000.json','["狂霖昏悲吟，瘦桂對病臥。", "檐虛能彯斜，舍蠹易漏破。", "宵愁將琴攻，晝悶用睡過。", "堆書仍傾觴，富貴未換箇。"]'),
('10743f98-8154-46f8-bdf4-61ed8b3b6f5b','雜體詩 苦雨中又作四聲詩寄魯望 平入聲','皮日休','唐','唐诗','tang','','[]','羇棲愁霖中，缺宅屋木惡。',48,'全唐诗/poet.tang.34000.json','["羇棲愁霖中，缺宅屋木惡。", "荷傾還驚魚，竹滴復觸鶴。", "閑僧千聲琴，宿客一笈藥。", "悠然思夫君，忽憶蠟屐著。"]'),
('152f2727-d2dd-409c-b7fe-251f455ba49c','雜體詩 奉和魯望疊韻雙聲二首 疊韻山中吟','皮日休','唐','唐诗','tang','','[]','穿煙泉潺湲，觸竹犢觳觫。',24,'全唐诗/poet.tang.34000.json','["穿煙泉潺湲，觸竹犢觳觫。", "荒篁香牆匡，熟鹿伏屋曲。"]'),
('7efa2022-5391-4cf6-b6ad-1ec76d2798f9','雜體詩 奉和魯望疊韻雙聲二首 雙聲溪上思','皮日休','唐','唐诗','tang','','[]','疎杉低通灘，冷鷺立亂浪。',24,'全唐诗/poet.tang.34000.json','["疎杉低通灘，冷鷺立亂浪。", "草彩欲夷猶，雲容空澹蕩。"]'),
('299d66dc-57f9-4b65-82be-1570afa10e1b','雜體詩 奉和魯望疊韻吳宮詞二首 一','皮日休','唐','唐诗','tang','','[]','侵深尋嶔岑，勢厲衛睥睨。',24,'全唐诗/poet.tang.34000.json','["侵深尋嶔岑，勢厲衛睥睨。", "荒王將鄉亡，細麗蔽袂逝。"]'),
('0a1d8d7b-8a82-4fc7-89f2-75e55c43476c','雜體詩 奉和魯望疊韻吳宮詞二首 二','皮日休','唐','唐诗','tang','','[]','枍指替製曳，康莊傷荒涼。',24,'全唐诗/poet.tang.34000.json','["枍指替製曳，康莊傷荒涼。", "主虜部伍苦，嬙亡房廊香。"]'),
('4654faef-ddd4-4474-8ccd-4ed90b867939','雜體詩 奉和魯望閑居雜題五首 晚秋吟','皮日休','唐','唐诗','tang','','[]','東臯煙雨歸耕日，免去玄冠手刈禾。',32,'全唐诗/poet.tang.34000.json','["東臯煙雨歸耕日，免去玄冠手刈禾。", "火滿酒爐詩在口，今人無計奈儂何。"]'),
('a44dc113-2534-4e52-ab40-64d202955d8a','雜體詩 奉和魯望閑居雜題五首 好詩景','皮日休','唐','唐诗','tang','','[]','青盤香露傾荷女，子墨風流更不言。',32,'全唐诗/poet.tang.34000.json','["青盤香露傾荷女，子墨風流更不言。", "寺寺雲蘿堪度日，京塵到死撲侯門。"]'),
('e480d9d3-d8d2-408b-bb56-8d45e70d985b','雜體詩 奉和魯望閑居雜題五首 醒聞檜','皮日休','唐','唐诗','tang','','[]','解洗餘酲晨半酉，星星仙吹起雲門。',32,'全唐诗/poet.tang.34000.json','["解洗餘酲晨半酉，星星仙吹起雲門。", "耳根無厭聽佳木，會盡山中寂靜源。"]'),
('55e9f3d9-c007-4329-b80f-9f0299a1f256','雜體詩 奉和魯望閑居雜題五首 寺鐘暝','皮日休','唐','唐诗','tang','','[]','百緣斗藪無塵土，寸地章煌欲布金。',32,'全唐诗/poet.tang.34000.json','["百緣斗藪無塵土，寸地章煌欲布金。", "重擊蒲牢唅山日，冥冥煙樹覩棲禽。"]'),
('1aefb735-f7b0-4f11-bb03-58770437e4e6','雜體詩 奉和魯望閑居雜題五首 砌思步','皮日休','唐','唐诗','tang','','[]','襹襹古薜繃危石，切切陰螿應晚田。',32,'全唐诗/poet.tang.34000.json','["襹襹古薜繃危石，切切陰螿應晚田。", "心事萬端何處止，少夷峰下舊雲泉。"]'),
('4c4f96b7-a091-4bef-81ee-7c7730754164','雜體詩 奉和魯望藥名離合夏月即事三首 一','皮日休','唐','唐诗','tang','','[]','季春人病拋芳杜，仲夏溪波繞壞垣。',32,'全唐诗/poet.tang.34000.json','["季春人病拋芳杜，仲夏溪波繞壞垣。", "衣典濁醪身倚桂，心中無事到雲昏。"]'),
('3259a666-932d-42e2-87ad-cbcb4609a11d','雜體詩 奉和魯望藥名離合夏月即事三首 二','皮日休','唐','唐诗','tang','','[]','數曲急溪衝細竹，葉舟來往盡能通。',32,'全唐诗/poet.tang.34000.json','["數曲急溪衝細竹，葉舟來往盡能通。", "草香石冷無辭遠，志在天台一遇中。"]'),
('4c085aea-d122-4321-bda6-08e0bab33d65','雜體詩 奉和魯望藥名離合夏月即事三首 三','皮日休','唐','唐诗','tang','','[]','桂葉似茸含露紫，葛花如綬蘸溪黃。',32,'全唐诗/poet.tang.34000.json','["桂葉似茸含露紫，葛花如綬蘸溪黃。", "連雲更入幽深地，骨錄閑攜相獵郎。"]'),
('5c063d7f-235d-4918-87fc-cad59895410a','雜體詩 懷錫山藥名離合二首 一','皮日休','唐','唐诗','tang','','[]','暗竇養泉容決決，明園護桂放亭亭。',32,'全唐诗/poet.tang.34000.json','["暗竇養泉容決決，明園護桂放亭亭。", "歷山居處當天半，夏裏松風盡足聽。"]'),
('4b864570-6f48-4337-8481-24fd5994242a','雜體詩 懷錫山藥名離合二首 二','皮日休','唐','唐诗','tang','','[]','曉景半和山氣白，薇香清淨雜纖雲。',32,'全唐诗/poet.tang.34000.json','["曉景半和山氣白，薇香清淨雜纖雲。", "實頭自是眠平石，腦側空林看虎羣。"]'),
('f86bd9db-ecd4-4e55-b6d2-ce8fedd99be7','雜體詩 懷鹿門縣名離合二首 一','皮日休','唐','唐诗','tang','','[]','山瘦更培秋後桂，溪澄閑數晚來魚。',32,'全唐诗/poet.tang.34000.json','["山瘦更培秋後桂，溪澄閑數晚來魚。", "臺前過雁盈千百，泉石無情不寄書。"]'),
('23951e9f-ce10-4b4d-bd0c-c6160956ee70','雜體詩 懷鹿門縣名離合二首 二','皮日休','唐','唐诗','tang','','[]','十里松蘿陰亂石，門前幽事雨來新。',32,'全唐诗/poet.tang.34000.json','["十里松蘿陰亂石，門前幽事雨來新。", "野霜濃處憐殘菊，潭上花開不見人。"]'),
('d0017457-d6b4-47bd-8da0-2ac01986fc44','雜體詩 奉和魯望寒日古人名一絕','皮日休','唐','唐诗','tang','','[]','北顧歡遊悲沈宋，南徐陵寢歎齊梁。',32,'全唐诗/poet.tang.34000.json','["北顧歡遊悲沈宋，南徐陵寢歎齊梁。", "水邊韶景無窮柳，寒被江淹一半黃。"]'),
('5ce1e4a6-e96e-4efe-ac5a-494a68c3f39a','雜體詩 胥口即事六言二首 一','皮日休','唐','唐诗','tang','','[]','波光杳杳不極，霽景澹澹初斜。',56,'全唐诗/poet.tang.34000.json','["波光杳杳不極，霽景澹澹初斜。", "黑蛺蝶粘蓮蘂，紅蜻蜓褭蔆花。", "鴛鴦一處兩處，舴艋三家五家。", "會把酒船偎荻，共君作箇生涯。"]'),
('f428c03c-3783-4e70-b0af-14a100b27088','雜體詩 胥口即事六言二首 二','皮日休','唐','唐诗','tang','','[]','拂釣清風細麗，飄蓑暑雨霏微。',56,'全唐诗/poet.tang.34000.json','["拂釣清風細麗，飄蓑暑雨霏微。", "湖雲欲散未散，嶼鳥將飛不飛。", "換酒帩頭把看，載蓮艇子撐歸。", "斯人到死還樂，誰道剛須用機。"]'),
('60268b90-4dce-4805-9cf8-17697d930f68','雜體詩 夜會問荅十 一','皮日休','唐','唐诗','tang','','[]','寒夜清，簾外迢迢星斗明。',28,'全唐诗/poet.tang.34000.json','["寒夜清，簾外迢迢星斗明。", "況有蕭閑洞中客，吟爲紫鳳呼凰聲。"]'),
('2e132cb0-e69b-45f2-aa39-dfde523eea6e','雜體詩 夜會問荅十 二','皮日休','唐','唐诗','tang','','[]','癭木杯，杉贅楠瘤刳得來。',28,'全唐诗/poet.tang.34000.json','["癭木杯，杉贅楠瘤刳得來。", "莫怪家人畔邊笑，渠心祗愛黃金罍。"]'),
('17b0af06-a2a7-4a4a-928c-cd41f64428ca','雜體詩 夜會問荅十 三','皮日休','唐','唐诗','tang','','[]','落霞琴，寥寥山水揚清音。',28,'全唐诗/poet.tang.34000.json','["落霞琴，寥寥山水揚清音。", "玉皇仙馭碧雲遠，空使松風終日吟。"]'),
('59ebac4a-097d-4bfa-875c-bb781c449eaf','雜體詩 夜會問荅十 四','皮日休','唐','唐诗','tang','','[]','蓮花燭，亭亭嫩蘂生紅玉。',28,'全唐诗/poet.tang.34000.json','["蓮花燭，亭亭嫩蘂生紅玉。", "不知含淚怨何人，欲問無由得心曲。"]'),
('a41b9637-bb30-4f75-aa42-fc16af3e7f29','雜體詩 夜會問荅十 五','皮日休','唐','唐诗','tang','','[]','金火障，紅獸飛來射羅幌。',28,'全唐诗/poet.tang.34000.json','["金火障，紅獸飛來射羅幌。", "夜來斜展掩深爐，半睡芙蓉香蕩漾。"]'),
('f3c3199b-5c16-4cd4-a077-9a4c246c0991','雜體詩 夜會問荅十 六','皮日休','唐','唐诗','tang','','[]','憶山月，前溪後溪清復絕。',28,'全唐诗/poet.tang.34000.json','["憶山月，前溪後溪清復絕。", "看看又及桂花時，空寄子規啼處血。"]'),
('300921e1-468b-4870-b9ba-49427be16b9d','雜體詩 夜會問荅十 七','皮日休','唐','唐诗','tang','','[]','錦鯨薦，碧香紅膩承君宴。',28,'全唐诗/poet.tang.34000.json','["錦鯨薦，碧香紅膩承君宴。", "幾度閑眠却覺來，彩鱗飛出雲濤面。"]'),
('8f54e277-db72-410c-83e6-5c0013486c00','雜體詩 夜會問荅十 八','皮日休','唐','唐诗','tang','','[]','懷溪雲，漠漠閑籠鷗鷺羣。',28,'全唐诗/poet.tang.34000.json','["懷溪雲，漠漠閑籠鷗鷺羣。", "有時日暮碧將合，還被魚舟來觸分。"]'),
('622977b9-dd17-4469-952c-91ec4ffa5fdc','雜體詩 夜會問荅十 九','皮日休','唐','唐诗','tang','','[]','霜中笛，落梅一曲瑤華滴。',28,'全唐诗/poet.tang.34000.json','["霜中笛，落梅一曲瑤華滴。", "不知青女是何人，三奏未終頭已白。"]'),
('5a6bd82c-fa19-48f5-9ed3-57332036ca98','雜體詩 夜會問荅十 十','皮日休','唐','唐诗','tang','','[]','月下橋，風外拂殘衰柳條。',28,'全唐诗/poet.tang.34000.json','["月下橋，風外拂殘衰柳條。", "倚欄杆處獨自立，青翰何人吹玉簫。"]'),
('13d496f0-b9f3-4c3e-97e7-1ed24bcfac41','讀襄陽耆舊傳因作詩五百言寄皮襲美','陸龜蒙','唐','唐诗','tang','','[]','漢臯古來雄，山水天下秀。',288,'全唐诗/poet.tang.34000.json','["漢臯古來雄，山水天下秀。", "高當軫翼分，化作英髦囿。", "暴秦之前人，灰滅不可究。", "自從宋生賢，特立冠耆舊。", "離騷既日月，九辯即列宿。", "卓哉悲秋辭，合在風雅右。", "龐公樂幽隱，辟聘無所就。", "祗愛鹿門泉，泠泠倚巖漱。", "孔明臥龍者，潛伏躬耕耨。", "忽遭玄德雲，遂起鱗角鬬。", "三胡節皆峻，二習名亦茂。", "其餘文武家，相望如斥堠。", "緬思齊梁降，寂寞寡清胄。", "凝融爲漪瀾，復結作瑩琇。", "不知粹和氣，有得方大受。", "將生皮夫子，上帝可其奏。", "幷包數公才，用以殿厥後。", "嘗聞兒童歲，嬉戲陳俎豆。", "積漸開詞源，一派分萬溜。", "先崇丘旦室，大懼隳結構。", "次補荀孟垣，所貴亡罅漏。", "仰瞻三皇道，蟣虱在宇宙。", "却視五霸圖，股掌弄孩幼。", "或能醢髖髀，或與翼雛鷇。"]'),
('d6272d0c-1f88-4689-9e20-cd58c806ba09','襲美先輩以龜蒙所獻五百言既蒙見和復示榮唱至於千字提獎之重蔑有稱實再抒鄙懷用伸酬謝','陸龜蒙','唐','唐诗','tang','','[]','洪範分九疇，轉成天下規。',288,'全唐诗/poet.tang.34000.json','["洪範分九疇，轉成天下規。", "河圖孕八卦，煥作玄中奇。", "先開否臧源，次築經緯基。", "粵若魯聖出，正當周德衰。", "越疆必載質，歷國將扶危。", "諸侯恣崛強，王室方陵遲。", "歌鳳時不偶，獲麟心益悲。", "始嗟吾道窮，竟使空言垂。", "首贊五十易，又刪三百詩。", "遂令篇籍光，可竝日月姿。", "向非筆削功，未必無瑕疵。", "迨至夫子沒，微言散如枝。", "所宗既不同，所得亦異宜。", "名法在深刻，虛玄至希夷。", "自從戰伐來，一派縱橫馳。", "寒谷生豔木，沸潭結流澌。", "驚奔失壯士，好惡隨纖兒。", "嬴氏幷六合，勢尊丞相斯。", "加於挾書律，盡取坑焚之。", "南勒會稽頌，北恢胡亥阺。", "猶懷徧巡狩，不暇親維持。", "及漢文景後，鴻生方鎃摫。", "簸揚堯舜風，反作三代吹。", "飄颻四百載，左右爲藩籬。"]'),
('ddd16fbf-3223-44d5-8f01-09a6834faa03','奉酬襲美先輩吳中苦雨一百韻','陸龜蒙','唐','唐诗','tang','','[]','微生參最靈，天與意緒拙。',288,'全唐诗/poet.tang.34000.json','["微生參最靈，天與意緒拙。", "人皆機巧求，百逕無一達。", "家爲唐臣來，奕世唯稷卨。", "只垂青白風，凜凜自貽厥。", "猶殘賜書在，編簡苦斷絕。", "其間忠孝字，萬古光不滅。", "孱孫誠瞢昧，有志常搰搰。", "敢云嗣良弓，但欲終守節。", "諠譁不入耳，讒佞不挂舌。", "仰詠堯舜言，俯遵周孔轍。", "所貪既仁義，豈暇理生活。", "縱有舊田園，拋來亦蕪沒。", "因之成否塞，十載真契闊。", "凍骭一襜褕，飢腸少糠籺。", "甘心付天壤，委分任迴斡。", "笠澤臥孤雲，桐江釣明月。", "盈筐盛芡芰，滿釜煮鱸鱖。", "酒幟風外㩻，茶槍露中擷。", "歌謠非大雅，捃摭爲小說。", "上可補熏莖，傍堪跐芽蘗。", "方當賣罾罩，盡以易紙札。", "蹤跡尚吳門，夢魂先魏闕。", "尋聞天子詔，赫怒誅叛卒。", "宵旰憫烝黎，謨明問征伐。"]'),
('5ae7f372-78fc-4149-9ba4-ea99993fba2e','奉酬襲美先輩初夏見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','積雨晦臯圃，門前煙水平。',276,'全唐诗/poet.tang.34000.json','["積雨晦臯圃，門前煙水平。", "蘋蘅增遙吹，枕席分餘清。", "村斾詫酒美，賒來滿鋞程。", "未必減宣子，何羨謝公榮。", "借宅去人遠，敗牆連古城。", "愁鴟占枯枿，野鼠趨前楹。", "昨日雲破損，晚林先覺晴。", "幽篁倚微照，碧粉含疎莖。", "蠹簡有遺字，㪇琴無泛聲。", "蠶寒繭尚薄，燕喜雛新成。", "覽物正搖思，得君初夏行。", "誠明復散誕，化匠安能爭。", "海浪刷三島，天風吹六英。", "洪崖領玉節，坐使虛音生。", "吾祖傲洛客，因言幾爲傖。", "末裔實漁者，敢懷干墨卿。", "唯思釣璜老，遂得持竿情。", "何須乞鵝炙，豈在斟羊羹。", "畦蔬與甕醁，便可相攜迎。", "蟠木几甚曲，筍皮冠且輕。", "閑心放羈靮，醉脚從欹傾。", "一逕有餘遠，一窗有餘明。", "秦皇苦不達，天下何足幷。"]'),
('717431a9-c01e-463a-acc2-3521da004caa','奉和襲美二遊詩 徐詩','陸龜蒙','唐','唐诗','tang','','[]','嘗聞四書曰，經史子集焉。',288,'全唐诗/poet.tang.34000.json','["嘗聞四書曰，經史子集焉。", "苟非天祿中，此事無由全。", "自從秦火來，歷代逢迍邅。", "漢祖入關日，蕭何爲政年。", "盡力取圖籍，遂持天下權。", "中興熹平時，教化還相宣。", "立石刻五經，置於太學前。", "賊卓亂王室，君臣如轉圜。", "洛陽且煨燼，載籍宜爲煙。", "逮晉武革命，生民纔息肩。", "惠懷亟寡昧，戎羯俄腥羶。", "已覺天地閉，競爲東南遷。", "日既不暇給，墳索何由專。", "爾後國脆弱，人多尚虛玄。", "任學者得謗，清言者爲賢。", "直至沈范輩，始家藏簡編。", "御府有不足，仍令就之傳。", "梁元渚宮日，盡取如蚳蝝。", "兵威忽破碎，焚爇無遺篇。", "近者隋後主，搜羅勢駢闐。", "寶函映玉軸，彩翠明霞鮮。", "伊唐受命初，載史聲連延。", "砥柱不我助，驚波湧淪漣。", "遂令因去書，半在餘浮泉。"]'),
('60477426-0c33-411e-bbf0-622a1c8d44a2','奉和襲美二遊詩 任詩','陸龜蒙','唐','唐诗','tang','','[]','吳之辟疆園，在昔勝概敵。',288,'全唐诗/poet.tang.34000.json','["吳之辟疆園，在昔勝概敵。", "前聞富脩竹，後說紛怪石。", "風煙慘無主，載祀將六百。", "草色與行人，誰能問遺跡。", "不知清景在，盡付任君宅。", "却是五湖光，偷來傍簷隙。", "出門向城路，車馬聲躪躒。", "入門望亭隈，水木氣岑寂。", "犨牆繞曲岸，勢似行無極。", "十步一危梁，乍疑當絕壁。", "池容澹而古，樹意蒼然僻。", "魚驚尾半紅，鳥下衣全碧。", "斜來島嶼隱，恍若瀟湘隔。", "雨靜挂殘絲，煙消有餘脉。", "朅來任公子，擺落名利役。", "雖將祿代耕，頗愛巾隨策。", "秋籠支遁鶴，夜榻戴顒客。", "說史足爲師，譚禪差作伯。", "君多鹿門思，到此情便適。", "偶蔭桂堪帷，縱吟苔可席。", "顧余真任誕，雅遂中心獲。", "但知醉還醒，豈知玄尚白。", "甘閑在雞口，不貴封龍額。", "即此自怡神，何勞謝公屐。"]'),
('cfd5e9c1-eecd-461d-bb82-56503debd7b2','次追和清遠道士詩韻','陸龜蒙','唐','唐诗','tang','','[]','一代先後賢，聲容劇河漢。',144,'全唐诗/poet.tang.34000.json','["一代先後賢，聲容劇河漢。", "況茲邁古士，復歷蒼崖竄。", "辰經幾十萬，邈與靈壽翫。", "海嶽尚推移，都鄙固蕪漫。", "羸僧下高閣，獨鳥沒遠岸。", "嘯初風雨來，吟餘鐘唄亂。", "如何鍊精魄，萬祀忽欲半。", "寧爲斷臂憂，肯作秋柏散。", "吾聞酆宮內，日月自昏旦。", "左右修文郎，縱橫灑篇翰。", "斯人久冥漠，得不垂慨歎。", "庶或有神交，相從重興讚。"]'),
('42f99f74-e61c-44b7-aac4-86dcf08a1fe6','補沈恭子詩','陸龜蒙','唐','唐诗','tang','','[]','靈質貫軒昊，遐年越商周。',144,'全唐诗/poet.tang.34000.json','["靈質貫軒昊，遐年越商周。", "自然失遠裔，安得怨寡儔。", "我亦小國胤，易名慙見優。", "雖非放曠懷，雅奉逍遙遊。", "攜手桂枝下，屬詞山之幽。", "風雨一以過，林麓颯然秋。", "落日倚石壁，天寒登古丘。", "荒泉已無夕，敗葉翳不流。", "亂翠缺月隱，衰紅清露愁。", "覽物性未逸，反爲情所囚。", "異才偶絕境，佳藻窮冥搜。", "虛傾寂寞音，敢作雜珮酬。"]'),
('f184be37-4589-4078-8cf6-9151c5eb5ec7','讀陰符經寄鹿門子','陸龜蒙','唐','唐诗','tang','','["\u9ec4\u6cb3"]','清晨整冠坐，朗詠三百言。',276,'全唐诗/poet.tang.34000.json','["清晨整冠坐，朗詠三百言。", "備識天地意，獻詞犯乾坤。", "何事不隱德，降靈生軒轅。", "口銜造化斧，鑿破機關門。", "五賊忽迸逸，萬物爭崩奔。", "虛施神仙要，莫救華池源。", "但學戰勝術，相高甲兵屯。", "龍蛇競起陸，鬬血浮中原。", "成湯與周武，反覆更爲尊。", "下及秦漢得，黷弄兵亦煩。", "姦強自林據，仁弱無枝蹲。", "狂喉恣吞噬，逆翼爭飛翻。", "家家伺天發，不肯匡淫昏。", "生民墜塗炭，比屋爲冤魂。", "祗爲讀此書，大樸難久存。", "微臣與軒轅，亦是萬世孫。", "未能窮意義，豈敢求瑕痕。", "曾亦愛兩句，可與賢達論。", "生者死之根，死者生之根。", "方寸了十字，萬化皆胚腪。", "身外更何事，眼前徒自喧。", "黃河但東注，不見歸崑崙。", "晝短苦夜永，勸君傾一尊。"]'),
('08915c1b-2083-4540-a060-6fc69c5b1a6b','奉和襲美初夏遊楞伽精舍次韻','陸龜蒙','唐','唐诗','tang','','[]','吳都涵汀洲，碧液浸郡郭。',288,'全唐诗/poet.tang.34000.json','["吳都涵汀洲，碧液浸郡郭。", "微雨蕩春醉，上下一清廓。", "奇蹤欲探討，靈物先瘵瘼。", "飄然蘭葉舟，旋倚煙霞泊。", "吟譚亂篙艣，夢寐雜巘崿。", "纖情不可逃，洪筆難暫閣。", "豈知楞伽會，乃在山水箔。", "金仙著書日，世界名極樂。", "薝蔔冠諸香，琉璃代華堊。", "禽言經不輟，象口川寧涸。", "萬善峻爲城，巉巉扞羣惡。", "清晨欲登造，安得無自愕。", "險穴駭坤牢，高蘿挂天笮。", "池容澹相向，蛟怪如可摸。", "苔蔽石髓根，蒲差水心鍔。", "嵐侵荅摩髻，日照狻猊絡。", "仰首乍眩旋，迴眸更輝㸌。", "簷端凝飛羽，磴外浮碧落。", "到迴解風襟，臨幽濯雲屩。", "塵機性非便，靜境心所著。", "自取海鷗知，何煩尸祝酢。", "峯圍震澤岸，翠浪舞綃幕。", "瀲灩豈堯遭，㟞嵃非禹鑿。", "潛聽鐘梵處，別有松桂壑。"]'),
('b04a162c-c793-4db6-bd3f-19718742080c','奉和襲美公齋四詠次韻 小松','陸龜蒙','唐','唐诗','tang','','[]','擢秀逋客巖，遺根飛鳥逕。',108,'全唐诗/poet.tang.34000.json','["擢秀逋客巖，遺根飛鳥逕。", "因求飾清閟，遂得辭危敻。", "貞同柏有心，立若珠無脛。", "枝形短未怪，鬣數差難定。", "況密三天風，方遵四時柄。", "那興培塿歎，免荅鄰里病。", "微霜靜可分，片月疎堪映。", "奇當虎頭筆，韻叶通明性。", "會拂陽烏胸，掄才膺帝命。"]'),
('36065dc3-00b8-489d-a155-35fc6779c7af','奉和襲美公齋四詠次韻 小桂','陸龜蒙','唐','唐诗','tang','','[]','諷賦輕八植，擅名方一枝。',96,'全唐诗/poet.tang.34000.json','["諷賦輕八植，擅名方一枝。", "才高不滿意，更自寒山移。", "宛宛別雲態，蒼蒼出塵姿。", "煙歸助華杪，雪點迎芳蕤。", "青條坐可結，白日如奔螭。", "諒無𠠜翦憂，即是蕭森時。", "洛浦雖有蔭，騷人聊自怡。", "終爲濟川檝，豈在論高卑。"]'),
('685fdb44-4e24-4c80-92b2-7a5f95e30c9d','奉和襲美公齋四詠次韻 新竹','陸龜蒙','唐','唐诗','tang','','[]','別塢破苔蘚，嚴城樹軒楹。',108,'全唐诗/poet.tang.34000.json','["別塢破苔蘚，嚴城樹軒楹。", "恭聞稟璇璣，化質離青冥。", "色可定雞頸，實堪招鳳翎。", "立窺五嶺秀，坐對三都屏。", "晴月窈窕入，曙煙霏微生。", "昔者尚借宅，況來處賓庭。", "金罍縱傾倒，碧露還鮮醒。", "若非抱苦節，何以偶惟馨。", "徐觀穉龍出，更賦錦苞零。"]'),
('f6404cb5-3033-46d8-b59d-193d5534705e','奉和襲美公齋四詠次韻 鶴屏','陸龜蒙','唐','唐诗','tang','','[]','時人重花屏，獨即胎化狀。',96,'全唐诗/poet.tang.34000.json','["時人重花屏，獨即胎化狀。", "叢毛練分彩，疎節筇相望。", "曾無氃氋態，頗得連軒樣。", "勢擬搶高尋，身猶在函丈。", "如憂雞鶩鬬，似憶煙霞向。", "塵世任縱橫，霜襟自閑放。", "空資明遠思，不待浮丘相。", "何由振玉衣，一舉棲瀛閬。"]'),
('329751a4-c351-4b39-b419-a22eff15dd0d','奉和襲美酬前進士崔潞盛製見寄因贈至一百四十言','陸龜蒙','唐','唐诗','tang','','[]','孔聖鑄顏事，垂之千載餘。',168,'全唐诗/poet.tang.34000.json','["孔聖鑄顏事，垂之千載餘。", "其間王道乖，化作荆榛墟。", "天必授賢哲，爲時攻翦除。", "軻雄骨已朽，百代徒趦趄。", "近者韓文公，首爲閑闢鋤。", "夫子又繼起，陰霾終廓如。", "搜得萬古遺，裁成十編書。", "南山盛雲雨，東序堆瓊琚。", "偶此真籍客，悠揚兩情攄。", "清詞忽窈窕，雅韻何虛徐。", "唱既野芳坼，酬還天籟疎。", "輕波掠翡翠，曉露披芙渠。", "儷曲信寡合，末流難嗣初。", "空持一竿餌，有意鯨魚。"]'),
('02a9d3d5-95a1-44f6-a403-36c8f72e6b74','奉和襲美太湖詩二十首 初入太湖','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','東南具區雄，天水合爲一。',240,'全唐诗/poet.tang.34000.json','["東南具區雄，天水合爲一。", "高帆大弓滿，羿射爭箭疾。", "時當暑雨後，氣象仍鬱密。", "乍如開雕笯，聳翅忽飛出。", "行將十洲近，坐覺八極溢。", "耳目駭鴻濛，精神寒佶栗。", "坑來斗呀豁，湧處驚嵳崒。", "嶮異拔龍湫，喧如破蛟室。", "斯須風妥帖，若受命平秩。", "微茫誠端倪，遠嶠疑格筆。", "巉巉見銅闕，左右皆輔弼。", "盤空儼相趨，去勢猶橫逸。", "嘗聞咸池氣，下注作清質。", "至今涵赤霄，尚且浴白日。", "又云構浮玉，宛與崑閬匹。", "肅爲靈官家，此事難致詰。", "纔迎沙嶼好，指顧俄已失。", "山川互蔽虧，魚鳥空聱耴。", "何當授真檢，得召天吳術。", "一一問朝宗，方應可譚悉。"]'),
('e341e40d-93f8-4a94-8ca4-f3b3301f6dc2','奉和襲美太湖詩二十首 曉次神景宮','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','曉帆逗碕岸，高步入神景。',168,'全唐诗/poet.tang.34000.json','["曉帆逗碕岸，高步入神景。", "灑灑襟袖清，如臨蘂珠屏。", "雖然羣動息，此地常寂靜。", "翠鑷有寒鏘，碧花無定影。", "憑軒羽人傲，夾戶天獸猛。", "稽首朝元君，褰衣就虛省。", "呀空雪牙利，嗽水石齒冷。", "香母未垂嬰，芝田不論頃。", "遙通河漢口，近撫松桂頂。", "飯薦七白蔬，杯釃九光杏。", "人間附塵躅，固陋真鉗頸。", "肯信抃鼇傾，猶疑夏蟲永。", "玄津蕩瓊壟，紫汞啼金鼎。", "盡出冰霜書，期君一披省。"]'),
('a9ee1e11-8141-4716-aab3-dc7410ef6a45','奉和襲美太湖詩二十首 入林屋洞','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','知名十小天，林屋當第九。',192,'全唐诗/poet.tang.34000.json','["知名十小天，林屋當第九。", "題之爲左神，理之以天后。", "魁堆辟邪輩，左右專備守。", "自非方瞳人，不敢窺洞口。", "唯君好奇士，復嘯忘情友。", "致傘在風林，低冠入雲竇。", "中深劇苔井，傍坎纔藥臼。", "石角忽支頤，藤根時束肘。", "初爲大幽怖，漸見微明誘。", "屹若造靈封，森如達仙藪。", "嘗聞白芝秀，狀與琅花偶。", "又坐紫泉光，甘如酌天酒。", "何人能挹嚼，餌以代漿糗。", "却笑探五符，徒勞步雙斗。", "真君不可見，焚盥空遲久。", "眷戀玉碣文，行行但迴首。"]'),
('cd8a696c-cd7e-491d-8b82-38f9cc3bfe73','奉和襲美太湖詩二十首 雨中遊包山精舍','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','包山信神仙，主者上真職。',144,'全唐诗/poet.tang.34000.json','["包山信神仙，主者上真職。", "及棲鐘梵侶，又是清涼域。", "乃知煙霞地，絕俗無不得。", "巖開一逕分，柏擁深殿黑。", "僧閑若圖畫，像古非雕刻。", "海客施明珠，湘蕤料淨食。", "有魚皆玉尾，有烏盡金臆。", "手攜鞞鐸佉，若在中印國。", "千峰殘雨過，萬籟清且極。", "此時空寂心，可以遺智識。", "知君戰未勝，尚倚功名力。", "却下聽經徒，孤帆有行色。"]'),
('489b5f09-4bed-45b4-9d6c-6fb7b4c3d837','奉和襲美太湖詩二十首 毛公壇','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','古有韓終道，授之劉先生。',204,'全唐诗/poet.tang.34000.json','["古有韓終道，授之劉先生。", "身如碧鳳皇，羽翼披輕輕。", "先生盛驅役，臣伏甲與丁。", "勢可倒五嶽，不唯鞭羣靈。", "飄颻駕翔螭，白日朝太清。", "空遺古壇在，稠疊煙蘿屏。", "遠懷步罡夕，列宿森然明。", "四角鎮露獸，三層差羽嬰。", "迴眸盼七炁，運足馳疎星。", "象外真既感，區中道俄成。", "邇來向千祀，雲嶠空崢嶸。", "石上橘花落，石根瑤草青。", "時時白鹿下，此外無人行。", "我訪岑寂境，自言齋戒精。", "如今君安死，魂魄猶羶腥。", "有芨皆綠字，有芝皆紫莖。", "相將望瀛島，浩蕩凌滄溟。"]'),
('da08d9cb-2c24-4e1c-ac3c-0c7ab8d3ed4e','奉和襲美太湖詩二十首 三宿神景宮','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','靈蹤未徧尋，不覺谿色瞑。',168,'全唐诗/poet.tang.34000.json','["靈蹤未徧尋，不覺谿色瞑。", "迴頭問棲所，稍下杉蘿逕。", "巖居更幽絕，澗戶相隱映。", "過此即神宮，虛堂愜雲性。", "四軒盡疎達，一榻何清零。", "髣髴聞玉笙，鼓鏗動涼磬。", "風凝古松粒，露壓脩荷柄。", "萬籟既無聲，澄明但心聽。", "希微辨真語，若授虛皇命。", "尺宅按來平，華池漱餘淨。", "頻窺宿羽麗，三吸晨霞盛。", "豈獨冷衣襟，便堪遺造請。", "徒深物外趣，未脫塵中病。", "舉首謝靈峰，徜徉事歸榜。"]'),
('3ec103b8-efa8-4a5d-b24b-97125b4a2c7a','奉和襲美太湖詩二十首 以毛公泉獻大諫清河公','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','先生鍊飛精，羽化成翩翻。',144,'全唐诗/poet.tang.34000.json','["先生鍊飛精，羽化成翩翻。", "荒壇與古甃，隱軫清泠存。", "四面蹙山骨，中心含月魂。", "除非紫水脉，即是金沙源。", "香實灑桂蘂，甘惟漬雲根。", "向來探幽人，酌罷祛蒙昏。", "況公珪璋質，近處諫諍垣。", "又聞虛靜姿，早挂冰雪痕。", "君對瑤華味，重獻蘭薰言。", "當應滌煩暑，朗詠翬飛軒。", "我願得一掬，攀天呌重閽。", "霏霏散爲雨，用以移焦原。"]'),
('e2f50ee9-058f-4378-99c2-6f2e572e60b6','奉和襲美太湖詩二十首 縹緲峰','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','左右皆跳岑，孤峰挺然起。',216,'全唐诗/poet.tang.34000.json','["左右皆跳岑，孤峰挺然起。", "因思縹緲稱，乃在虛無裏。", "清晨躋磴道，便是孱顏始。", "據石即更歌，遇泉還徙倚。", "花奇忽如薦，樹曲渾成几。", "樂靜煙靄知，忘機猨狖喜。", "頻攀峻過斗，末造平如砥。", "舉首閡青冥，迴眸聊下視。", "高帆大於鳥，廣墠纔類蟻。", "就此微茫中，爭先未嘗已。", "葛洪話剛氣，去地四千里。", "苟能乘之遊，止若道路耳。", "吾將自峰頂，便可朝帝扆。", "盡欲活羣生，不唯私一己。", "超騎明月蜍，復弄華星蘂。", "却下蓬萊巔，重窺清淺水。", "身爲大塊客，自號天隨子。", "他日向華陽，敲雲問名氏。"]'),
('c1c132ca-63a9-4aeb-8394-a36e0e90f0af','奉和襲美太湖詩二十首 桃花塢','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','行行問絕境，貴與名相親。',108,'全唐诗/poet.tang.34000.json','["行行問絕境，貴與名相親。", "空經桃花塢，不見秦時人。", "願此爲東風，吹起枝上春。", "願此作流水，潛浮蘂中塵。", "願此爲好鳥，得棲花際鄰。", "願此作幽蝶，得隨花下賓。", "朝爲照花日，暮作涵花津。", "試爲探花士，作此偷桃臣。", "桃源不我棄，庶可全天真。"]'),
('9e11dee2-3272-4230-bdd5-7f5fb55d2106','奉和襲美太湖詩二十首 明月灣','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','昔聞明月觀，祗傷荒野基。',180,'全唐诗/poet.tang.34000.json','["昔聞明月觀，祗傷荒野基。", "今逢明月灣，不值三五時。", "擇此二明月，洞庭看最奇。", "連山忽中斷，遠樹分毫釐。", "周迴二十里，一片澄風漪。", "見說秋半夜，淨無雲物欺。", "兼之星斗藏，獨有神仙期。", "初聞鏘鐐跳，積漸調參差。", "空中卓羽衛，波上停龍螭。", "蹤舞玉煙節，高歌碧霜詞。", "清光悄不動，萬象寒咿咿。", "此會非俗致，無由得旁窺。", "但當乘扁舟，酒甕仍相隨。", "或徹三弄笛，或成數聯詩。", "自然瑩心骨，何用神仙爲。"]'),
('e24a1ee6-ee5b-413b-8a20-015a2294aa8e','奉和襲美太湖詩二十首 練瀆','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','越恃君子衆，大將壓全吳。',168,'全唐诗/poet.tang.34000.json','["越恃君子衆，大將壓全吳。", "吳將派天澤，以練舟師徒。", "一鏡止千里，支流忽然迂。", "蒼匳朿洪波，坐似馮夷軀。", "戰艦百萬輩，浮宮三十餘。", "平川盛丁寧，絕島分儲胥。", "鳳押半鶴膝，錦杠雜肥胡。", "香煙與殺氣，浩浩隨風驅。", "彈射盡高鳥，杯觥醉潛魚。", "山靈恐見鞭，水府愁爲墟。", "兵利德日削，反爲讎國屠。", "至今鉤鏃殘，尚與泥沙俱。", "照此月倍苦，來茲煙亦孤。", "丁魂尚有淚，合灑青楓枯。"]'),
('1d863fb3-649d-4e63-92cd-b6008942c289','奉和襲美太湖詩二十首 投龍潭','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','名山潭洞中，自古多祕邃。',144,'全唐诗/poet.tang.34000.json','["名山潭洞中，自古多祕邃。", "君將接神物，聊用申祀事。", "鎔金象牙角，尺木無不備。", "亦既奉真官，因之徇前志。", "持來展明誥，敬以投嘉瑞。", "鱗光煥水容，目色燒山翠。", "吾皇病秦漢，豈獨探幽異。", "所貴風雨時，民皆受其賜。", "良田爲巨浸，污澤成赤地。", "掌職一不行，精靈又何寄。", "唯貪血食飽，但據驪珠睡。", "何必費黃金，年年授星使。"]'),
('2333e7aa-fbb6-40bb-b733-fadf85a20b31','奉和襲美太湖詩二十首 孤園寺','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','浮屠從西來，事者極梁武。',144,'全唐诗/poet.tang.34000.json','["浮屠從西來，事者極梁武。", "巖幽與水曲，結構無遺土。", "窮山林幹盡，竭海珠璣聚。", "況即侍從臣，敢愛煙波塢。", "幡條玉龍扣，殿角金虬舞。", "釋子厭樓臺，生人露風雨。", "今來四百載，像設藏雲浦。", "輕鴿亂馴鷗，鳴鐘和朝艣。", "庭蕉裂旗斾，野蔓差纓組。", "石上解空人，窗前聽經虎。", "林虛葉如織，水淨沙堪數。", "徧問得中天，歸脩釋迦譜。"]'),
('e8417f22-03ae-4ce1-967e-4c416525322b','奉和襲美太湖詩二十首 上真觀','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','嘗聞昇三清，真有上中下。',192,'全唐诗/poet.tang.34000.json','["嘗聞昇三清，真有上中下。", "官居乘佩服，一一自相亞。", "霄裙或霞粲，侍女忽玉姹。", "坐進金碧腴，去馳飆歘駕。", "今來上真觀，恍若心靈訝。", "祗恐暫神遊，又疑新羽化。", "風餘撼朱草，雲破生瑤榭。", "望極覺波平，行虛信煙藉。", "閑開飛龜帙，靜倚宿鳳架。", "俗狀既能遺，塵冠聊以卸。", "人間方大火，此境無朱夏。", "松蓋蔭日車，泉紳垂天罅。", "窮幽不知倦，復息芝園舍。", "鏘珮引涼姿，焚香禮遙夜。", "無情走聲利，有志依閑暇。", "何處好迎僧，希將石樓借。"]'),
('be2b3d29-41a0-4a18-a07c-bf83f6be4bd7','奉和襲美太湖詩二十首 銷夏灣','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','霞島焰難泊，雲峰奇未收。',144,'全唐诗/poet.tang.34000.json','["霞島焰難泊，雲峰奇未收。", "蕭條千里灣，獨自清如秋。", "古岸過新雨，高蘿蔭橫流。", "遙風吹蒹葭，折處鳴颼颼。", "昔予守圭竇，過於回祿囚。", "日爲蘧筁徒，分作祗裯讎。", "願狎寒水怪，不封朱轂侯。", "豈知煙浪涯，坐可思重裘。", "健若數尺鯉，泛然雙白鷗。", "不識號火井，孰問名焦丘。", "我真魚鳥家，盡室營扁舟。", "遺名復避世，消夏還消憂。"]'),
('e25f0e41-aa28-4cee-bf79-3809c9c488f8','奉和襲美太湖詩二十首 包山祠','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','靜境林麓好，古祠煙靄濃。',96,'全唐诗/poet.tang.34000.json','["靜境林麓好，古祠煙靄濃。", "自非通靈才，敢陟羣仙峰。", "百里波浪沓，中堂簫鼓重。", "真君具瓊輿，髣髴來相從。", "清露濯巢鳥，陰雲生晝龍。", "風飄橘柚香，日動旛蓋容。", "將命禮且潔，所祈年不凶。", "終當以疏聞，特用諸侯封。"]'),
('15daca87-cbd8-4d67-a042-0b7964a81e06','奉和襲美太湖詩二十首 聖姑廟','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','渺渺洞庭水，盈盈芳嶼神。',120,'全唐诗/poet.tang.34000.json','["渺渺洞庭水，盈盈芳嶼神。", "因知古佳麗，不獨湘夫人。", "流蘇蕩遙吹，斜領生輕塵。", "蜀彩駮霞碎，吳綃盤霧勻。", "可憐飛燕姿，合是乘鸞賓。", "坐想煙雨夕，兼知花草春。", "空登油壁車，窈窕誰相親。", "好贈玉條脫，堪攜紫綸巾。", "殷勤撥香池，重薦汀洲蘋。", "明朝動蘭檝，不翅星河津。"]'),
('22f2b07d-9662-435d-a4d7-9507fc5e048d','奉和襲美太湖詩二十首 太湖石','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','他山豈無石，厥狀皆可薦。',156,'全唐诗/poet.tang.34000.json','["他山豈無石，厥狀皆可薦。", "端然遇良工，坐使天質變。", "或裁基棟宇，礧砢成廣殿。", "或剖出溫瑜，精光具華瑱。", "或將破仇敵，百礮資苦戰。", "或用鏡功名，萬古如會面。", "今之洞庭者，一以非此選。", "槎牙真不才，反作天下彥。", "所奇者嵌崆，所尚者蔥蒨。", "旁穿參洞穴，內竅均環釧。", "刻削九琳窗，玲瓏五明扇。", "新雕碧霞段，旋破秋天片。", "無力置池塘，臨風只流眄。"]'),
('20ffeef9-9cdd-45ca-a7a5-28a8517d24af','奉和襲美太湖詩二十首 崦裏','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','山橫路若絕，轉檝逢平川。',144,'全唐诗/poet.tang.34000.json','["山橫路若絕，轉檝逢平川。", "川中水木幽，高下兼良田。", "溝塍墮微溜，桑柘含疎煙。", "處處倚蠶箔，家家下魚筌。", "騃犢臥新𦬻，野禽爭折蓮。", "試招搔首翁，共語殘陽邊。", "今來九州內，未得皆恬然。", "賊陣始吉語，狂波又凶年。", "吾翁欲何道，守此常安眠。", "笑我掉頭去，蘆中聞刺船。", "余知隱地術，可以齊真仙。", "終當從之遊，庶復全於天。"]'),
('5e8e4bac-4b05-4680-aa37-f0806ed90d81','奉和襲美太湖詩二十首 石板','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','一片倒山屏，何時隳洞門。',144,'全唐诗/poet.tang.34000.json','["一片倒山屏，何時隳洞門。", "屹然空闊中，萬古波濤痕。", "我意上帝命，持來壓泉源。", "恐爲庚辰官，囚怪力所掀。", "又疑廣袤次，零落潛驚奔。", "不然遭霹靂，強半沈無垠。", "如何造化首，便截秋雲根。", "往事不足問，奇蹤安可論。", "吾今病煩暑，據簟常昏昏。", "欲從石公乞，瑩理平如璊。", "前後植桂檜，東西置琴尊。", "盡攜天壤徒，浩唱羲皇言。"]'),
('ab1b0f8d-726e-4cdb-8f0a-6134d6381984','雜諷九首 一','陸龜蒙','唐','唐诗','tang','','[]','紅蠶緣枯桑，青繭大如甕。',96,'全唐诗/poet.tang.34000.json','["紅蠶緣枯桑，青繭大如甕。", "人爭捩其臂，羿矢亦不中。", "微微待賢祿，一一希入夢。", "縱操上吉言，口噤難即貢。", "蛟龍在怒水，拔取牙角弄。", "丹穴如可遊，家家畜孤鳳。", "凶門尚兒戲，戰血波澒溶。", "社鬼苟有靈，誰能遏秋慟。"]'),
('ab233e8c-fdd2-42c5-8d60-a9fb2ff8b5f7','雜諷九首 二','陸龜蒙','唐','唐诗','tang','','[]','童麋來觸犀，德力不相及。',120,'全唐诗/poet.tang.34000.json','["童麋來觸犀，德力不相及。", "伊無愜心事，祗有碎首泣。", "況將鵬蝨校，數又百與十。", "攻如餓鴟呌，勢若脫兔急。", "斯爲朽關鍵，怒犖抉以入。", "年來橫干戈，未見拔城邑。", "得非佐饔者，齒齒待啜汁。", "羈維豪傑輩，四駭方少縶。", "此皆乘時利，縱舍在呼吸。", "吾欲斧其吭，無雷動幽蟄。"]'),
('aa221fac-4309-4669-b11c-5b31f9a8422e','雜諷九首 三','陸龜蒙','唐','唐诗','tang','','[]','𪃿鵝慘於冰，陸立懷所適。',120,'全唐诗/poet.tang.34000.json','["𪃿鵝慘於冰，陸立懷所適。", "斯人道仍閟，不得不嗚呃。", "當時布衣士，亦作天子客。", "至今東方生，滿口自誇白。", "終爲萬乘交，談笑無所隔。", "致君非有書，乃是堯舜畫。", "祗今侯門峻，日掃貧賤迹。", "朝趨九韶音，暮列五鼎食。", "如聞恭儉語，謇謇事夕惕。", "可拍伊牧肩，功名被金石。"]'),
('f2736ec1-6b36-425f-99fc-d7f53f445a86','雜諷九首 四','陸龜蒙','唐','唐诗','tang','','[]','赤舌可燒城，讒邪易爲伍。',96,'全唐诗/poet.tang.34000.json','["赤舌可燒城，讒邪易爲伍。", "詩人疾之甚，取俾投豺虎。", "長風吹窾木，始有音韻吐。", "無木亦無風，笙簧由喜怒。", "女媧鍊五石，天缺猶可補。", "當其利口銜，罅漏不復數。", "元精遺萬類，雙目如牖戶。", "非是既相參，重瞳亦爲瞽。"]'),
('6a4fc569-340e-4560-8589-b591cb262aff','雜諷九首 五','陸龜蒙','唐','唐诗','tang','','[]','東南有狂兕，獵者西北矢。',132,'全唐诗/poet.tang.34000.json','["東南有狂兕，獵者西北矢。", "利塵白冥冥，獨此清夜止。", "無人語其事，偶坐窺天紀。", "安得東壁明，洪洪用墳史。", "搜揚好古士，一以罄雲水。", "流堪灑菁英，風足去稗秕。", "如能出奇計，坐可平賊壘。", "徐陳羲皇道，高駕太平軌。", "攫疏成特雄，濯垢爲具美。", "貢賢當上賞，景福視所履。", "永播南熏音，垂之萬年耳。"]'),
('41a8d504-765e-43c6-913f-1d68e477137d','雜諷九首 六','陸龜蒙','唐','唐诗','tang','','[]','有蘗何青青，空城雪霜裏。',72,'全唐诗/poet.tang.34000.json','["有蘗何青青，空城雪霜裏。", "千林盡枯槁，苦節獨不死。", "他遭匠石顧，總入犧黃美。", "遂得保天年，私心未爲耻。", "高從宿梟怪，下亦容螻蟻。", "大廈若掄材，亭亭託君子。"]'),
('8ce2c388-d5f6-442e-9cbb-fab548eba754','雜諷九首 七','陸龜蒙','唐','唐诗','tang','','[]','左右佩劒者，彼此亦相笑。',96,'全唐诗/poet.tang.34000.json','["左右佩劒者，彼此亦相笑。", "趨時與閉門，喧寂不同調。", "潛機取聲利，自許臻乎妙。", "志士以神窺，慚然真可弔。", "天之發遐籟，大小隨萬竅。", "魁其罏冶姿，形質惟所召。", "鼗笙磬竽瑟，是必登清廟。", "伊聖不可欺，誰能守蓬藋。"]'),
('9b72ad09-dfcf-4385-a61a-0c14ec9e4fac','雜諷九首 八','陸龜蒙','唐','唐诗','tang','','[]','橫笛喝秋風，清商入疏越。',168,'全唐诗/poet.tang.34000.json','["橫笛喝秋風，清商入疏越。", "君居不夜城，肯怨孤戍月。", "吳兵甚犀利，太白光突兀。", "日已費千金，厪聞侵一撥。", "豈無惡年少，縱酒遊俠窟。", "募爲敢死軍，去以梟叛卒。", "豈無中林士，貫穿學問骨。", "兵法五十家，浩蕩如溟渤。", "高懸鹿皮睡，清澗時依樾。", "分已諾煙霞，全遺事干謁。", "既非格猛獸，未可輕華髪。", "北面師其謀，幾能止征伐。", "何妨秦堇勇，又有曹劌說。", "堯舜尚詢芻，公乎聽無忽。"]'),
('c7a16caf-080b-49d7-9b6f-1c7fdc430826','雜諷九首 九','陸龜蒙','唐','唐诗','tang','','[]','朝爲壯士歌，暮爲壯士歌。',108,'全唐诗/poet.tang.34000.json','["朝爲壯士歌，暮爲壯士歌。", "壯士心獨苦，傍人謂之何。", "古鐵久不快，倚天無處磨。", "將來易水上，猶足生寒波。", "捷可搏飛狖，健能超槖駞。", "羣兒被堅利，索手安馮河。", "驚飆掃長林，直木謝𬄭科。", "嚴霜凍大澤，僵龍不如蛇。", "昔者天血碧，吾徒安歎嗟。"]'),
('a622aeb1-8637-4eb6-9566-1032e18ed9f3','美人','陸龜蒙','唐','唐诗','tang','','[]','美人抱瑤瑟，哀怨彈別鶴。',72,'全唐诗/poet.tang.34000.json','["美人抱瑤瑟，哀怨彈別鶴。", "雌雄南北飛，一旦異棲託。", "諒非金石性，安得宛如昨。", "生爲竝蒂花，亦有先後落。", "秋林對斜日，光景自相薄。", "猶欲悟君心，朝朝佩蘭若。"]'),
('45e44e91-b5b8-4c28-ba19-b267d670481b','感事','陸龜蒙','唐','唐诗','tang','','[]','將軍被鮫函，祗畏金石鏃。',72,'全唐诗/poet.tang.34000.json','["將軍被鮫函，祗畏金石鏃。", "豈知讒箭利，一中成赤族。", "古來信簧舌，巧韻淒鏘曲。", "君聞悅耳音，盡日聽不足。", "初因起毫髪，漸可離骨肉。", "所以賢達心，求人須任目。"]'),
('11eba15b-ac12-4ec5-9c89-277ab47742ef','素絲','陸龜蒙','唐','唐诗','tang','','[]','園客麗獨繭，詩人吟五緵。',72,'全唐诗/poet.tang.34000.json','["園客麗獨繭，詩人吟五緵。", "如何墨子淚，反以悲途窮。", "我意豈如是，願參天地功。", "爲綫補君衮，爲弦繫君桐。", "左右脩闕職，宮商還古風。", "端然潔白心，可與神明通。"]'),
('2c34582b-c825-4822-86ad-6d2437384a2f','次幽獨君韻 一','陸龜蒙','唐','唐诗','tang','','[]','靈氣獨不死，尚能成綺文。',24,'全唐诗/poet.tang.34000.json','["靈氣獨不死，尚能成綺文。", "如何孤窆裏，猶自讀三墳。"]'),
('394ef011-f628-4391-a86d-6576901f9dbb','次幽獨君韻 二','陸龜蒙','唐','唐诗','tang','','[]','落日送萬古，秋聲含七哀。',72,'全唐诗/poet.tang.34000.json','["落日送萬古，秋聲含七哀。", "枯株不蕭瑟，枝幹虛崔嵬。", "伊昔臨大道，歌鐘醉高臺。", "臺今已平地，祗有春風迴。", "明月白草死，積陰荒隴推。", "聖賢亦如此，慟絕真悠哉。"]'),
('04459fc9-0e2c-4410-9726-2887b54a1ac7','贈遠','陸龜蒙','唐','唐诗','tang','','[]','芙蓉匣中鏡，欲照心還嬾。',72,'全唐诗/poet.tang.34000.json','["芙蓉匣中鏡，欲照心還嬾。", "本是細腰人，別來羅帶緩。", "從君出門後，不奏雲和管。", "妾思冷如簧，時時望君暖。", "心期夢中見，路永魂夢短。", "怨坐泣西風，秋窗月華滿。"]'),
('a9d1ecb0-582d-4a3e-a8e9-b9b130fcaba3','村夜二篇 一','陸龜蒙','唐','唐诗','tang','','[]','江上冬日短，裴回草堂暝。',240,'全唐诗/poet.tang.34000.json','["江上冬日短，裴回草堂暝。", "鴻當絕塞來，客向孤村病。", "緜緜起歸念，咽咽興微詠。", "菊逕月方高，橘齋霜已併。", "盤飱蔬粟粗，史籍籤牌盛。", "目冷松桂寒，耳喧兒女競。", "開瓶浮蟻綠，試筆秋毫勁。", "晝戶亦重關，寒屏遞相映。", "詩從騷雅得，字向鉛槧正。", "遇敵舞蛇矛，逢談捉犀柄。", "無名升甲乙，有志扶荀孟。", "守道希昔賢，爲文通古聖。", "幽憂廢長劒，顦顇慚清鏡。", "祗會魚鳥情，詎知時俗性。", "浮虛多徇勢，老嬾圖歷聘。", "既不務人知，空餘樂天命。", "吾家在田野，家事苦遼敻。", "耕稼一以微，囷倉自然罄。", "愁襟風葉亂，獨坐燈花迸。", "明發成浩歌，誰能少傾聽。"]'),
('4e507d5f-d26e-4a22-954e-08c96e3e5bdf','村夜二篇 二','陸龜蒙','唐','唐诗','tang','','[]','世既賤文章，歸來事耕稼。',288,'全唐诗/poet.tang.34000.json','["世既賤文章，歸來事耕稼。", "伊人著農道，我亦賦田舍。", "所悲勞者苦，敢用詞爲詫。", "祗効芻牧言，誰防輕薄駡。", "嘻今居寵祿，各自矜雄霸。", "堂上考華鐘，門前竚高駕。", "纖洪動絲竹，水陸供鱠炙。", "小雨靜樓臺，微風動蘭麝。", "吹噓川可倒，眄睞花爭奼。", "萬戶膏血窮，一筵歌舞價。", "安知勤播植，卒歲無閑暇。", "種以春鳸初，獲從秋隼下。", "專專望穜稑，搰搰條桑柘。", "日晏腹未充，霜繁體猶躶。", "平生守仁義，所疾唯狙詐。", "上誦周孔書，沈溟至酣籍。", "豈無致君術，堯舜不上下。", "豈無活國方，頗牧齊教化。", "蛟龍任乾死，雲雨終不借。", "羿臂束如囚，徒勞誇善射。", "才能誚箕斗，辯可移嵩華。", "若與虻輩量，飢寒殆相亞。", "長吟倚清瑟，孤憤生遙夜。", "自古有遺賢，吾容偏稱謝。"]'),
('57465762-a4b3-4a39-99ac-0d1143961b31','記事','陸龜蒙','唐','唐诗','tang','','[]','本作漁釣徒，心將遂疎放。',288,'全唐诗/poet.tang.34000.json','["本作漁釣徒，心將遂疎放。", "苦爲飢寒累，未得恣閑暢。", "去年十二月，身住霅溪上。", "病裏賀豐登，雞豚聊饋餉。", "巍峩卞山雪，凝冽不可向。", "瘦骨倍加寒，徒爲厚繒纊。", "晴來露青靄，千仞缺尋丈。", "臥恐玉華銷，時時推枕望。", "雖然營衛困，亦覺精神王。", "把筆強題詩，粗言環怪狀。", "吳興鄭太守，文律頗清壯。", "鳳尾與鯨牙，紛披落雜唱。", "緘書寄城內，搪突無以況。", "料峭採蓮船，縱橫簸天浪。", "方傾謝公酒，忽值莊生喪。", "默默阻音徽，臨風但惆悵。", "春歸迨秋末，固自嬰微恙。", "歲晏弗躬親，何由免欺誑。", "今來觀刈獲，乃在松江並。", "門外兩潮過，波瀾光蕩漾。", "都緣新卜築，是事皆草創。", "爾後如有年，還應愜微尚。", "天高氣味爽，野迥襟懷曠。", "感物動牢愁，憤時頻骯髒。"]'),
('37beceea-294d-4754-9afc-c35d7267b608','孤雁','陸龜蒙','唐','唐诗','tang','','[]','我生天地間，獨作南賓雁。',216,'全唐诗/poet.tang.34000.json','["我生天地間，獨作南賓雁。", "哀鳴慕前侶，不免飲啄晏。", "雖蒙小雅詠，未脫魚網患。", "況是婚禮須，憂爲弋者篡。", "晴鳶爭上下，意氣苦凌慢。", "吾常嚇鴛雛，爾輩安足訕。", "迴頭語晴鳶，汝食腐鼠慣。", "無異駑駘羣，戀短豆皂棧。", "豈知瀟湘岸，葭菼蘋萍間。", "有石形狀奇，寒流古來灣。", "閑看麋鹿志，了不憂芻豢。", "世所重巾冠，何妨野夫丱。", "騷人誇蕙芷，易象取陸莧。", "漆園逍遙篇，中亦載斥鷃。", "汝惟材性下，嗜好不可諫。", "身雖慕高翔，糞壤是盻盼。", "或聞通鬼魅，怪祟立可辯。", "硩蔟書尚存，寧容恣妖幻。"]'),
('7782bee4-6ffc-4909-b441-71ab6cd74692','南涇漁父','陸龜蒙','唐','唐诗','tang','','[]','予方任疎慵，地僻即所好。',240,'全唐诗/poet.tang.34000.json','["予方任疎慵，地僻即所好。", "江流背村落，偶往心已嫪。", "田家相去遠，岑寂且縱傲。", "出戶手先筇，見人頭未帽。", "南涇有漁父，往往攜稚造。", "問其所以漁，對我真蹈道。", "我初簎魚鼈，童丱至於耄。", "窟穴與生成，自然通壺奧。", "孜孜戒吾屬，天物不可暴。", "大小參去留，候其孳養報。", "終朝獲魚利，魚亦未常耗。", "同覆天地中，違仁辜覆燾。", "余觀爲政者，此意諒難到。", "民皆死搜求，莫肯興愍悼。", "今年川澤旱，前歲山源潦。", "牒訴已盈庭，聞之類禽噪。", "譬如死雞鶩，豈不容乳抱。", "孟子譏宋人，非其揠苗躁。", "吾嘉漁父旨，雅叶賢哲操。", "倘遇採詩官，斯文誠敢告。"]'),
('fdfa5fdd-4f9b-4355-9b27-61b0ef9c62f2','引泉詩','陸龜蒙','唐','唐诗','tang','','[]','上嗣位六載，吾宗刺桐川。',288,'全唐诗/poet.tang.34000.json','["上嗣位六載，吾宗刺桐川。", "余來拜旌戟，詔下之明年。", "是時春三月，繞郭花蟬聯。", "嵐盤百萬髻，上插黃金鈿。", "授以道士館，置榻於東偏。", "滿院聲碧樹，空堂形老仙。", "本性樂凝淡，及來更虛玄。", "焚香禮真像，盥手披靈編。", "新定山角角，烏龍獨巉然。", "除非淨晴日，不見蒼崖巔。", "上有拏雲峰，下有噴壑泉。", "泉分數十汊，落處皆崢潺。", "寒聲入爛醉，聒破西窗眠。", "支筇起獨尋，祗在牆東邊。", "呼童具畚鍤，立鑿莓苔穿。", "灇淙一派墮，練帶橫斜牽。", "亂石拋落落，寒流響濺濺。", "狂奴七里瀨，縮到疎楹前。", "跳花潑半散，湧沫飛旋圓。", "勢束三峽挂，瀉危孤磴懸。", "曾聞瑤池溜，亦灌朱草田。", "鳧伯弄翠蘂，鸞雛舞丹煙。", "凌風捩桂柂，隔霧馳犀船。", "況當玄元家，嘗著道德篇。"]'),
('34d88e80-b3f5-4ffc-9055-75a305294d73','紀夢遊甘露寺','陸龜蒙','唐','唐诗','tang','','[]','昔臥嵩高雲，雲窗正寒夕。',288,'全唐诗/poet.tang.34000.json','["昔臥嵩高雲，雲窗正寒夕。", "披裘忽生夢，似到空王宅。", "峨天一峰立，欄楯橫半壁。", "級倚綠巔差，關臨赤霄闢。", "捫虛陟孤峭，不翅千餘尺。", "疊掌望罘罳，分明袒肩釋。", "凌香稽首罷，嘹嘵□□□。", "高戶乘北風，聲號大波白。", "光中目難送，定驗方可覿。", "樹細鴻濛煙，島疎零落碧。", "須臾羣籟入，空水相噴激。", "積浪亞寒堆，呀如鬬危石。", "跳音簇鞞鼓，濺沫交矛戟。", "鳥疾帆亦奔，紛紛助勁敵。", "思非水靈怒，即是飢龍擘。", "怯懾不敢前，荷襟汗霑霢。", "迴經定僧處，泉木光相射。", "巖磴雲族栖，柖柯露華適。", "逍遙得真趨，邐迤尋常跡。", "山腹貯孤亭，嵐根四垂帟。", "誰題雪月句，乃是曹劉格。", "閬闕一枝瓊，邊樓數聲笛。", "吟高矍然起，若自蒼旻擲。", "短燭墮餘花，圓蟾挂斜魄。"]'),
('cbb66a1e-6d7c-4fc2-ab05-af191b0d110b','惜花','陸龜蒙','唐','唐诗','tang','','[]','人壽期滿百，花開唯一春。',36,'全唐诗/poet.tang.34000.json','["人壽期滿百，花開唯一春。", "其間風雨至，旦夕旋爲塵。", "若使花解愁，愁於看花人。"]'),
('7885fc9a-d9f0-4e31-94f6-17008c393baa','別離','陸龜蒙','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba", "\u8bae\u8bba"]','丈夫非無淚，不灑離別間。',48,'全唐诗/poet.tang.34000.json','["丈夫非無淚，不灑離別間。", "杖劒對尊酒，耻爲游子顏。", "蝮蛇一螫手，壯士即解腕。", "所志在功名，離別何足歎。"]'),
('04217a87-def6-4d3b-ade5-82d67c8ff185','鳴雁行','陸龜蒙','唐','唐诗','tang','','[]','朔風動地來，吹起沙上聲。',36,'全唐诗/poet.tang.34000.json','["朔風動地來，吹起沙上聲。", "閨中有邊思，玉筯此時橫。", "莫怕兒女恨，主人烹不鳴。"]'),
('48de0646-18f2-4d47-911d-acf2b114eb9d','短歌行','陸龜蒙','唐','唐诗','tang','','[]','爪牙在身上，陷穽猶可制。',48,'全唐诗/poet.tang.34000.json','["爪牙在身上，陷穽猶可制。", "爪牙在胸中，劒戢無所畏。", "人言畏猛虎，誰是撩頭弊。", "祗見古來心，姦雄暗相噬。"]'),
('61c9833f-452a-40be-a006-61cfa24294a1','挾瑟歌','陸龜蒙','唐','唐诗','tang','','[]','挾瑟爲君撫，君嫌聲太古。',36,'全唐诗/poet.tang.34000.json','["挾瑟爲君撫，君嫌聲太古。", "寥寥倚浪系，㗫㗫沈湘語。", "賴有秋風知，清泠吹玉柱。"]'),
('62461c87-1bbc-425b-8ac3-469205706146','婕妤怨','陸龜蒙','唐','唐诗','tang','','[]','妾貌非傾國，君王忽然寵。',48,'全唐诗/poet.tang.34000.json','["妾貌非傾國，君王忽然寵。", "南山掌上來，下敵新恩重。", "後宮多窈窕，日日學新聲。", "一落君王耳，南山又須輕。"]'),
('0cd983b0-d029-4a17-baf3-45c22fc54eec','江南曲','陸龜蒙','唐','唐诗','tang','','[]','爲愛江南春，涉江聊采蘋。',72,'全唐诗/poet.tang.34000.json','["爲愛江南春，涉江聊采蘋。", "水深煙浩浩，空對雙車輪。", "車輪明月團，車蓋浮雲盤。", "雲月徒自好，水中行路難。", "遙遙洛陽道，夾道生春草。", "寄語櫂船郎，莫誇風浪好。"]'),
('81295de7-b833-4f4d-8cb0-e172990a4b59','漁具詩 網','陸龜蒙','唐','唐诗','tang','','[]','大罟綱目繁，空江波浪黑。',48,'全唐诗/poet.tang.34000.json','["大罟綱目繁，空江波浪黑。", "沈沈到波底，恰共波同色。", "牽時萬鬐入，已有千鈞力。", "尚悔不橫流，恐他人更得。"]'),
('d9d77d14-6fac-40cc-9295-4baaba20d939','漁具詩 罩','陸龜蒙','唐','唐诗','tang','','[]','左手揭圓罛，輕橈弄舟子。',48,'全唐诗/poet.tang.34000.json','["左手揭圓罛，輕橈弄舟子。", "不知潛鱗處，但去籠煙水。", "時穿紫屏破，忽值朱衣起。", "貴得不貴名，敢論魴與鯉。"]'),
('debbda55-2f49-4a32-b593-36a6c1ad5baa','漁具詩 𦊔','陸龜蒙','唐','唐诗','tang','','[]','有意烹小鮮，乘流駐孤櫂。',48,'全唐诗/poet.tang.34000.json','["有意烹小鮮，乘流駐孤櫂。", "雖然煩取舍，未肯求津要。", "多爲蝦蜆誤，已分鵁鶄笑。", "寄語龍伯人，荒唐不同調。"]'),
('cbf9b5a8-c8ac-4912-b7d0-ee2508788f6c','漁具詩 釣筒','陸龜蒙','唐','唐诗','tang','','[]','短短截筠光，悠悠臥江色。',48,'全唐诗/poet.tang.34000.json','["短短截筠光，悠悠臥江色。", "蓬差樐相應，雨慢煙交織。", "須臾中芳餌，迅疾如飛翼。", "彼竭我還浮，君看不爭得。"]'),
('60406526-f24f-4df0-977a-fed1ee7e6cee','漁具詩 釣車','陸龜蒙','唐','唐诗','tang','','[]','溪上持隻輪，溪邊指茅屋。',48,'全唐诗/poet.tang.34000.json','["溪上持隻輪，溪邊指茅屋。", "閑乘風水便，敢議朱丹轂。", "高多倚衡懼，下有折軸速。", "曷若載逍遙，歸來臥雲族。"]'),
('8ed43a3f-7ffe-4d88-b89e-6a46debe57c1','漁具詩 魚梁','陸龜蒙','唐','唐诗','tang','','[]','能編似雲薄，橫絕清川口。',48,'全唐诗/poet.tang.34000.json','["能編似雲薄，橫絕清川口。", "缺處欲隨波，波中先置笱。", "投身入籠檻，自古難飛走。", "盡日水濱吟，殷勤謝漁叟。"]'),
('6d7c7629-6d10-4a0c-a913-dd73de89b242','漁具詩 叉魚','陸龜蒙','唐','唐诗','tang','','[]','春溪正含綠，良夜才參半。',48,'全唐诗/poet.tang.34000.json','["春溪正含綠，良夜才參半。", "持矛若羽輕，列燭如星爛。", "傷鱗跳密藻，碎首沈遙岸。", "盡族染東流，傍人作佳翫。"]'),
('ad2430e9-83db-48e2-adfa-a44d536b60e9','漁具詩 射魚','陸龜蒙','唐','唐诗','tang','','[]','彎弓注碧潯，掉尾行涼沚。',48,'全唐诗/poet.tang.34000.json','["彎弓注碧潯，掉尾行涼沚。", "青楓下晚照，正在澄明裏。", "抨弦斷荷扇，濺血殷菱蘂。", "若使禽荒聞，移之暴煙水。"]'),
('a4de9147-15ee-401c-a918-f6f5c65d5520','漁具詩 鳴桹','陸龜蒙','唐','唐诗','tang','','[]','水淺藻荇澀，[釣]罩無所及。',50,'全唐诗/poet.tang.34000.json','["水淺藻荇澀，[釣]罩無所及。", "鏗如木鐸音，勢若金鉦急。", "敺之就深處，用以資俯拾。", "搜羅爾甚微，遁去將何入。"]'),
('a75af895-78e0-4198-95e9-183432f6d16d','漁具詩 滬','陸龜蒙','唐','唐诗','tang','','[]','萬植禦洪波，森然倒林薄。',48,'全唐诗/poet.tang.34000.json','["萬植禦洪波，森然倒林薄。", "千顱咽雲上，過半隨潮落。", "其間風信背，更值雷聲惡。", "天道亦裒多，吾將移海若。"]'),
('bb52ff3d-9421-4d13-8136-17c86472de89','漁具詩 𥶠','陸龜蒙','唐','唐诗','tang','','[]','斬木置水中，枝條互相蔽。',48,'全唐诗/poet.tang.34000.json','["斬木置水中，枝條互相蔽。", "寒魚遂家此，自以爲生計。", "春冰忽融冶，盡取無遺裔。", "所託成禍機，臨川一凝睇。"]'),
('7168f21d-651a-49e1-b3e2-6d099a809de4','漁具詩 種魚','陸龜蒙','唐','唐诗','tang','','[]','鑿池收赬鱗，疎疎置雲嶼。',48,'全唐诗/poet.tang.34000.json','["鑿池收赬鱗，疎疎置雲嶼。", "還同汗漫遊，遂以江湖處。", "如非一神守，潛被蛟龍主。", "蛟龍若無道，跛鼈亦可禦。"]'),
('78cb1054-975b-4b4f-808e-b2ab7a83c8da','漁具詩 藥魚','陸龜蒙','唐','唐诗','tang','','[]','香餌綴金鉤，日中懸者幾。',48,'全唐诗/poet.tang.34000.json','["香餌綴金鉤，日中懸者幾。", "盈川是毒流，細大同時死。", "不唯空飼犬，便可將貽蟻。", "苟負竭澤心，其他盡如此。"]'),
('d2d206a9-cf78-4ed4-9851-b76eb4d5b846','漁具詩 舴艋','陸龜蒙','唐','唐诗','tang','','[]','篷櫂兩三事，天然相與閑。',48,'全唐诗/poet.tang.34000.json','["篷櫂兩三事，天然相與閑。", "朝隨穉子去，暮唱菱歌還。", "倚石遲後侶，徐橈供遠山。", "君看萬斛載，沈溺須臾間。"]'),
('154d9034-7d18-4ded-95c7-992864161a5f','漁具詩 笭箵','陸龜蒙','唐','唐诗','tang','','[]','誰謂笭箵小，我謂笭箵大。',48,'全唐诗/poet.tang.34000.json','["誰謂笭箵小，我謂笭箵大。", "盛魚自足餐，寘璧能爲害。", "時將刷蘋浪，又取懸藤帶。", "不及腰上金，何勞問蓍蔡。"]'),
('dfe786b0-ad26-469e-bdae-cb46162088cd','奉和襲美添漁具五篇 漁菴','陸龜蒙','唐','唐诗','tang','','[]','結茅次煙水，用以資嘯傲。',48,'全唐诗/poet.tang.34000.json','["結茅次煙水，用以資嘯傲。", "豈謂釣家流，忽同禪室號。", "閑憑山叟占，晚有溪禽嫪。", "華屋莫相非，各隨吾所好。"]'),
('460b6510-baf5-40a6-9687-15e2ba9654cf','奉和襲美添漁具五篇 釣磯','陸龜蒙','唐','唐诗','tang','','[]','揀得白雲根，秋潮未曾沒。',48,'全唐诗/poet.tang.34000.json','["揀得白雲根，秋潮未曾沒。", "坡陁坐鼇背，散漫垂龍髪。", "持竿從掩霧，置酒復待月。", "即此放神情，何勞適吳越。"]'),
('6c206039-d6ce-44ba-8cf8-c04275459c36','奉和襲美添漁具五篇 蓑衣','陸龜蒙','唐','唐诗','tang','','[]','山前度微雨，不廢小澗漁。',48,'全唐诗/poet.tang.34000.json','["山前度微雨，不廢小澗漁。", "上有青襏襫，下有新腒疎。", "滴瀝珠影泫，離披嵐彩虛。", "君看荷製者，不得安吾廬。"]'),
('8cb22119-688e-4175-9ad8-24a54153454b','奉和襲美添漁具五篇 篛笠','陸龜蒙','唐','唐诗','tang','','[]','朝攜下楓浦，晚戴出煙艇。',48,'全唐诗/poet.tang.34000.json','["朝攜下楓浦，晚戴出煙艇。", "冒雪或平簷，聽泉時仄頂。", "飆移靄然色，波亂危如影。", "不識九衢塵，終年居下泂。"]'),
('03e47a2a-f165-46f3-9087-5384dff721a8','奉和襲美添漁具五篇 背蓬','陸龜蒙','唐','唐诗','tang','','[]','敏手劈江筠，隨身織煙殼。',48,'全唐诗/poet.tang.34000.json','["敏手劈江筠，隨身織煙殼。", "沙禽固不知，釣伴猶初覺。", "閑從翠微拂，靜唱滄浪濯。", "見說萬山潭，漁童盡能學。"]'),
('ab0dd798-330d-46f6-863a-ae6326f56b46','樵人十詠 樵谿','陸龜蒙','唐','唐诗','tang','','[]','山高谿且深，蒼蒼但羣木。',48,'全唐诗/poet.tang.34000.json','["山高谿且深，蒼蒼但羣木。", "抽條欲千尺，衆亦疑樸𣙙。", "一朝蒙翦伐，萬古辭林麓。", "若遇燎玄穹，微煙出雲族。"]'),
('e6d7b3f4-bb62-420b-a90f-3903be7f10ca','樵人十詠 樵家','陸龜蒙','唐','唐诗','tang','','[]','草木黃落時，比鄰見相喜。',48,'全唐诗/poet.tang.34000.json','["草木黃落時，比鄰見相喜。", "門當清澗盡，屋在寒雲裏。", "山棚日纔下，野竈煙初起。", "所謂順天民，唐堯亦如此。"]'),
('e8688b69-461d-456b-bd6f-7436b0d04cff','樵人十詠 樵叟','陸龜蒙','唐','唐诗','tang','','[]','自小即胼胝，至今凋鬢髪。',48,'全唐诗/poet.tang.34000.json','["自小即胼胝，至今凋鬢髪。", "所圖山褐厚，所愛山鑪熱。", "不知冠蓋好，但信煙霞活。", "富貴如疾顛，吾從老岩穴。"]'),
('00aea0a5-3436-4402-9af0-2688cb86862d','樵人十詠 樵子','陸龜蒙','唐','唐诗','tang','','[]','生自蒼崖邊，能諳白雲養。',48,'全唐诗/poet.tang.34000.json','["生自蒼崖邊，能諳白雲養。", "纔穿遠林去，已在孤峰上。", "薪和野花束，步帶山詞唱。", "日暮不歸來，柴扉有人望。"]'),
('79e5c8b7-da20-47b2-9346-7dc9b64f8e32','樵人十詠 樵徑','陸龜蒙','唐','唐诗','tang','','[]','石脉青靄間，行行自幽絕。',48,'全唐诗/poet.tang.34000.json','["石脉青靄間，行行自幽絕。", "方愁山繚繞，更值雲遮截。", "爭推好林浪，共約歸時節。", "不似名利途，相期覆車轍。"]'),
('a98992a3-bc33-4e14-b829-790822cb6d71','樵人十詠 樵斧','陸龜蒙','唐','唐诗','tang','','[]','淬礪秋水清，攜持遠山曙。',48,'全唐诗/poet.tang.34000.json','["淬礪秋水清，攜持遠山曙。", "丁丁在前澗，杳杳無尋處。", "巢傾鳥猶在，樹盡猨方去。", "授鉞者何人，吾今易其慮。"]'),
('7c096dde-c0ed-42ac-be8c-22074bbe7b72','樵人十詠 樵擔','陸龜蒙','唐','唐诗','tang','','[]','輕無斗儲價，重則筋力絕。',48,'全唐诗/poet.tang.34000.json','["輕無斗儲價，重則筋力絕。", "欲下半巖時，憂襟兩如結。", "風高勢還却，雪厚疑中折。", "負荷誠獨難，移之贈來哲。"]'),
('c8cf2075-747b-403d-9585-9cee93b1eb09','樵人十詠 樵風','陸龜蒙','唐','唐诗','tang','','[]','朝隨早潮去，暮帶殘陽返。',48,'全唐诗/poet.tang.34000.json','["朝隨早潮去，暮帶殘陽返。", "向背得清飆，相追無近遠。", "採山一何遲，服道常苦蹇。", "仙術信能爲，年華未將晚。"]'),
('e4b4d480-ffc1-4ec1-bb07-318f36525998','樵人十詠 樵火','陸龜蒙','唐','唐诗','tang','','[]','積雪報松塢，蠹根然草堂。',48,'全唐诗/poet.tang.34000.json','["積雪報松塢，蠹根然草堂。", "深鑪與遠燒，此夜仍交光。", "或似坐奇獸，或如焚異香。", "堪嗟宦遊子，凍死道路傍。"]'),
('8ead8cd7-6e19-444a-979e-bce9cea25213','樵人十詠 樵歌','陸龜蒙','唐','唐诗','tang','','[]','縱調爲野吟，徐徐下雲磴。',48,'全唐诗/poet.tang.34000.json','["縱調爲野吟，徐徐下雲磴。", "因知負樵樂，不減援琴興。", "出林方自轉，隔水猶相應。", "但取天壤情，何求郢人稱。"]'),
('177e65b6-6cdd-4cbc-b0e0-acebe17d879b','奉和襲美酒中十詠 酒星','陸龜蒙','唐','唐诗','tang','','[]','萬古醇酎氣，結而成晶熒。',48,'全唐诗/poet.tang.34000.json','["萬古醇酎氣，結而成晶熒。", "降爲嵇阮徒，動與尊罍幷。", "不獨祭天廟，亦應邀客星。", "何當八月槎，載我遊青冥。"]'),
('3575d526-3618-4fe3-a57a-688c159435c7','奉和襲美酒中十詠 酒泉','陸龜蒙','唐','唐诗','tang','','[]','初懸碧崖口，漸注青谿腹。',48,'全唐诗/poet.tang.34000.json','["初懸碧崖口，漸注青谿腹。", "味既敵中山，飲寧拘一斛。", "春疑浸花骨，暮若酣雲族。", "此地得封侯，終身持美祿。"]'),
('91d76a16-2ae2-4ea2-92e7-82befdc74ac4','奉和襲美酒中十詠 酒篘','陸龜蒙','唐','唐诗','tang','','[]','山齋醞方熟，野童編近成。',48,'全唐诗/poet.tang.34000.json','["山齋醞方熟，野童編近成。", "持來歡伯內，坐使賢人清。", "不待盎中滿，旋供花下傾。", "汪汪日可挹，未羨黃金籯。"]'),
('c11139fa-b500-42f8-8903-0c4251195b84','奉和襲美酒中十詠 酒牀','陸龜蒙','唐','唐诗','tang','','[]','六尺樣何奇，溪邊濯來潔。',48,'全唐诗/poet.tang.34000.json','["六尺樣何奇，溪邊濯來潔。", "糟深貯方半，石重流還咽。", "閑移秋病可，偶聽寒夢缺。", "往往枕眠時，自疑陶靖節。"]'),
('3d21f850-0cfe-4328-a018-3b72bbc14226','奉和襲美酒中十詠 酒壚','陸龜蒙','唐','唐诗','tang','','[]','錦里多佳人，當壚自沽酒。',48,'全唐诗/poet.tang.34000.json','["錦里多佳人，當壚自沽酒。", "高低過反坫，大小隨圓瓿。", "數錢紅燭下，滌器春江口。", "若得奉君歡，十千求一斗。"]'),
('8091b191-449d-4456-8840-ad514f3622b9','奉和襲美酒中十詠 酒樓','陸龜蒙','唐','唐诗','tang','','[]','百尺江上起，東風吹酒香。',48,'全唐诗/poet.tang.34000.json','["百尺江上起，東風吹酒香。", "行人落帆上，遠樹涵殘陽。", "凝睇復凝睇，一觴還一觴。", "須知凭欄客，不醉難爲腸。"]'),
('a353e4fe-4308-42ca-bd27-8df0a72266b3','奉和襲美酒中十詠 酒旗','陸龜蒙','唐','唐诗','tang','','[]','搖搖倚青岸，遠蕩遊人思。',48,'全唐诗/poet.tang.34000.json','["搖搖倚青岸，遠蕩遊人思。", "風欹翠竹杠，雨澹香醪字。", "纔來隔煙見，已覺臨江遲。", "大斾非不榮，其如有王事。"]'),
('45a6752c-d954-47d4-a494-4bae4ed83ade','奉和襲美酒中十詠 酒尊','陸龜蒙','唐','唐诗','tang','','[]','黃金即爲侈，白石又太拙。',48,'全唐诗/poet.tang.34000.json','["黃金即爲侈，白石又太拙。", "斲得奇樹根，中如老蛟穴。", "時招山下叟，共酌林間月。", "盡醉兩忘言，誰能作天舌。"]'),
('8fa09077-3220-4fd4-aa0c-9568a0e23ecb','奉和襲美酒中十詠 酒城','陸龜蒙','唐','唐诗','tang','','[]','何代驅生靈，築之爲釀地。',48,'全唐诗/poet.tang.34000.json','["何代驅生靈，築之爲釀地。", "殊無甲兵守，但有糟漿氣。", "雉堞屹如狂，女牆低似醉。", "必若據而爭，先登儀狄氏。"]'),
('90bdeecd-8318-4bef-a295-dcf6df02b68d','奉和襲美酒中十詠 酒鄉','陸龜蒙','唐','唐诗','tang','','[]','誰知此中路，暗出虛無際。',48,'全唐诗/poet.tang.34000.json','["誰知此中路，暗出虛無際。", "廣莫是鄰封，華胥爲附麗。", "三杯聞古樂，伯雅逢遺裔。", "自爾等榮枯，何勞問玄弟。"]'),
('39f42324-d398-4064-b60a-79a451be4d81','添酒中六詠 酒池','陸龜蒙','唐','唐诗','tang','','[]','萬斛輸曲沼，千鍾未爲多。',48,'全唐诗/poet.tang.34000.json','["萬斛輸曲沼，千鍾未爲多。", "殘霞入醍齊，遠岸澄白酇。", "后土亦沈醉，姦臣空浩歌。", "邇來荒淫君，尚得乘餘波。"]'),
('7ee8265d-697c-45ef-a281-5b3ea95b89d6','添酒中六詠 酒龍','陸龜蒙','唐','唐诗','tang','','[]','銅雀羽儀麗，金龍光彩奇。',48,'全唐诗/poet.tang.34000.json','["銅雀羽儀麗，金龍光彩奇。", "潛傾鄴宮酒，忽作商庭漦。", "若怒鱗甲赤，如酣頭角垂。", "君臣坐相滅，安用驕奢爲。"]'),
('8ce49d04-05bf-47c7-a10c-643d57bdc54a','添酒中六詠 酒甕','陸龜蒙','唐','唐诗','tang','','[]','候煖麴糵調，覆深苫蓋淨。',48,'全唐诗/poet.tang.34000.json','["候煖麴糵調，覆深苫蓋淨。", "溢處每淋漓，沈來還濎瀅。", "常聞清涼酎，可養希夷性。", "盜飲以爲名，得非君子病。"]'),
('ac14ca5b-707f-4239-9df8-3a7649647420','添酒中六詠 酒船','陸龜蒙','唐','唐诗','tang','','[]','昔人性何誕，欲載無窮酒。',48,'全唐诗/poet.tang.34000.json','["昔人性何誕，欲載無窮酒。", "波上任浮身，風來即開口。", "荒唐意難遂，沈湎名不朽。", "千古如比肩，問君能繼不。"]'),
('aba0ad7a-0251-44e9-9015-9a3edb296b17','添酒中六詠 酒鎗','陸龜蒙','唐','唐诗','tang','','[]','景山實名士，所玩垂清塵。',48,'全唐诗/poet.tang.34000.json','["景山實名士，所玩垂清塵。", "嘗作酒家語，自言中聖人。", "奇器質含古，挫糟未應醇。", "唯懷魏公子，即此飛觴頻。"]'),
('c8366d23-ac39-4970-be2a-f19463104aa0','添酒中六詠 酒杯','陸龜蒙','唐','唐诗','tang','','[]','叔夜傲天壤，不將琴酒疎。',48,'全唐诗/poet.tang.34000.json','["叔夜傲天壤，不將琴酒疎。", "製爲酒中物，恐是琴之餘。", "一弄廣陵散，又裁絕交書。", "頹然擲林下，身世俱何如。"]'),
('094e8152-864b-40a0-8bef-3a2e368ef4fa','奉和襲美茶具十詠 茶塢','陸龜蒙','唐','唐诗','tang','','[]','茗地曲隈回，野行多繚繞。',48,'全唐诗/poet.tang.34000.json','["茗地曲隈回，野行多繚繞。", "向陽就中密，背澗差還少。", "遙盤雲髻慢，亂簇香篝小。", "何處好幽期，滿巖春露曉。"]'),
('9d08f041-f1d6-4c56-bc37-f7ce711d1976','奉和襲美茶具十詠 茶人','陸龜蒙','唐','唐诗','tang','','[]','天賦識靈草，自然鍾野姿。',48,'全唐诗/poet.tang.34000.json','["天賦識靈草，自然鍾野姿。", "閑來北山下，似與東風期。", "雨後探芳去，雲間幽路危。", "唯應報春鳥，得共斯人知。"]'),
('bf2aeb1a-e51f-4180-a8af-7281b8b267c1','奉和襲美茶具十詠 茶筍','陸龜蒙','唐','唐诗','tang','','[]','所孕和氣深，時抽玉苕短。',48,'全唐诗/poet.tang.34000.json','["所孕和氣深，時抽玉苕短。", "輕煙漸結華，嫩蘂初成管。", "尋來青靄曙，欲去紅雲煖。", "秀色自難逢，傾筐不曾滿。"]'),
('5ac53c59-6600-497b-b08c-84fac2d5b536','奉和襲美茶具十詠 茶籯','陸龜蒙','唐','唐诗','tang','','[]','金刀劈翠筠，織似波文斜。',48,'全唐诗/poet.tang.34000.json','["金刀劈翠筠，織似波文斜。", "製作自野老，攜持伴山娃。", "昨日鬬煙粒，今朝貯綠華。", "爭歌調笑曲，日暮方還家。"]'),
('39f41c50-f6f9-48eb-8b34-ee81eef5048d','奉和襲美茶具十詠 茶舍','陸龜蒙','唐','唐诗','tang','','[]','旋取山上材，架爲山下屋。',48,'全唐诗/poet.tang.34000.json','["旋取山上材，架爲山下屋。", "門因水勢斜，壁任巖隈曲。", "朝隨鳥俱散，暮與雲同宿。", "不憚採掇勞，祗憂官未足。"]'),
('2aef4ca3-512d-443f-81f6-6f7b0e6d98f3','奉和襲美茶具十詠 茶竈','陸龜蒙','唐','唐诗','tang','','[]','無突抱輕嵐，有煙映初旭。',48,'全唐诗/poet.tang.34000.json','["無突抱輕嵐，有煙映初旭。", "盈鍋玉泉沸，滿甑雲芽熟。", "奇香襲春桂，嫩色凌秋菊。", "煬者若吾徒，年年看不足。"]'),
('7d2c8f19-5499-476b-adf2-936795dd3218','奉和襲美茶具十詠 茶焙','陸龜蒙','唐','唐诗','tang','','[]','左右擣凝膏，朝昏布煙縷。',48,'全唐诗/poet.tang.34000.json','["左右擣凝膏，朝昏布煙縷。", "方圓隨樣拍，次第依層取。", "山謠縱高下，火候還文武。", "見說焙前人，時時炙花脯。"]'),
('9ac95600-20cf-4836-ae71-673f804e8a0b','奉和襲美茶具十詠 茶鼎','陸龜蒙','唐','唐诗','tang','','[]','新泉氣味良，古鐵形狀醜。',48,'全唐诗/poet.tang.34000.json','["新泉氣味良，古鐵形狀醜。", "那堪風雪夜，更值煙霞友。", "曾過赬石下，又住清溪口。", "且共薦臯盧，何勞傾斗酒。"]'),
('7e3d5abd-45ec-425a-9ded-a8bbc90a2641','奉和襲美茶具十詠 茶甌','陸龜蒙','唐','唐诗','tang','','[]','昔人謝塸埞，徒爲妍詞飾。',48,'全唐诗/poet.tang.34000.json','["昔人謝塸埞，徒爲妍詞飾。", "豈如珪璧姿，又有煙嵐色。", "光參筠席上，韻雅金罍側。", "直使于闐君，從來未嘗識。"]'),
('e85e0d00-d945-494d-ac10-c77b2756adba','奉和襲美茶具十詠 煮茶','陸龜蒙','唐','唐诗','tang','','[]','閑來松間坐，看煮松上雪。',48,'全唐诗/poet.tang.34000.json','["閑來松間坐，看煮松上雪。", "時於浪花裏，併下藍英末。", "傾餘精爽健，忽似氛埃滅。", "不合別觀書，但宜窺玉札。"]'),
('a526bb16-2274-4966-ab74-bcfca61e5559','置酒行','陸龜蒙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','落塵花片排香痕，闌珊醉露栖愁魂。',64,'全唐诗/poet.tang.34000.json','["落塵花片排香痕，闌珊醉露栖愁魂。", "洞庭波色惜不得，東風領入黃金尊。", "千筠擲毫春譜大，碧舞紅啼相倡和。", "安知寂寞西海頭，青𥳇未垂孤鳳餓。"]'),
('9a252887-e6d7-4c41-a14d-7f4050d4a099','江湖散人歌','陸龜蒙','唐','唐诗','tang','','[]','江湖散人天骨奇，短髪搔來蓬半垂。',344,'全唐诗/poet.tang.34000.json','["江湖散人天骨奇，短髪搔來蓬半垂。", "手提孤篁曳寒繭，口誦太古滄浪詞。", "詞云太古萬萬古，民性甚野無風期。", "夜棲止與禽獸雜，獨自構架縱橫枝。", "因而稱曰有巢氏，民共敬貴如君師。", "當時只效烏鵲輩，豈是有意陳尊卑。", "無端後聖穿鑿破，一派前導千流隨。", "多方惱亂元氣死，日使文字生姦欺。", "聖人事業轉銷耗，尚有漁者存熙熙。", "風波不獨困一士，凡百器具皆能施。", "罛疎滬腐鱸鱖脫，止失檢馭無讒疵。", "人間所謂好男子，我見婦女留鬚眉。", "奴顏婢膝真乞丐，反以正直爲狂癡。", "所以頭欲散，不散弁峩巍。", "所以腰欲散，不散珮陸離。", "行散任之適，坐散從傾欹。", "語散空谷應，笑散春雲披。", "衣散單複便，食散酸醎宜。", "書散渾真草，酒散甘醇醨。", "屋散勢斜直，樹散行參差。", "客散忘簪屨，禽散虛籠池。", "物外一以散，中心散何疑。", "不共諸侯分邑里，不與天子專隍陴。", "靜則守桑柘，亂則逃妻兒。"]'),
('efa4111e-73c5-4d4a-8ea6-d970c9385562','五歌 放牛','陸龜蒙','唐','唐诗','tang','','[]','江草秋窮似秋半，十角吳牛放江岸。',64,'全唐诗/poet.tang.34000.json','["江草秋窮似秋半，十角吳牛放江岸。", "鄰肩抵尾乍依隈，橫去斜奔忽分散。", "荒陂斷塹無端入，背上時時孤鳥立。", "日暮相將帶雨歸，田家煙火微茫濕。"]'),
('d5cf054c-6fd0-4cb2-a37e-02ac722b9d89','五歌 水鳥','陸龜蒙','唐','唐诗','tang','','[]','水鳥山禽雖異名，天工各與雙翅翎。',228,'全唐诗/poet.tang.34000.json','["水鳥山禽雖異名，天工各與雙翅翎。", "雛巢吞啄即一例，游處高卑殊不停。", "則有觜鈹爪戟勁立直眎者，擊搏挽裂圖羶腥。", "如此等色恣豪橫，聳身往往凌青冥。", "爲人羅絆取材力，韋韝綵綬懸金鈴。", "三驅不以鳥捕鳥，矢下先得聞諸經。", "超然可繼義勇後，恰似有志行天刑。", "鷗閑鶴散兩自遂，意思不受人丁寧。", "今朝櫂倚寒江汀，舂鉏翡翠參鵁鶄。", "孤翹側睨瞥滅沒，未是即肯馴簷楹。", "婦女衣襟便佞舌，始得金籠日提挈。", "精神卓犖背人飛，冷抱蒹葭宿煙月。", "我與時情大乖刺，祗是江禽有毛髪。", "慇懃謝汝莫相猜，歸來長短同羣活。"]'),
('7b82a916-fdb7-4132-9241-b61d520984c7','五歌 刈穫','陸龜蒙','唐','唐诗','tang','','[]','自春徂秋天弗雨，廉廉早稻纔遮畝。',192,'全唐诗/poet.tang.34000.json','["自春徂秋天弗雨，廉廉早稻纔遮畝。", "芒粒稀疎熟更輕，地與禾頭不相拄。", "我來愁築心如堵，更聽農夫夜深語。", "凶年是物即爲災，百陣野鳧千穴鼠。", "平明抱杖入田中，十穗蕭條九穗空。", "敢言一歲囷倉實，不了如今朝暮舂。", "天職誰司下民籍，苟有區區宜㭊㭊。", "本作耕耘意若何，蟲豸兼教食人食。", "古者爲邦須蓄積，魯饑尚責如齊糴。", "今之爲政異當時，一任流離恣徵索。", "平生幸遇華陽客，向日餐霞轉肥白。", "欲賣耕牛棄水田，移家且傍三茅宅。"]'),
('0918d722-8bc2-4a3d-b288-c5880b5d4691','五歌 雨夜','陸龜蒙','唐','唐诗','tang','','[]','屋小茅乾雨聲大，自疑身著蓑衣臥。',64,'全唐诗/poet.tang.34000.json','["屋小茅乾雨聲大，自疑身著蓑衣臥。", "兼似孤舟小泊時，風吹折葦來相佐。", "我有愁襟無可那，纔成好夢剛驚破。", "背壁殘燈不及螢，重挑却向燈前坐。"]'),
('200abdc2-254b-48b2-8496-5b975c2e2e86','五歌 食魚','陸龜蒙','唐','唐诗','tang','','[]','江南春旱魚無澤，歲晏未曾腥鼎鬲。',96,'全唐诗/poet.tang.34000.json','["江南春旱魚無澤，歲晏未曾腥鼎鬲。", "今朝有客賣鱸魴，手提見我長於尺。", "呼兒舂取紅蓮米，輕重相當加十倍。", "且作吳羹助早餐，飽臥晴簷曝寒背。", "橫戈負羽正紛紛，祗用驍雄不用文。", "爭如曉夕謳吟樣，好伴滄洲白鳥羣。"]'),
('81e1d557-b65a-4829-996e-7015c74aa9ed','丁隱君歌','陸龜蒙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','華陽道士南遊歸，手中半卷青蘿衣。',184,'全唐诗/poet.tang.34000.json','["華陽道士南遊歸，手中半卷青蘿衣。", "自言逋客持贈我，乃是錢搪丁翰之。", "連江大抵多奇岫，獨話君家最奇秀。", "盤燒天竺春筍肥，琴倚洞庭秋石瘦。", "草堂暗引龍泓溜，老樹根株若蹲獸。", "霜濃果熟未容收，往往兒童雜猨狖。", "去歲猖狂有黃寇，官軍解散無人鬬。", "滿城奔迸翰之閑，只把枯松塞圭竇。", "前度相逢正賣文，一錢不直虛云云。", "今來利作採樵客，可以拋身麋鹿羣。", "丁隱君，丁隱君，叩頭且莫變名氏，即日更尋丁隱君。"]'),
('78761f91-dc8a-4ae9-8810-5daf2304cf05','紫溪翁歌','陸龜蒙','唐','唐诗','tang','','[]','一丘之木，其棲深也屋，吾容不辱。',65,'全唐诗/poet.tang.34000.json','["一丘之木，其棲深也屋，吾容不辱。", "一溪之石，其居平也席，吾勞以息。", "一竇之泉，其音清也弦，吾方在懸。", "得乎人，得乎天，吾不知所以然而然。"]'),
('bbaa025f-cbda-47fb-baa4-00acf6cbd275','賡歌','陸龜蒙','唐','唐诗','tang','','[]','采江之魚兮，朝船有鱸。',42,'全唐诗/poet.tang.34000.json','["采江之魚兮，朝船有鱸。", "采江之蔬兮，暮筐有蒲。", "左圖且書，右琴與壺。", "壽歟夭歟，貴歟賤歟。"]'),
('59e9bd87-2d5d-4594-a292-91849fc4703d','鶴媒歌','陸龜蒙','唐','唐诗','tang','','[]','偶繫漁舟汀樹枝，因看射鳥令人悲。',163,'全唐诗/poet.tang.34000.json','["偶繫漁舟汀樹枝，因看射鳥令人悲。", "盤空野鶴忽然下，背翳見媒心不疑。", "媒閑靜立如無事，清唳時時入遙吹。", "裴回未忍過南塘，且應同聲就同類。", "梳翎宛若相逢喜，祗怕纔來又驚起。", "窺鱗啄藻乍低昂，立定當胸流一矢。", "媒歡舞躍勢離披，似諂功能邀弩兒。", "雲飛水宿各自物，妬侶害羣猶爾爲。", "而況世間有名利，外頭笑語中猜忌。", "君不見荒陂野鶴陷良媒，同類同聲真可畏。"]'),
('8cf63533-4fe0-46a6-982f-ed945ef9bc7b','慶封宅古井行','陸龜蒙','唐','唐诗','tang','','[]','古甓團團蘚花碧，鼎渫寒泉深百尺。',160,'全唐诗/poet.tang.34000.json','["古甓團團蘚花碧，鼎渫寒泉深百尺。", "江南戴白盡能言，此地曾爲慶封宅。", "慶封嗜酒荒齊政，齊人剪族封奔迸。", "雖過魯國羞魯儒，欲弄吳民竊吳柄。", "吳分巖邑號朱方，子家負固心彊梁。", "澤車豪馬馳似水，錦鳳玉龍森若牆。", "一朝雲夢圍兵至，胸陷鋒鋩腦塗地。", "因知富德不富財，顏氏簞瓢有深意。", "宣父嘗違盜泉水，懦夫立事貪夫止。", "今歌此井示吳人，斷綆沉瓶自茲始。"]'),
('3cfb58cd-7d67-4789-b137-f709383031fc','小雞山樵人歌','陸龜蒙','唐','唐诗','tang','','[]','長其船兮利其斧，輸予薪兮勿予侮。',58,'全唐诗/poet.tang.34000.json','["長其船兮利其斧，輸予薪兮勿予侮。", "田予登兮穀予庾，突晨煙兮蓬縷縷。", "窗有明兮編有古，飽而安兮惟編是伍，時不用兮吾無汝撫。"]'),
('04a2b832-5114-4dc7-ac24-ab678a02e61a','吳俞兒舞歌 劒俞','陸龜蒙','唐','唐诗','tang','','[]','枝月喉，櫂霜脊，北斗離離在寒碧。',81,'全唐诗/poet.tang.34000.json','["枝月喉，櫂霜脊，北斗離離在寒碧。", "龍魂清，虎尾白，秋照海心同一色。", "纛影吒沙千影側，神豪髪直。", "四睨之人股佶栗，欲定不定定不得。", "舂牘殘，兒且止，狄胡有膽大如山，怖亦死。"]'),
('d06d3899-567d-4285-bd18-aabd8977a985','吳俞兒舞歌 矛俞','陸龜蒙','唐','唐诗','tang','','[]','手盤風，頭背分。',61,'全唐诗/poet.tang.34000.json','["手盤風，頭背分。", "電光戰扇，欲刺敲心留半綫。", "纏肩繞脰，𧞔合眩旋。", "卓植赴列，奪避中節。", "前衝函禮穴，上指孛彗滅，與君一用來有截。"]'),
('9594393c-6dc9-43b7-b8f1-7b895431b896','吳俞兒舞歌 弩俞','陸龜蒙','唐','唐诗','tang','','[]','牛來開弦，人爲置鏃。',69,'全唐诗/poet.tang.34000.json','["牛來開弦，人爲置鏃。", "捩機關，迸山谷。", "鹿駭澀，隼擊遲。", "析毫中睫，洞腋分龜。", "達堅壘，殘雄師。", "可以冠猛樂壯曲，抑揚蹈厲。", "有裂犀兕之氣者，非公與。"]'),
('af3d4e82-aed6-40d0-a57b-e529905f26ef','句曲山朝真詞二首 迎真','陸龜蒙','唐','唐诗','tang','','[]','九華磬荅寒泉急，十絕幡搖翠微濕。',64,'全唐诗/poet.tang.34000.json','["九華磬荅寒泉急，十絕幡搖翠微濕。", "司命旍旌未下來，焚香抱簡凝神立。", "殘星下照霓襟冷，缺月纔分鶴輪影。", "空洞靈章發一聲，春來萬壑煙花醒。"]'),
('7f7aa10e-e6ad-483f-98f2-94f5f2dc3aae','句曲山朝真詞二首 送真','陸龜蒙','唐','唐诗','tang','','[]','縈雲鳳髻飄然解，玉鉞玄干儼先邁。',67,'全唐诗/poet.tang.34000.json','["縈雲鳳髻飄然解，玉鉞玄干儼先邁。", "朝真弟子悄無言，再拜碧杯添沆瀣。", "火{金靈}跳躍龍毛蓋，腦髪青青赮綷綷。", "萬象銷沈一瞬間，空餘月外聞殘佩。"]'),
('949a318f-fa86-4f0b-8fb1-ada5bad20bc8','戰秋辭','陸龜蒙','唐','唐诗','tang','','[]','八月空堂，前臨隙荒。',330,'全唐诗/poet.tang.34000.json','["八月空堂，前臨隙荒。", "抽關散扇，晨烏未光。", "左右物態，森疎強梁。", "天隨子爽駴恂慄，恍軍庸之我當。", "濠然而溝，壘然而牆。", "纛然而桂，隊然而篁。", "杉巉攢矛，蕉標建常。", "槁艾矢束，矯蔓弦張。", "蛙合助吹，鳥分啓行。", "若革進而金止，固違陰而就陽。", "無何，雲顏師，風旨伯，蒼茫慘澹，隳危摵劃。", "煙蒙上焚，雨陣下棘。", "如濠者注，如壘者闢，如纛者亞，如隊者析，如矛者折，如常者拆，如矢者仆，如弦者磔，如吹者瘖，如行者惕，石有髪兮盡纍，木有耳兮咸馘。", "雲風雨煙，乘勝之勢驕。", "杉篁蕉蔓，敗北之氣摵。", "天隨子曰：吁！秋無神則已，如其有神，吾爲爾羞之。", "南北畿圻，盜興五朞。", "方州大都，虎節龍旗。", "瓦解冰碎，瓜分豆離。", "斧抵耋老，干穿乳兒。", "昨宇今燼，朝人暮尸。", "萬犢一啗，千倉一炊。", "擾踐邊朔，殲傷蜑夷。", "制質守帥，披攘城池。"]'),
('4c692b37-a166-4fad-a9e5-15bdc3405975','祝牛宮辭','陸龜蒙','唐','唐诗','tang','','[]','四牸三牯，中一去乳。',110,'全唐诗/poet.tang.34000.json','["四牸三牯，中一去乳。", "天霜降寒，納此室處。", "老農拘拘，度地不畝。", "東西幾何，七舉其武。", "南北幾何，丈二加五。", "偶楹當閑，載尺入土。", "太歲在亥，餘不足數。", "上締蓬茅，下遠官府。", "耕耨以時，飲食得所。", "或寢或臥，免風免雨。", "宜爾子孫，實我倉庾。"]'),
('25a8bf44-b319-4467-bbf3-42b70cc4cbcc','迎潮送潮辭 迎潮','陸龜蒙','唐','唐诗','tang','','[]','江霜嚴兮楓葉丹，潮聲高兮墟落寒。',86,'全唐诗/poet.tang.34000.json','["江霜嚴兮楓葉丹，潮聲高兮墟落寒。", "鷗巢卑兮漁箔短，遠岸沒兮光爛爛。", "潮之德兮無際，既充其大兮又充其細。", "密幽人兮欵柴門，寂寞流連兮依稀舊痕。", "濡腴澤槁兮潮之恩，不尸其功兮歸於混元。"]'),
('dd461073-ba62-4320-acee-87365b1dd2e1','迎潮送潮辭 送潮','陸龜蒙','唐','唐诗','tang','','[]','潮西來兮又東下，日染中流兮紅灑灑。',85,'全唐诗/poet.tang.34000.json','["潮西來兮又東下，日染中流兮紅灑灑。", "汀葭蒼兮嶼蓼枯，風騷牢兮愁煙孤。", "大幾望兮微將晦翳，睨瀛溶兮斂然而退。", "愛長波兮數數，一幅巾兮無纓可濯。", "帆生塵兮檝有衣，悵潮之還兮吾猶未歸。"]'),
('81876772-2380-492b-be1f-22e68976d9f8','問吳宮辭','陸龜蒙','唐','唐诗','tang','','[]','彼吳之宮兮江之郍涯，複道盤兮當高且斜。',144,'全唐诗/poet.tang.34000.json','["彼吳之宮兮江之郍涯，複道盤兮當高且斜。", "波搖疏兮霧濛箔，菡萏國兮鴛鴦家。", "鸞之簫兮蛟之瑟，駢筠參差兮界絲密。", "讌曲房兮上初日，月落星稀兮歌酣未畢。", "越山叢叢兮越溪疾，美人雄劒兮相先後出。", "火姑蘇兮沼長洲，此宮之麗人兮留乎不留。", "霜氛重兮孤榜曉，遠樹扶蘇兮愁煙悄眇。", "欲摭愁煙兮問故基，又恐愁煙兮推白鳥。"]'),
('f9f361c9-9922-4527-a77b-3c221e618f48','螢詩','陸龜蒙','唐','唐诗','tang','','[]','肖翹雖振羽，戚促盡疑冰。',48,'全唐诗/poet.tang.34000.json','["肖翹雖振羽，戚促盡疑冰。", "風助流還急，煙遮點漸凝。", "不須輕列宿，纔可擬孤燈。", "莫倚隋家事，曾煩下詔徵。"]'),
('8115dc0c-1669-4c12-b7e4-ee0c793dc411','蟬','陸龜蒙','唐','唐诗','tang','','[]','祗憑風作使，全仰柳爲都。',48,'全唐诗/poet.tang.34000.json','["祗憑風作使，全仰柳爲都。", "一腹清何甚，雙翎薄更無。", "伴貂金換酒，幷雀畫成圖。", "恐是千年恨，偏令落日呼。"]'),
('980b31b0-9ced-4403-b8c8-2f9740da30c0','秋熱','陸龜蒙','唐','唐诗','tang','','[]','自惜秋捐扇，今來意未衰。',48,'全唐诗/poet.tang.34000.json','["自惜秋捐扇，今來意未衰。", "慇懃付柔握，淅瀝待清吹。", "午氣朱崖近，宵聲白羽隨。", "總如南國候，無復婕妤悲。"]'),
('4a65189f-536c-4efc-9573-36e336f8ad34','村中晚望','陸龜蒙','唐','唐诗','tang','','[]','抱杖柴門立，江村日易斜。',48,'全唐诗/poet.tang.34000.json','["抱杖柴門立，江村日易斜。", "鴈寒猶憶侶，人病更離家。", "短鬢看成雪，雙眸舊有花。", "何須萬里外，即此是天涯。"]'),
('cb06c787-a424-4600-a546-a140dbfe2191','四明山詩 石窗','陸龜蒙','唐','唐诗','tang','','[]','石窗何處見，萬仞倚晴虛。',48,'全唐诗/poet.tang.34000.json','["石窗何處見，萬仞倚晴虛。", "積靄迷青璅，殘霞動綺疏。", "山應列圓嶠，宮便接方諸。", "祗有三奔客，時來教隱書。"]'),
('341cf4a4-ff3c-42d4-85d9-a0a670f3e271','四明山詩 過雲','陸龜蒙','唐','唐诗','tang','','[]','相訪一程雲，雲深路僅分。',48,'全唐诗/poet.tang.34000.json','["相訪一程雲，雲深路僅分。", "嘯臺隨日辨，樵斧帶風聞。", "曉著衣全濕，寒衝酒不醺。", "幾迴歸思靜，髣髴見蘇君。"]'),
('ea82da93-b4cd-4f6a-a240-8221d373a72d','四明山詩 雲南','陸龜蒙','唐','唐诗','tang','','[]','雲南更有溪，丹礫盡無泥。',48,'全唐诗/poet.tang.34000.json','["雲南更有溪，丹礫盡無泥。", "藥有巴賨賣，枝多越鳥啼。", "夜清先月午，秋近少嵐迷。", "若得山顏住，芝𥰭手自攜。"]'),
('286906ac-00b2-4567-937e-ba5e5644b5e1','四明山詩 雲北','陸龜蒙','唐','唐诗','tang','','[]','雲北是陽川，人家洞壑連。',48,'全唐诗/poet.tang.34000.json','["雲北是陽川，人家洞壑連。", "壇當星斗下，樓拶翠微邊。", "一半遙峰雨，三條古井煙。", "金庭如有路，應到左神天。"]'),
('4d71c826-2e14-43e8-8f93-e5ba34de594e','四明山詩 鹿亭','陸龜蒙','唐','唐诗','tang','','[]','鹿亭巖下置，時領白麛過。',48,'全唐诗/poet.tang.34000.json','["鹿亭巖下置，時領白麛過。", "草細眠應久，泉香飲自多。", "認聲來月塢，尋跡到煙蘿。", "早晚吞金液，騎將上絳河。"]'),
('05cc5afb-1c3a-4942-804c-1149b79636f6','四明山詩 樊榭','陸龜蒙','唐','唐诗','tang','','[]','樊榭何年築，人應白日飛。',48,'全唐诗/poet.tang.34000.json','["樊榭何年築，人應白日飛。", "至今山客說，時駕玉麟歸。", "乳蔕緣松嫩，芝臺出石微。", "憑欄虛目斷，不見羽華衣。"]'),
('edef742a-1fcd-49a4-bd51-4a0995fdfce1','四明山詩 潺湲洞','陸龜蒙','唐','唐诗','tang','','[]','石淺洞門深，潺潺萬古音。',48,'全唐诗/poet.tang.34000.json','["石淺洞門深，潺潺萬古音。", "似吹雙羽管，如奏落霞琴。", "倒穴漂龍沫，穿松濺鶴襟。", "何人乘月弄，應作上清吟。"]'),
('09976f10-91ee-4c4d-a663-eb8dfe0755b7','四明山詩 青櫺子','陸龜蒙','唐','唐诗','tang','','[]','山實號青櫺，環岡次第生。',48,'全唐诗/poet.tang.34000.json','["山實號青櫺，環岡次第生。", "外形堅綠殼，中味敵璚英。", "墮石樵兒拾，敲林宿鳥驚。", "亦應仙吏守，時取薦層城。"]'),
('5320f946-4527-46f4-9688-028d6284a859','四明山詩 鞠侯','陸龜蒙','唐','唐诗','tang','','[]','何事鞠侯名，先封在四明。',48,'全唐诗/poet.tang.34000.json','["何事鞠侯名，先封在四明。", "但爲連臂飲，不作斷腸聲。", "野蔓垂纓細，寒泉佩玉清。", "滿林遊宦子，誰爲作君卿。"]'),
('56af20a6-2789-425a-97ed-28a37552cc37','奉和襲美贈魏處士五貺詩 五瀉舟','陸龜蒙','唐','唐诗','tang','','[]','樣自桐川得，詞因隱地成。',48,'全唐诗/poet.tang.34000.json','["樣自桐川得，詞因隱地成。", "好漁翁亦喜，新白鳥還驚。", "沙際擁江沫，渡頭橫雨聲。", "尚應嫌越相，遺禍不遺名。"]'),
('35fd5ab8-af29-47f0-9e4c-cfb438197174','奉和襲美贈魏處士五貺詩 華頂杖','陸龜蒙','唐','唐诗','tang','','[]','萬古陰崖雪，靈根不爲枯。',48,'全唐诗/poet.tang.34000.json','["萬古陰崖雪，靈根不爲枯。", "瘦於霜鶴脛，奇似黑龍鬚。", "拄訪譚玄客，持看潑墨圖。", "湖雲如有路，兼可到仙都。"]'),
('91d24f28-4a33-482c-a499-75c9be660fe0','奉和襲美贈魏處士五貺詩 太湖硯','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','誰截小秋灘，閑窺四緒寬。',48,'全唐诗/poet.tang.34000.json','["誰截小秋灘，閑窺四緒寬。", "繞爲千嶂遠，深置一潭寒。", "坐久雲應出，詩成墨未乾。", "不知新博物，何處擬重刊。"]'),
('29579d48-f7ae-43e6-a27e-ed64fbcbd246','奉和襲美贈魏處士五貺詩 烏龍養和','陸龜蒙','唐','唐诗','tang','','[]','養和名字好，偏寄道情深。',48,'全唐诗/poet.tang.34000.json','["養和名字好，偏寄道情深。", "所以親逋客，兼能助五禽。", "倚肩滄海望，鉤膝白雲吟。", "不是逍遙侶，誰知世外心。"]'),
('c813b9b4-133e-4917-8057-7d3104635788','奉和襲美贈魏處士五貺詩 訶陵尊','陸龜蒙','唐','唐诗','tang','','[]','魚骼匠成尊，猶殘海浪痕。',48,'全唐诗/poet.tang.34000.json','["魚骼匠成尊，猶殘海浪痕。", "外堪欺玳瑁，中可酌崑崙。", "水繞苔磯曲，山當草閣門。", "此中醒復醉，何必問乾坤。"]'),
('bbfe0efd-b325-42e2-8acf-1e9481292556','奉酬襲美早春病中書事','陸龜蒙','唐','唐诗','tang','','[]','祗貪詩調苦，不計病容生。',48,'全唐诗/poet.tang.34000.json','["祗貪詩調苦，不計病容生。", "我亦休文瘦，君能叔寶清。", "藥須勤一服，春莫累多情。", "欲入毘耶問，無人敵浄名。"]'),
('648e367d-98fd-40cb-81bd-bd9053a6e982','又酬次韻','陸龜蒙','唐','唐诗','tang','','[]','從來多遠思，尤向靜中生。',48,'全唐诗/poet.tang.34000.json','["從來多遠思，尤向靜中生。", "所以令心苦，還應是骨清。", "酒香偏入夢，花落又關情。", "積此風流事，爭無後世名。"]'),
('fa5747e1-1858-4a46-b497-cbafc0ad1a60','奉酬襲美秋晚見題二首 一','陸龜蒙','唐','唐诗','tang','','[]','爲愛晚窗明，門前亦嬾行。',48,'全唐诗/poet.tang.34000.json','["爲愛晚窗明，門前亦嬾行。", "圖書看得熟，鄰里見還生。", "鳥啄琴材響，僧傳藥味精。", "緣君多古思，攜手上空城。"]'),
('30293bd1-f00d-432a-b438-dd74b2e73291','奉酬襲美秋晚見題二首 二','陸龜蒙','唐','唐诗','tang','','[]','何事樂漁樵，巾車或倚橈。',48,'全唐诗/poet.tang.34000.json','["何事樂漁樵，巾車或倚橈。", "和詩盈古篋，賒酒半寒瓢。", "失雨園蔬赤，無風蚛葉彫。", "清言一相遺，吾道未全消。"]'),
('8cfea701-9290-48cd-b138-1ebc137218bc','奉和襲美初冬章上人院','陸龜蒙','唐','唐诗','tang','','[]','每伴來方丈，還如到四禪。',48,'全唐诗/poet.tang.34000.json','["每伴來方丈，還如到四禪。", "菊承荒砌露，茶待遠山泉。", "畫古全無跡，林寒却有煙。", "相看吟未竟，金磬已泠然。"]'),
('a99ea4f7-ac36-4f00-acaf-8b358fccb61c','襲美見題郊居十首因次韻酬之以伸榮謝 一','陸龜蒙','唐','唐诗','tang','','[]','近來唯樂靜，移傍故城居。',48,'全唐诗/poet.tang.34000.json','["近來唯樂靜，移傍故城居。", "閑打修琴料，時封謝藥書。", "夜停江上鳥，晴曬篋中魚。", "出亦圖何事，無勞置棧車。"]'),
('92d54911-b851-4bfa-a8a8-3bccb95eba2b','襲美見題郊居十首因次韻酬之以伸榮謝 二','陸龜蒙','唐','唐诗','tang','','[]','倩人醫病樹，看僕補衡茅。',48,'全唐诗/poet.tang.34000.json','["倩人醫病樹，看僕補衡茅。", "散髪還同阮，無心敢慕巢。", "簡便書露竹，尊待破霜匏。", "日好林間坐，煙蘿近欲交。"]'),
('3f1694aa-4e82-49e1-bfa4-834ca62023a4','襲美見題郊居十首因次韻酬之以伸榮謝 三','陸龜蒙','唐','唐诗','tang','','[]','倭僧留海紙，山匠製雲牀。',48,'全唐诗/poet.tang.34000.json','["倭僧留海紙，山匠製雲牀。", "嬾外應無敵，貧中直是王。", "池平鷗思喜，花盡蝶情忙。", "欲問新秋計，菱絲一畝強。"]'),
('26b088cb-0760-406e-ad25-12aac4d5d646','襲美見題郊居十首因次韻酬之以伸榮謝 四','陸龜蒙','唐','唐诗','tang','','[]','故山空自擲，當路竟誰知。',48,'全唐诗/poet.tang.34000.json','["故山空自擲，當路竟誰知。", "祗有經時策，全無養拙資。", "病深憐灸客，炊晚信樵兒。", "謾欲陳風俗，周官未採詩。"]'),
('57e63595-354e-4518-aedb-3199dc5de124','襲美見題郊居十首因次韻酬之以伸榮謝 五','陸龜蒙','唐','唐诗','tang','','[]','福地能容壍，玄關詎有扉。',48,'全唐诗/poet.tang.34000.json','["福地能容壍，玄關詎有扉。", "靜思瓊版字，閑洗鐵筇衣。", "鳥破涼煙下，人衝暮雨歸。", "故園秋草夢，猶記綠微微。"]'),
('6b0acb4e-9b4f-487b-8f01-0a54ac38659d','襲美見題郊居十首因次韻酬之以伸榮謝 六','陸龜蒙','唐','唐诗','tang','','[]','水影沈魚器，鄰聲動緯車。',48,'全唐诗/poet.tang.34000.json','["水影沈魚器，鄰聲動緯車。", "燕輕捎墜葉，蜂嬾臥燋花。", "說史評諸例，論兵到百家。", "明時如不用，歸去種桑麻。"]'),
('9edd45e4-0dfa-4120-97a8-58996ce16fbd','襲美見題郊居十首因次韻酬之以伸榮謝 七','陸龜蒙','唐','唐诗','tang','','[]','禹穴奇編缺，雷平異境殘。',48,'全唐诗/poet.tang.34000.json','["禹穴奇編缺，雷平異境殘。", "靜吟封籙檢，歸興削帆竿。", "白石堪爲飯，青蘿好作冠。", "幾時當斗柄，同上步罡壇。"]'),
('e738d519-b9d3-443a-bb92-bee9287dcfe0','襲美見題郊居十首因次韻酬之以伸榮謝 八','陸龜蒙','唐','唐诗','tang','','[]','強起披衣坐，徐行處暑天。',48,'全唐诗/poet.tang.34000.json','["強起披衣坐，徐行處暑天。", "上階來鬬雀，移樹去驚蟬。", "莫問鹽車駿，誰看醬瓿玄。", "黃金如可化，相近買雲泉。"]'),
('767e8df8-13e7-401e-8716-fa12ad99fb0e','襲美見題郊居十首因次韻酬之以伸榮謝 九','陸龜蒙','唐','唐诗','tang','','[]','野入青蕪巷，陂侵白竹門。',48,'全唐诗/poet.tang.34000.json','["野入青蕪巷，陂侵白竹門。", "風高開栗刺，沙淺露芹根。", "迸鼠緣藤桁，飢烏立石盆。", "東吳雖不改，誰是武王孫。"]'),
('af0eca6a-417b-4fec-b0f7-284820122e11','襲美見題郊居十首因次韻酬之以伸榮謝 十','陸龜蒙','唐','唐诗','tang','','[]','疎慵真有素，時勢盡無能。',48,'全唐诗/poet.tang.34000.json','["疎慵真有素，時勢盡無能。", "風月雖爲敵，林泉幸未憎。", "酒材經夏闕，詩債待秋徵。", "祗有君同癖，閑來對曲肱。"]'),
('9dd6e645-170e-4363-8860-37f11f969b32','和張廣文賁旅泊吳門次韻','陸龜蒙','唐','唐诗','tang','','[]','高秋能叩觸，天籟忽成文。',48,'全唐诗/poet.tang.34000.json','["高秋能叩觸，天籟忽成文。", "苦調雖潛倚，靈音自絕羣。", "茅峰曾醮斗，笠澤久眠雲。", "許伴山中躅，三年任一醺。"]'),
('e7410d1e-8595-45e8-a734-300391d89a35','又次前韻酬廣文','陸龜蒙','唐','唐诗','tang','','[]','獨倚秋光岸，風漪學簟文。',48,'全唐诗/poet.tang.34000.json','["獨倚秋光岸，風漪學簟文。", "玄堪教鳳集，書好換鵝羣。", "葉墮平臺月，香消古徑雲。", "強歌非白紵，聊以送餘醺。"]'),
('bb12412d-2bbe-48d2-80e7-b3b05d196027','送延陵張宰','陸龜蒙','唐','唐诗','tang','','[]','春盡未離關，之官亦似閑。',48,'全唐诗/poet.tang.34000.json','["春盡未離關，之官亦似閑。", "不嫌請薄俸，爲喜帶名山。", "默禱三真後，高吟十字還。", "祗應江上鳥，時下訟庭間。"]'),
('087341a4-1c74-4e0c-b832-eddc91048a2c','送人罷官歸茅山','陸龜蒙','唐','唐诗','tang','','[]','呼僮曉拂鞍，歸上大茅端。',48,'全唐诗/poet.tang.34000.json','["呼僮曉拂鞍，歸上大茅端。", "薄俸雖休入，明霞自足餐。", "暗霜松粒赤，疎雨草堂寒。", "又鑿中峰石，重修醮月壇。"]'),
('9ed5bbbf-a7ea-428a-9f22-00773c5b57cc','立春日','陸龜蒙','唐','唐诗','tang','','[]','去年花落時，題作送春詩。',48,'全唐诗/poet.tang.34000.json','["去年花落時，題作送春詩。", "自爲重相見，應無今日悲。", "道孤逢識寡，身病買名遲。", "一夜東風起，開簾不敢窺。"]'),
('4dcbff2b-29e8-4802-926c-6fee68446b8e','中秋夜寄友生','陸龜蒙','唐','唐诗','tang','','[]','秋來一度滿，重見色難齊。',48,'全唐诗/poet.tang.34000.json','["秋來一度滿，重見色難齊。", "獨坐猶過午，同吟不到西。", "疎芒唯斗在，殘白合河迷。", "更憶前年望，孤舟泊大溪。"]'),
('fdd041c2-5765-4068-b3ee-07699c082d67','奉和襲美古杉三十韻','陸龜蒙','唐','唐诗','tang','','[]','衆木盡相遺，孤芳獨任奇。',288,'全唐诗/poet.tang.34000.json','["衆木盡相遺，孤芳獨任奇。", "鍤天形硉兀，當殿勢𢼮危。", "恐是夸娥怒，教臨嶻嶭衰。", "節穿開耳目，根癭坐熊羆。", "世只論榮落，人誰問等衰。", "有巔從日上，無葉與秋欺。", "虎搏應難動，鵰蹲不敢遲。", "戰鋒新缺齾，燒岸黑𪑿黧。", "鬬死龍骸雜，爭奔鹿角差。", "肢銷洪水腦，稜聳梵天眉。", "磔索珊瑚湧，森嚴獬豸窺。", "向空分犖指，衝浪出鯨鬐。", "楊僕船橦在，蚩尤陣纛隳。", "下連金粟固，高用鐵菱披。", "挺若苻堅棰，浮於祖納椎。", "崢嶸驚露鶴，䟐趚閡雲螭。", "傍宇將支壓，撐霄欲抵隵。", "背交蟲臂挶，相向鶻拳追。", "格筆差猶立，階干卓未麾。", "鬼神應暗畫，風雨恐潛移。", "已覺寒松伏，偏宜后土疲。", "好邀清嘯傲，堪映古茅茨。", "材大應容蝎，年深必孕夔。", "後雕依佛氏，初植必僧彌。"]'),
('8647dc9e-1f83-4b73-8ae9-8ab0bd38ef86','奉和襲美新秋言懷三十韻次韻','陸龜蒙','唐','唐诗','tang','','[]','身閑唯愛靜，籬外是荒郊。',288,'全唐诗/poet.tang.34000.json','["身閑唯愛靜，籬外是荒郊。", "地僻憐同巷，庭喧厭累巢。", "岸聲搖舴艋，窗影辨蠨蛸。", "徑祗溪禽下，關唯野客敲。", "竹岡從古凸，池緣本來䫜。", "早藕擎霜節，涼花束紫梢。", "漁情隨錘網，獵興起鳴𩩉。", "好夢經年說，名方著處抄。", "才疎惟自補，技癢欲誰抓。", "窗靜常懸䕹，鞭閑不正鞘。", "山衣輕斧藻，天籟逸弦匏。", "蕙轉風前帶，桃烘雨後膠。", "蘚乾黏晚砌，煙濕動晨庖。", "沈約便圖籍，揚雄重酒肴。", "目曾窺絕洞，耳不犯征鐃。", "曆外窮飛朔，蓍中記伏爻。", "石林空寂歷，雲肆肯嘵譊。", "松桂何妨蠹，龜龍亦任嘲。", "未能丹作髓，誰相紫爲胞。", "莫把榮枯異，但和大小包。", "由弓猨不捷，梁圈虎忘虓。", "舊友懷三益，關山阻二崤。", "道隨書簏古，時共釣輪拋。", "好作忘機士，須爲莫逆交。"]'),
('40a48118-a069-45c2-b41a-bd8c7f58e9c5','和襲美江南書情二十韻寄祕閣韋校書貽之商洛宋先輩垂文二同年次韻','陸龜蒙','唐','唐诗','tang','','[]','我志如魚樂，君詞稱鳳銜。',240,'全唐诗/poet.tang.34000.json','["我志如魚樂，君詞稱鳳銜。", "暫來從露冕，何事買雲巖。", "水石應容病，松篁未聽讒。", "罐香松蠹膩，山信藥苗緘。", "愛鷺欹危立，思猨矍鑠獑。", "謝才偏許朓，阮放最憐咸。", "大樂寧忘缶，奇工肯顧瑊。", "客愁迷舊隱，鷹健想秋毚。", "硯缺猶慵琢，文繁却要芟。", "雨餘幽沼淨，霞散遠峰巉。", "洗筆煙成段，培花土作杴。", "訪僧還覓伴，醫鶴自須監。", "荒廟猶懷季，清灘幾夢嚴。", "背風開蠹簡，衝浪試新帆。", "悶憶年支酒，閑裁古樣衫。", "釣家隨野舫，仙蘊逐雕函。", "度歲賒羸馬，先春買小𧍧。", "共疏泉入竹，同坐月過杉。", "染翰窮高致，懷賢發至諴。", "不堪潘子鬢，愁促易髟髟。"]'),
('cbfa56d2-f2b4-4363-854a-7affc2f17546','憶襲美洞庭觀步奉和次韻','陸龜蒙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','聞君遊靜境，雅具更摐摐。',122,'全唐诗/poet.tang.34000.json','["聞君遊靜境，雅具更摐摐。", "竹傘遮雲徑，藤鞋踏蘚矼。", "杖斑花不一，尊大癭成雙。", "水鳥行沙嶼，山僧禮石幢。", "已甘三秀味，誰念百牢腔。", "遠棹投何處，殘陽到幾窗。", "仙謠珠樹曲，村餉白醅[缸]。", "地里方吳會，人風似冉厖。", "探幽非遯世，尋勝肯迷邦。", "爲讀江南傳，何賢過二龐。"]'),
('8ba4b018-7ade-4c42-801f-4e76d93dec45','江墅言懷','陸龜蒙','唐','唐诗','tang','','[]','病身兼稚子，田舍劣相容。',120,'全唐诗/poet.tang.34000.json','["病身兼稚子，田舍劣相容。", "跡共公卿絕，貧須稼穡供。", "月方行到閏，霜始近言濃。", "樹少棲禽雜，村孤守犬重。", "汀洲藏晚弋，籬落露寒舂。", "野弁欹還整，家書拆又封。", "杉篁宜夕照，窗戶倚疎鐘。", "南北唯聞戰，縱橫未勝農。", "大春雖苦學，叔夜本多慵。", "直使貂裘弊，猶堪過一冬。"]'),
('2dada512-e466-44b1-bd68-509718e7a373','自和次前韻','陸龜蒙','唐','唐诗','tang','','[]','命既時相背，才非世所容。',120,'全唐诗/poet.tang.34000.json','["命既時相背，才非世所容。", "著書粮易絕，多病藥難供。", "夢爲懷山數，愁因戒酒濃。", "鳥媒呈不一，魚寨下仍重。", "晚桁蓑兼褐，晴簷織帶舂。", "著籤分水味，標石認田封。", "此地家三戶，何人祿萬鍾。", "草堂聊當貴，金穴任輕農。", "把釣竿初冷，題詩筆未慵。", "莫憂寒事晚，江上少嚴冬。"]'),
('71dcbf87-1934-4a67-a024-f6cceeaade7f','秋日遣懷十六韻寄道侶','陸龜蒙','唐','唐诗','tang','','[]','盡日臨風坐，雄詞妙略兼。',192,'全唐诗/poet.tang.34000.json','["盡日臨風坐，雄詞妙略兼。", "共知時世薄，寧恨歲華淹。", "且把靈方試，休憑吉夢占。", "夜然燒汞火，朝煉洗金鹽。", "有路求真隱，無媒舉孝廉。", "自然成嘯傲，不是學沈潛。", "水恨同心隔，霜愁兩鬢霑。", "鶴屏憐掩扇，烏帽愛垂簷。", "雅調宜觀樂，清才稱典籤。", "冠𢼮玄髪少，書健紫毫尖。", "故疾因秋召，塵容畏日黔。", "壯圖須行行，儒服謾襜襜。", "片石聊當枕，橫煙欲代簾。", "蠹根延穴蟻，疎葉漏庭蟾。", "藥鼎高低鑄，雲菴早晚苫。", "胡麻如重寄，從誚我無厭。"]'),
('49876ad5-0c71-4887-8e44-20d4e8d04abf','京口與友生話別','陸龜蒙','唐','唐诗','tang','','[]','共是悲秋客，相逢恨不堪。',288,'全唐诗/poet.tang.34000.json','["共是悲秋客，相逢恨不堪。", "鴈頻辭蘇北，人尚在江南。", "名利機初發，樵漁事先諳。", "松門穿戴寺，荷徑繞秦潭。", "繩檢真難束，疎慵却易耽。", "枕當高樹穩，茶試遠泉甘。", "架上經唯一，尊前雅祗三。", "風雲勞夢想，天地入醺酣。", "曆自堯階數，書因禹穴探。", "御龍雖世祿，下馬亦清譚。", "國計徒盈策，家儲不滿甔。", "斷簾從燕出，𢼮弁請人簪。", "木墜涼來葉，山橫霽後嵐。", "竹窗深䆗窱，苔洞綠龕弇。", "積行依顏子，和光則老聃。", "杖誠爲虎節，披信作鮫函。", "養鷺看窺沼，尋僧助結菴。", "功名思馬援，歌唱咽羊曇。", "乞食羞孤鳳，無衣羨八蠶。", "繫帆留宿客，吟句任羸驂。", "寵鶴空無衛，占烏未見𨝸。", "香還須是桂，青會出於藍。", "蜀酒時傾瓿，吳鰕徧發坩。", "玉封千挺藕，霜閉一筒柑。"]'),
('61935c96-3ada-4783-8f8e-7d4680ec635d','丹陽道中寄友生','陸龜蒙','唐','唐诗','tang','','[]','煙樹綠微微，春流浸竹扉。',96,'全唐诗/poet.tang.34000.json','["煙樹綠微微，春流浸竹扉。", "短蓑攜稚去，孤艇載魚歸。", "海俗蘆編室，村娃練束衣。", "舊栽奴橘老，新刈女桑肥。", "錦鯉衝風擲，絲禽掠浪飛。", "短亭幽徑入，陳廟數峰圍。", "地廢金牛暗，陵荒石獸稀。", "思君同一望，帆上怨餘暉。"]'),
('7243a9fc-9499-425b-abea-cef3c66d2ef3','寄茅山何道士','陸龜蒙','唐','唐诗','tang','','[]','終身持玉舃，丹訣未應傳。',120,'全唐诗/poet.tang.34000.json','["終身持玉舃，丹訣未應傳。", "況是曾同宿，相違便隔年。", "問顏知更少，聽話想踰玄。", "古籙文垂露，新金汞絕煙。", "蜂供和餌蜜，人寄買溪錢。", "紫燕長巢硐，青龜忽上蓮。", "篋藏徵隱詔，囊佩攝生篇。", "圃暖芝臺秀，巖春乳管圓。", "池栖子孫鶴，堂宿弟兄仙。", "幸閱靈書次，心期賜一編。"]'),
('e1d1f06d-7da3-40be-bb99-4006eeafad65','江南秋懷寄華陽山人','陸龜蒙','唐','唐诗','tang','','[]','櫛髪涼天曙，含毫故國情。',288,'全唐诗/poet.tang.34000.json','["櫛髪涼天曙，含毫故國情。", "歸心一夜極，病體九秋輕。", "忽起襜褕詠，因悲絡緯鳴。", "逢山即堪隱，何路可圖榮。", "揲策空占命，持竿不釣名。", "忘憂如有待，縱嬾似無營。", "小徑纔分草，斜扉劣辨荆。", "冷荷承露菂，疎菊臥煙莖。", "譜爲聽琴閱，圖緣看海㡠。", "鷺毛浮島白，魚尾撇波赬。", "庭橘低攀嗅，園葵旋折烹。", "餓烏窺食案，鬬鼠落書棚。", "種豆悲楊惲，投瓜憶衛旍。", "東林誰處士，南郭自先生。", "分野星多蹇，連山卦少亨。", "衣裾徒博大，文籍漫縱橫。", "蘭葉騷人佩，蓴絲內史羹。", "鶡冠難適越，羊酪未饒傖。", "倚嘯微抽恨，論玄好析酲。", "栖遲勞鼓篋，豪俠愛金籯。", "鍊藥傳丹鼎，嘗茶試石𪼿。", "沼連枯葦暗，窗對脫梧明。", "未達譏張翰，非才嫉禰衡。", "遠懷魂易黯，幽憤骨堪驚。"]'),
('64dc25b6-a75b-42a1-941d-73a802a27fa9','送宣武從事越中按獄','陸龜蒙','唐','唐诗','tang','','[]','曉看呈使範，知欲敕星軺。',96,'全唐诗/poet.tang.34000.json','["曉看呈使範，知欲敕星軺。", "水國難驅傳，山城便倚橈。", "秉籌先獨立，持法稱高標。", "旌斾臨危堞，金絲發麗譙。", "別愁當翠巘，冤望隔風潮。", "木落孤帆迥，江寒疊鼓飄。", "客鴻吳島盡，殘雪剡汀消。", "坐想休秦獄，春應到柳條。"]'),
('14a5755b-bbbc-4dea-8ada-dcd134bcdec9','江南冬至和人懷洛下','陸龜蒙','唐','唐诗','tang','','[]','昔居清洛涯，長恨苦寒遲。',72,'全唐诗/poet.tang.34000.json','["昔居清洛涯，長恨苦寒遲。", "自作江南客，稀遲下雪時。", "有煙棲菊梗，無凍落杉枝。", "背日能尋徑，臨風尚覆棋。", "鳥聲渾欲轉，草色固應知。", "與看平湖上，東流或片澌。"]'),
('271089d4-cd26-496f-b6b4-5399856ba610','謹和諫議罷郡敘懷六韻','陸龜蒙','唐','唐诗','tang','','[]','已報東吳政，初捐左契歸。',72,'全唐诗/poet.tang.34000.json','["已報東吳政，初捐左契歸。", "天應酬苦節，人不犯寒威。", "江上思重借，朝端望載飢。", "紫泥封夜詔，金殿賜春衣。", "對酒情何遠，裁詩思極微。", "待升鎔造日，江海問漁扉。"]'),
('fc244ab7-824f-4baa-9129-e02fd4dab206','二遺詩','陸龜蒙','唐','唐诗','tang','','[]','誰從毫末見參天，又到蒼蒼化石年。',64,'全唐诗/poet.tang.34000.json','["誰從毫末見參天，又到蒼蒼化石年。", "萬古清風吹作籟，一條寒溜滴成穿。", "閑追金帶徒勞恨，靜格朱絲更可憐。", "幸與野人俱散誕，不煩良匠更雕鐫。"]'),
('ad8e01e8-a224-46ad-b4a0-a498f110d84d','鵁鶄','陸龜蒙','唐','唐诗','tang','','[]','詞賦曾誇鸀鳿流，果爲名誤別滄洲。',64,'全唐诗/poet.tang.34000.json','["詞賦曾誇鸀鳿流，果爲名誤別滄洲。", "雖蒙靜置疎籠晚，不似閑栖折葦秋。", "自昔稻粱高鳥畏，至今珪組野人讐。", "防徽避繳無窮事，好與裁書謝白鷗。"]'),
('7e01fe7b-4c03-4c18-82a3-554192e91ab2','新秋月夕客有自遠相尋者作吳體二首以贈 一','陸龜蒙','唐','唐诗','tang','','[]','風初寥寥月乍滿，杉篁左右供餘清。',64,'全唐诗/poet.tang.34000.json','["風初寥寥月乍滿，杉篁左右供餘清。", "因君一話故山事，憶鶴互應深溪聲。", "雲門老森定未起，白閣道士遙相迎。", "日聞羽檄日夜急，掉臂欲歸巖下行。"]'),
('a89d8103-f76c-4ab0-b5fe-07fea12bb2d1','新秋月夕客有自遠相尋者作吳體二首以贈 二','陸龜蒙','唐','唐诗','tang','','[]','驚聞遠客訪良夜，扶病起坐綸巾欹。',64,'全唐诗/poet.tang.34000.json','["驚聞遠客訪良夜，扶病起坐綸巾欹。", "清談白紵思悄悄，玉繩銀漢光離離。", "三吳煙霧且如此，百越琛賮來何時。", "林端片月落未落，強慰別情言後期。"]'),
('68a1268e-057e-4b10-91fc-f9a779ee4af2','閑書','陸龜蒙','唐','唐诗','tang','','[]','病學高僧置一牀，披衣纔暇即焚香。',64,'全唐诗/poet.tang.34000.json','["病學高僧置一牀，披衣纔暇即焚香。", "閑階雨過苔花潤，小簟風來薤葉涼。", "南國羽書催部曲，東山毛褐傲羲皇。", "升平聞道無時節，試問中林亦不妨。"]'),
('28052148-ec29-4e56-b658-f9ccc40b7f80','獨夜','陸龜蒙','唐','唐诗','tang','','[]','新秋霽夜有清境，窮襜病容無佳期。',64,'全唐诗/poet.tang.34000.json','["新秋霽夜有清境，窮襜病容無佳期。", "生公把經向石說，而我對月須人爲。", "獨行獨坐亦獨酌，獨玩獨吟還獨悲。", "古稱獨坐與獨立，若比羣居終校奇。"]'),
('4c8be2e6-1f83-446e-ab36-af171471b70b','寄吳融','陸龜蒙','唐','唐诗','tang','','[]','一夜秋聲入井桐，數枝危綠怕西風。',64,'全唐诗/poet.tang.34000.json','["一夜秋聲入井桐，數枝危綠怕西風。", "霏霏晚砌煙華上，淅淅疎簾雨氣通。", "君整輸蹄名未了，我依琴鶴病相攻。", "到頭江畔從漁事，織作中流萬尺篊。"]'),
('0546f1e5-3920-4af5-820c-1473e6b70cc0','中秋待月','陸龜蒙','唐','唐诗','tang','','[]','轉缺霜輪上轉遲，好風偏似送佳期。',64,'全唐诗/poet.tang.34000.json','["轉缺霜輪上轉遲，好風偏似送佳期。", "簾斜樹隔情無限，燭暗香殘坐不辭。", "最愛笙調聞北里，漸看星澹失南箕。", "何人爲校清涼力，未似初圓欲午時。"]'),
('80c6900a-4be3-44cb-9a58-346a4c8fa498','重憶白菊','陸龜蒙','唐','唐诗','tang','','[]','我憐貞白重寒芳，前後叢生夾小堂。',64,'全唐诗/poet.tang.34000.json','["我憐貞白重寒芳，前後叢生夾小堂。", "月朵暮開無絕豔，風莖時動有奇香。", "何慙謝雪清才詠，不羨劉梅貴主妝。", "更憶幽窗凝一夢，夜來村落有微霜。"]'),
('862844aa-45ce-422e-b5c4-d7ac72d41014','別墅懷歸','陸龜蒙','唐','唐诗','tang','','[]','水國初冬和暖天，南榮方好背陽眠。',64,'全唐诗/poet.tang.34000.json','["水國初冬和暖天，南榮方好背陽眠。", "題詩朝憶復暮憶，見月上弦還下弦。", "遙爲晚花吟白菊，近炊香稻識紅蓮。", "何人授我黃金百，買取蘇君負郭田。"]'),
('de2a431d-c0e3-43c6-85ea-ec86a9cab574','寄淮南鄭寶書記','陸龜蒙','唐','唐诗','tang','','[]','記室千年翰墨孤，唯君才學似應徐。',64,'全唐诗/poet.tang.34000.json','["記室千年翰墨孤，唯君才學似應徐。", "五丁驅得神功盡，二酉搜來祕檢疎。", "煬帝帆檣留澤國，淮王牋奏入班書。", "清詞醉草無因見，但釣寒江半尺鱸。"]'),
('f4468968-5cdd-4373-88d8-9e077cb5413d','小雪後書事','陸龜蒙','唐','唐诗','tang','','[]','時候頻過小雪天，江南寒色未曾偏。',64,'全唐诗/poet.tang.34000.json','["時候頻過小雪天，江南寒色未曾偏。", "楓汀尚憶逢人別，麥隴唯應欠雉眠。", "更擬結茅臨水次，偶因行藥到村前。", "鄰翁意緒相安慰，多說明年是稔年。"]'),
('aa1c76e0-9240-44d6-974f-40f99b316461','寒夜同襲美訪北禪院寂上人','陸龜蒙','唐','唐诗','tang','','[]','月樓風殿靜沈沈，披拂霜華訪道林。',64,'全唐诗/poet.tang.34000.json','["月樓風殿靜沈沈，披拂霜華訪道林。", "鳥在寒枝棲影動，人依古堞坐禪深。", "明時尚阻青雲步，半夜猶追白石吟。", "自是海邊鷗伴侶，不勞金偈更降心。"]'),
('fb2a184c-ed68-4f7e-a95b-baa4713d2709','和襲美江南道中懷茅山廣文南陽博士三首次韻 一','陸龜蒙','唐','唐诗','tang','','[]','一片輕帆背夕陽，望三峰拜七真堂。',64,'全唐诗/poet.tang.34000.json','["一片輕帆背夕陽，望三峰拜七真堂。", "天寒夜漱雲牙淨，雪壞晴梳石髪香。", "自拂煙霞安筆格，獨開封檢試砂牀。", "莫言洞府能招隱，會輾飆輪見玉皇。"]'),
('82ae7f24-5ebc-4659-81ee-8d1148225c18','和襲美江南道中懷茅山廣文南陽博士三首次韻 二','陸龜蒙','唐','唐诗','tang','','[]','壺中行坐可攜天，何況林間息萬緣。',64,'全唐诗/poet.tang.34000.json','["壺中行坐可攜天，何況林間息萬緣。", "組綬任垂三品石，佩環從落四公泉。", "丹臺已運陰陽火，碧簡須雕次第仙。", "想得雷平春色動，五芝煙甲又芊眠。"]'),
('59edd019-e5bc-49de-8087-565a66615751','和襲美江南道中懷茅山廣文南陽博士三首次韻 三','陸龜蒙','唐','唐诗','tang','','[]','良常應不動移文，金醴從酸亦自醺。',64,'全唐诗/poet.tang.34000.json','["良常應不動移文，金醴從酸亦自醺。", "桂父舊歌飛絳雪，桐孫新韻倚玄雲。", "春臨柳谷鶯先覺，曙醮蕪香鶴共聞。", "珍重雙雙玉條脫，盡憑三島寄羊君。"]'),
('67acc701-5804-4954-a387-7e3446e411ef','早春雪中作吳體寄襲美','陸龜蒙','唐','唐诗','tang','','[]','迎春避臘不肯下，欺花凍草還飄然。',64,'全唐诗/poet.tang.34000.json','["迎春避臘不肯下，欺花凍草還飄然。", "光填馬窟蓋塞外，勢壓鶴巢偏殿巔。", "山爐癭節萬狀火，墨突乾衰孤穗煙。", "君披鶴氅獨自立，何人解道真神仙。"]'),
('0864724d-33dd-4764-ba28-3e666e408866','奉和襲美吳中言情見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','菰煙蘆雪是儂鄉，釣線隨身好坐忘。',64,'全唐诗/poet.tang.34000.json','["菰煙蘆雪是儂鄉，釣線隨身好坐忘。", "徒愛右軍遺點畫，閑披左氏得膏盲。", "無因月殿聞移屧，秖有風汀去採香。", "莫問江邊漁艇子，玉皇看賜羽衣裳。"]'),
('51066268-58a2-4769-aa2e-2f08e004b514','和襲美揚州看辛夷花次韻','陸龜蒙','唐','唐诗','tang','','[]','柳疎梅墮少春叢，天遣花神別致功。',64,'全唐诗/poet.tang.34000.json','["柳疎梅墮少春叢，天遣花神別致功。", "高處朵稀難避日，動時枝弱易爲風。", "堪將亂蘂添雲肆，若得千株便雪宮。", "不待羣芳應有意，等閑桃杏即爭紅。"]'),
('00f9a560-1be4-474b-adc9-4fcf6b73b3be','奉和襲美行次野梅次韻','陸龜蒙','唐','唐诗','tang','','[]','飛櫂參差拂早梅，強欺寒色尚低徊。',64,'全唐诗/poet.tang.34000.json','["飛櫂參差拂早梅，強欺寒色尚低徊。", "風憐薄媚留香與，月會深情借豔開。", "梁殿得非蕭帝瑞，齊宮應是玉兒媒。", "不知謝客離腸醒，臨水應添萬恨來。"]'),
('ca94aa16-25bf-4656-8ceb-add843482a4c','奉和襲美暇日獨處見寄','陸龜蒙','唐','唐诗','tang','','[]','謝府殷樓少暇時，又拋清宴入書帷。',64,'全唐诗/poet.tang.34000.json','["謝府殷樓少暇時，又拋清宴入書帷。", "三千餘歲上下古，八十一家文字奇。", "冷夢漢臯懷鹿隱，靜憐煙島覺鴻離。", "知君滿篋前朝事，鳳諾龍奴借與窺。"]'),
('0979fa35-44e8-4a9b-87a1-53c54a7623dc','奉和襲美見訪不遇','陸龜蒙','唐','唐诗','tang','','[]','爲愁煙岸老塵囂，扶病呼兒斸翠苕。',64,'全唐诗/poet.tang.34000.json','["爲愁煙岸老塵囂，扶病呼兒斸翠苕。", "秖道府中持簡牘，不知林下訪漁樵。", "花盤小墢晴初壓，葉擁疎籬凍未燒。", "倚杖徧吟春照午，一池冰段幾多消。"]'),
('0456f0b8-354c-4f3e-8994-67f6b476cd21','酬襲美見寄海蟹','陸龜蒙','唐','唐诗','tang','','[]','藥杯應阻蟹螯香，却乞江邊採捕郎。',64,'全唐诗/poet.tang.34000.json','["藥杯應阻蟹螯香，却乞江邊採捕郎。", "自是揚雄知郭索，且非何胤敢餦餭。", "骨清猶似含春靄，沫白還疑帶海霜。", "強作南朝風雅客，夜來偷醉早梅傍。"]'),
('250efd4e-1ed3-437b-b7c0-eef9b606a21c','奉和襲美開元寺客省早景即事次韻','陸龜蒙','唐','唐诗','tang','','[]','日上罘罳疊影紅，一聲清梵萬緣空。',64,'全唐诗/poet.tang.34000.json','["日上罘罳疊影紅，一聲清梵萬緣空。", "䙰褷滿地貝多雪，料峭入樓于闐風。", "水榭初抽寥泬思，竹窗猶挂夢魂中。", "靈香散盡禪家接，誰共殷源小品同。"]'),
('1766d7ae-8530-425d-b958-9a0dbcb58c31','獨夜有懷因作吳體寄襲美','陸龜蒙','唐','唐诗','tang','','[]','人吟側景抱凍竹，鶴夢缺月沈枯梧。',64,'全唐诗/poet.tang.34000.json','["人吟側景抱凍竹，鶴夢缺月沈枯梧。", "清澗無波鹿無魄，白雲有根虬有鬚。", "雲虬澗鹿真逸調，刀名錐利非良圖。", "不然快作燕市飲，笑撫肉枅眠酒壚。"]'),
('c6f10e7d-dcb5-40b3-b1c3-a296b9e53600','闔閭城北有賣花翁討春之士往往造焉因招襲美','陸龜蒙','唐','唐诗','tang','','[]','故城邊有賣花翁，水曲舟輕去盡通。',64,'全唐诗/poet.tang.34000.json','["故城邊有賣花翁，水曲舟輕去盡通。", "十畝芳菲爲舊業，一家煙雨是元功。", "閑添藥品年年別，笑指生涯樹樹紅。", "若要見春歸處所，不過攜手問東風。"]'),
('2537eacf-f276-4ee2-a05a-a28c1ea2da07','奉和襲美病中庭際海石榴花盛發見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','紫府真人餉露囊，猗蘭燈燭未熒煌。',64,'全唐诗/poet.tang.34000.json','["紫府真人餉露囊，猗蘭燈燭未熒煌。", "丹華乞曙先侵日，金焰欺寒却照霜。", "誰與佳名從海曲，秖應芳裔出河陽。", "那堪謝氏庭前見，一段清香染郄郎。"]'),
('a65cecff-9bb6-4565-b5e8-76e10af7c359','襲美以春橘見惠兼之雅篇因次韻酬謝','陸龜蒙','唐','唐诗','tang','','[]','到春猶作九秋鮮，應是親封白帝煙。',64,'全唐诗/poet.tang.34000.json','["到春猶作九秋鮮，應是親封白帝煙。", "良玉有漿須讓味，明珠無纇亦羞圓。", "堪居漢苑霜梨上，合在仙家火棗前。", "珍重更過三十子，不堪分付野人邊。"]'),
('0e945645-bde4-40ef-9408-94f5540fd002','奉和襲美病中書情寄上崔諫議次韻','陸龜蒙','唐','唐诗','tang','','[]','或偃虛齋或在公，藹然林下昔賢風。',64,'全唐诗/poet.tang.34000.json','["或偃虛齋或在公，藹然林下昔賢風。", "庭前有蜨爭煙蘂，簾外無人報水筒。", "行藥不離深幌底，寄書多向遠山中。", "西園夜燭偏堪憶，曾爲題詩刻半紅。"]'),
('8a029f2b-8cf8-4020-a34f-d269a55f1f78','奉酬襲美病中見寄','陸龜蒙','唐','唐诗','tang','','[]','逢花逢月便相招，忽臥雲航隔野橋。',64,'全唐诗/poet.tang.34000.json','["逢花逢月便相招，忽臥雲航隔野橋。", "春恨與誰同酩酊，玄言何處問逍遙？", "題詩石上空迴筆，拾蕙汀邊獨倚橈。", "早晚却還巖下電，共尋芳徑結煙條。"]'),
('f4dff51a-63a5-4692-9d43-e594a6b23cc1','奉和襲美病孔雀','陸龜蒙','唐','唐诗','tang','','[]','嬾移金翠傍簷楹，斜倚芳叢舊態生。',64,'全唐诗/poet.tang.34000.json','["嬾移金翠傍簷楹，斜倚芳叢舊態生。", "唯奈瘴煙籠飲啄，可堪春雨滯飛鳴。", "鴛鴦水畔迴頭羨，荳蔻圖前舉眼驚。", "爭得鷓鴣來伴著，不妨還校有心情。"]'),
('26fbc610-4881-47dd-89be-cdb571e8367c','上元日道室焚修寄襲美','陸龜蒙','唐','唐诗','tang','','[]','三清今日聚靈官，玉刺齊抽謁廣寒。',64,'全唐诗/poet.tang.34000.json','["三清今日聚靈官，玉刺齊抽謁廣寒。", "執蓋冒花香寂歷，侍晨交佩響闌珊。", "將排鳳節分階易，欲校龍書下筆難。", "唯有世塵中小兆，夜來心拜七星壇。"]'),
('5f5cce92-e418-490b-b2c9-466d980e70f4','正月十五惜春寄襲美','陸龜蒙','唐','唐诗','tang','','[]','六分春色一分休，滿眼東波盡是愁。',64,'全唐诗/poet.tang.34000.json','["六分春色一分休，滿眼東波盡是愁。", "花匠凝寒應束手，酒龍多病尚垂頭。", "無窮嬾惰齊中散，有底機謀敵右侯。", "見織短篷裁小檝，拿煙閑弄箇漁舟。"]'),
('6d574758-645d-4e24-b3ab-06e3d6bccde1','襲美病中聞余遊顔家園見寄次韻酬之','陸龜蒙','唐','唐诗','tang','','[]','日華風蕙正交光，羯末相攜籍草塘。',64,'全唐诗/poet.tang.34000.json','["日華風蕙正交光，羯末相攜籍草塘。", "佳酒旋傾醽醁嫩，短船閑弄木蘭香。", "煙絲鳥拂來縈帶，蘂榼人收去約簧。", "今日好爲聯句會，不成剛爲欠檀郎。"]'),
('f1d44780-ce15-4c43-94bb-7ce74b759772','春雨即事寄襲美','陸龜蒙','唐','唐诗','tang','','[]','小謝輕埃日日飛，城邊江上阻春暉。',64,'全唐诗/poet.tang.34000.json','["小謝輕埃日日飛，城邊江上阻春暉。", "雖愁野岸花房凍，還得山家藥笋肥。", "雙屐著頻看齒折，敗裘披苦見毛稀。", "比鄰釣叟無塵事，灑笠鳴蓑夜半歸。"]'),
('89af9c4e-06b6-46a9-b994-023dd2679032','奉和襲美抱疾杜門見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','雖失春城醉上期，下帷裁徧未裁詩。',66,'全唐诗/poet.tang.34000.json','["雖失春城醉上期，下帷裁徧未裁詩。", "因吟郢岸百畝蕙，[欲]采商崖三秀枝。", "棲野鶴籠寬使織，施山僧飯別教炊。", "但醫沈約重瞳健，不怕江花不滿枝。"]'),
('d64f41f9-6b33-4410-b13c-04787501b254','偶掇野蔬寄襲美有作','陸龜蒙','唐','唐诗','tang','','[]','野園煙裏自幽尋，嫩甲香蕤引漸深。',64,'全唐诗/poet.tang.34000.json','["野園煙裏自幽尋，嫩甲香蕤引漸深。", "行歇每依鵶舅影，挑頻時見鼠姑心。", "凌風藹彩初攜籠，帶露虛疎或貯襟。", "欲助春盤還愛否，不妨蕭灑似家林。"]'),
('58a22096-2cae-486f-b7ec-c529f4165ff1','奉和襲美臥疾感春見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','共尋花思極飛騰，病帶春寒去未能。',64,'全唐诗/poet.tang.34000.json','["共尋花思極飛騰，病帶春寒去未能。", "煙徑水涯多好鳥，竹牀蒲椅但高僧。", "須知日富爲神授，秖有家貧免盜憎。", "除却數函圖籍外，更將何事結良朋。"]'),
('b97979fd-9237-4e6c-bf1e-6a940bf1f257','徐方平後聞赦因寄襲美','陸龜蒙','唐','唐诗','tang','','[]','新春旒扆御翬軒，海內初傳渙汗恩。',64,'全唐诗/poet.tang.34000.json','["新春旒扆御翬軒，海內初傳渙汗恩。", "秦獄已收爲厲氣，瘴江初返未招魂。", "英材盡作龍蛇蟄，戰地多成虎豹村。", "除却數般傷痛外，不知何事及王孫。"]'),
('3cb9bfd0-9781-4aa6-801d-a1c78f836be6','襲美以魚牋見寄因謝成篇','陸龜蒙','唐','唐诗','tang','','[]','擣成霜粒細鱗鱗，知作愁吟喜見分。',64,'全唐诗/poet.tang.34000.json','["擣成霜粒細鱗鱗，知作愁吟喜見分。", "向日乍驚新繭色，臨風時辨白萍文。", "好將花下承金粉，堪送天邊詠碧雲。", "見倚小窗親襞染，盡圖春色寄夫君。"]'),
('22b99aff-2d9e-4582-bc3a-e5148063df26','次和襲美病後春思','陸龜蒙','唐','唐诗','tang','','[]','氣和靈府漸氤氳，酒有賢人藥有君。',64,'全唐诗/poet.tang.34000.json','["氣和靈府漸氤氳，酒有賢人藥有君。", "七字篇章看月得，百勞言語傍花聞。", "閑尋古寺消晴日，最憶深溪枕夜雲。", "早晚共搖孤艇去，紫屏風外碧波文。"]'),
('6a96fa86-d57a-4917-9e79-202ffc475ed6','襲美以公齋小宴見招因代書寄之','陸龜蒙','唐','唐诗','tang','','[]','早雲纔破漏春陽，野客晨興喜又忙。',64,'全唐诗/poet.tang.34000.json','["早雲纔破漏春陽，野客晨興喜又忙。", "自與酌量煎藥水，別教安置曬書牀。", "依方釀酒愁遲去，借樣裁巾怕索將。", "唯待數般幽事了，不妨還入少年場。"]'),
('b98d39d0-afcf-43e7-9cb4-0a81f61d7af2','京口','陸龜蒙','唐','唐诗','tang','','[]','江干古渡傷離情，斷山零落春潮平。',64,'全唐诗/poet.tang.34000.json','["江干古渡傷離情，斷山零落春潮平。", "東風料峭客帆遠，落葉夕陽天際明。", "戰舸昔浮千騎去，釣舟今載一翁輕。", "可憐宋帝籌帷處，蒼翠無煙草自生。"]'),
('0b32a1de-0f10-4b71-b1ec-138aa2a73298','潤州送人往長洲','陸龜蒙','唐','唐诗','tang','','[]','秋來頻上向吳亭，每上思歸意剩生。',64,'全唐诗/poet.tang.34000.json','["秋來頻上向吳亭，每上思歸意剩生。", "廢苑池臺煙裏色，夜村蓑笠雨中聲。", "汀洲月下菱船疾，楊柳風高酒斾輕。", "君住松江多少日，爲嘗鱸鱠與蓴羹。"]'),
('58056a54-5131-4dd3-ae83-7118e61e2d03','潤州江口送人謁池陽衛郎中','陸龜蒙','唐','唐诗','tang','','[]','山翁曾約舊交歡，須拂侯門側注冠。',64,'全唐诗/poet.tang.34000.json','["山翁曾約舊交歡，須拂侯門側注冠。", "月在石頭搖戍角，風生江口亞帆竿。", "閑隨野醉溪聲鬧，獨伴清譚曉色殘。", "待取新秋歸更好，九華蒼翠入樓寒。"]'),
('ebd9bc45-84a2-4167-a665-40fcad0d7485','襲美以紗巾見惠繼以雅音因次韻酬謝','陸龜蒙','唐','唐诗','tang','','[]','薄如蟬翅背斜陽，不稱春前贈𦊔郎。',64,'全唐诗/poet.tang.34000.json','["薄如蟬翅背斜陽，不稱春前贈𦊔郎。", "初覺頂寒生遠吹，預憂頭白透新霜。", "堪窺水檻澄波影，好拂花牆亞蘂香。", "知有芙蓉留自戴，欲峨煙霧訪黃房。"]'),
('dda9b159-4187-4385-acb2-4f63245ebc9f','聞襲美有親迎之期因以寄賀','陸龜蒙','唐','唐诗','tang','','[]','梁鴻夫婦欲雙飛，細雨輕寒拂雉衣。',64,'全唐诗/poet.tang.34000.json','["梁鴻夫婦欲雙飛，細雨輕寒拂雉衣。", "初下雪窗因眷戀，次乘煙幰奈光輝。", "參差扇影分華月，斷續簫聲落翠微。", "見說春風偏有賀，露花千朵照庭闈。"]'),
('f44dde40-6356-4514-a255-3d7581decbcb','襲美以巨魚之半見分因以酬謝','陸龜蒙','唐','唐诗','tang','','[]','誰與春江上信魚，可憐霜刃截來初。',64,'全唐诗/poet.tang.34000.json','["誰與春江上信魚，可憐霜刃截來初。", "鱗隳似撤騷人屋，腹斷疑傷遠客書。", "避網幾跳山影破，逆風曾蹙浪花虛。", "今朝最是家童喜，免泥荒畦掇野蔬。"]'),
('114b29ba-8b1e-4587-ba03-64819859287a','奉和襲美館娃宮懷古次韻','陸龜蒙','唐','唐诗','tang','','[]','鏤楣消落濯春雨，蒼翠無言空斷崖。',64,'全唐诗/poet.tang.34000.json','["鏤楣消落濯春雨，蒼翠無言空斷崖。", "草碧未能忘帝女，燕輕猶自識宮釵。", "江山祗有愁容在，劒珮應和媿色埋。", "賴在伍員騷思少，吳王纔免似荆懷。"]'),
('2c54974c-54da-4ea6-b174-78096c428731','同襲美遊北禪院','陸龜蒙','唐','唐诗','tang','','[]','連延花蔓映風廊，岸幘披襟到竹房。',64,'全唐诗/poet.tang.34000.json','["連延花蔓映風廊，岸幘披襟到竹房。", "居士祗今開梵處，先生曾是草玄堂。", "清尊林下看香印，遠岫窗中挂鉢囊。", "今日有情消未得，欲將名理問思光。"]'),
('dc899377-1490-41cc-b08f-d94a25741e38','襲美以紫石硯見贈以詩迎之','陸龜蒙','唐','唐诗','tang','','[]','霞骨堅來玉自愁，琢成飛燕古釵頭。',64,'全唐诗/poet.tang.34000.json','["霞骨堅來玉自愁，琢成飛燕古釵頭。", "澄沙脆弱聞應伏，青鐵沈埋見亦羞。", "最稱風亭批碧簡，好將雲竇漬寒流。", "君能把贈閑吟客，徧寫江南物象酬。"]'),
('273cf284-b442-4d39-857f-7f924f97a400','和襲美送孫發百篇遊天台','陸龜蒙','唐','唐诗','tang','','[]','直應天授與詩情，百詠唯消一日成。',64,'全唐诗/poet.tang.34000.json','["直應天授與詩情，百詠唯消一日成。", "去把彩毫揮下國，歸參黃綬別春卿。", "閑窺碧落懷煙霧，暫向金庭隱姓名。", "珍重興公徒有賦，石梁深處是君行。"]'),
('81a71528-61bb-4d30-a217-d8391c8ea5a7','奉和襲美聞開元寺開笋園寄章上人','陸龜蒙','唐','唐诗','tang','','[]','春龍爭地養檀欒，況是雙林雨後看。',64,'全唐诗/poet.tang.34000.json','["春龍爭地養檀欒，況是雙林雨後看。", "迸出似毫當垤㙞，孤生如恨倚欄干。", "凌虛勢欲齊金剎，折贈光宜照玉盤。", "更得錦苞零落後，粉環高下挶煙寒。"]'),
('e8df93b7-aafe-4e1b-aff5-86df9aca638d','薔薇','陸龜蒙','唐','唐诗','tang','','[]','倚牆當戶自橫陳，致得貧家似不貧。',64,'全唐诗/poet.tang.34000.json','["倚牆當戶自橫陳，致得貧家似不貧。", "外布芳菲雖笑日，中含芒刺欲傷人。", "清香往往生遙吹，狂蔓看看及四鄰。", "遇有客來堪玩處，一端晴綺照煙新。"]'),
('460538a8-d323-4756-b234-6d3a60c757bf','奉和襲美開元寺佛鉢詩','陸龜蒙','唐','唐诗','tang','','[]','空王初受逞神功，四鉢須臾現一重。',64,'全唐诗/poet.tang.34000.json','["空王初受逞神功，四鉢須臾現一重。", "持次想添香積飯，覆時應帶步羅鍾。", "光寒好照金毛鹿，響靜堪降白耳龍。", "從此寶函香裏見，不須西去詣靈峰。"]'),
('490d406d-f62d-4b7f-84ef-2c1a512197c7','酬襲美夏首病愈見招次韻','陸龜蒙','唐','唐诗','tang','','[]','雨多青合是垣衣，一幅蠻牋夜欵扉。',64,'全唐诗/poet.tang.34000.json','["雨多青合是垣衣，一幅蠻牋夜欵扉。", "蕙帶又聞寬沈約，茅齋猶自憶王微。", "方靈祗在君臣正，篆古須拋點畫肥。", "除却伴談秋水外，野鷗何處更忘機。"]'),
('409fb7ba-c1ad-4581-b878-cfdfd1965bec','新夏東郊閑泛有懷襲美','陸龜蒙','唐','唐诗','tang','','[]','遲於春日好於秋，野客相攜上釣舟。',64,'全唐诗/poet.tang.34000.json','["遲於春日好於秋，野客相攜上釣舟。", "經略彴時冠暫亞，佩笭箵後帶頻搊。", "蒹葭鷺起波搖笠，村落蠶眠樹挂鉤。", "料得祗君能愛此，不爭煙水似封侯。"]'),
('6916b646-92a0-42d4-8712-e8cd8c0b0d24','四月十五日道室書事寄襲美','陸龜蒙','唐','唐诗','tang','','[]','烏飯新炊芼臛香，道家齋日以爲常。',64,'全唐诗/poet.tang.34000.json','["烏飯新炊芼臛香，道家齋日以爲常。", "月苗杯舉存三洞，雲蘂函開叩九章。", "一掬陽泉堪作雨，數銖秋石欲成霜。", "可中值著雷平信，爲覓閑眠苦竹牀。"]'),
('7236fa13-09b5-41ca-89b3-502cd7626eaa','看壓新醅寄懷襲美','陸龜蒙','唐','唐诗','tang','','[]','曉壓糟牀漸有聲，旋如[荒]澗野泉清。',66,'全唐诗/poet.tang.34000.json','["曉壓糟牀漸有聲，旋如[荒]澗野泉清。", "身前古態燻應出，世上愁痕滴合平。", "飲啄斷年同鶴儉，風波終日看人爭。", "尊中若使常能淥，兩綬通侯總強名。"]'),
('f92d70db-4d9d-4f0e-9824-8d192e127ad5','奉和襲美登初陽樓寄懷北平郎中','陸龜蒙','唐','唐诗','tang','','[]','遠窗浮檻亦成年，幾伴楊公白晝筵。',64,'全唐诗/poet.tang.34000.json','["遠窗浮檻亦成年，幾伴楊公白晝筵。", "日暖煙花曾撲地，氣浮星象却歸天。", "閑將水石侵軍壘，醉引笙歌上釣船。", "無限恩波猶在目，東風吹起細漪漣。"]'),
('2840c59e-8415-40d2-b26b-427e3426aa03','奉和夏初襲美見訪題小齋次韻','陸龜蒙','唐','唐诗','tang','','[]','四鄰多是老農家，百樹雞桑半頃麻。',66,'全唐诗/poet.tang.34000.json','["四鄰多是老農家，百樹雞桑半頃麻。", "盡趁[晴]明修網架，每和煙雨掉繰車。", "啼鸞偶坐身藏葉，餉婦歸來鬢有花。", "不是對君吟復醉，更將何事送年華。"]'),
('3ec8b32f-f9e5-413b-b7fd-f6fa7b180847','奉和襲美所居首夏水木尤清適然有作次韻','陸龜蒙','唐','唐诗','tang','','[]','柿陰成列藥花空，却憶桐江下釣筒。',64,'全唐诗/poet.tang.34000.json','["柿陰成列藥花空，却憶桐江下釣筒。", "亦以魚蝦供熟鷺，近緣櫻笋識鄰翁。", "閑分酒劑多還少，自記書籤白間紅。", "更愛夜來風月好，轉思玄度對支公。"]'),
('5508557f-6b9d-4e70-b2d5-7b03223f97f4','奉和襲美題達上人藥圃二首 一','陸龜蒙','唐','唐诗','tang','','[]','藥味多從遠客齎，旋添花圃旋成畦。',64,'全唐诗/poet.tang.34000.json','["藥味多從遠客齎，旋添花圃旋成畦。", "三椏舊種根應異，九節初移葉尚低。", "山莢便和幽澗石，水芝須帶本池泥。", "從今直到清秋日，又有香苗幾番齊。"]'),
('25f52ca4-1e94-48ee-b8f8-d0a7c07e1e56','奉和襲美題達上人藥圃二首 二','陸龜蒙','唐','唐诗','tang','','[]','淨名無語示清羸，藥草搜來喻更微。',64,'全唐诗/poet.tang.34000.json','["淨名無語示清羸，藥草搜來喻更微。", "一雨一風皆遂性，花開花落盡忘機。", "教疏兔鏤金弦亂，自擁龍芻紫汞肥。", "莫怪獨親幽圃坐，病容銷盡欲依歸。"]'),
('5f3dd2a8-e691-4a27-a8fb-2a7fb3273611','奉和襲美懷華陽潤卿博士三首 一','陸龜蒙','唐','唐诗','tang','','[]','幾降真官授隱書，洛公曾到夢中無。',64,'全唐诗/poet.tang.34000.json','["幾降真官授隱書，洛公曾到夢中無。", "眉間入靜三辰影，肘後通靈五嶽圖。", "北洞樹形如曲蓋，東凹山色入薰爐。", "金墟福地能容否，願作岡前蔣負芻。"]'),
('1923ae1e-9c18-4c18-9135-de2b8fff9473','奉和襲美懷華陽潤卿博士三首 二','陸龜蒙','唐','唐诗','tang','','[]','火景應難到洞宮，蕭閑堂冷任天風。',64,'全唐诗/poet.tang.34000.json','["火景應難到洞宮，蕭閑堂冷任天風。", "談玄麈尾拋雲底，服散龍胎在酒中。", "有路還將赤城接，無泉不共紫河通。", "奇編早晚教傳授，免以神仙問葛洪。"]'),
('be74ec29-dcd6-4cb7-b7e7-626c7cbfa76b','奉和襲美懷華陽潤卿博士三首 三','陸龜蒙','唐','唐诗','tang','','[]','終日焚香禮洞雲，更思琪樹轉勞神。',64,'全唐诗/poet.tang.34000.json','["終日焚香禮洞雲，更思琪樹轉勞神。", "曾尋下泊常經月，不到中峰又累春。", "仙道最高黃玉籙，暑天偏稱白綸巾。", "清齋若見茅司命，乞取朱兒十二斤。"]'),
('0b40a3be-3820-484a-912d-c32789e5ecaf','以竹夾膝寄贈襲美','陸龜蒙','唐','唐诗','tang','','[]','截得篔簹冷似龍，翠光橫在暑天中。',64,'全唐诗/poet.tang.34000.json','["截得篔簹冷似龍，翠光橫在暑天中。", "堪臨薤簟閑憑月，好向松窗臥跂風。", "持贈敢齊青玉案，醉吟偏稱碧荷筒。", "添君雅具教多著，爲著西齋譜一通。"]'),
('d1e4c795-695c-457f-ab5e-b2b0e4f9ff83','奉和襲美夏景無事因懷章來二上人次韻 一','陸龜蒙','唐','唐诗','tang','','[]','簷外青陽有二梅，折來堪下凍醪杯。',64,'全唐诗/poet.tang.34000.json','["簷外青陽有二梅，折來堪下凍醪杯。", "高杉自欲生龍腦，小弁誰能寄鹿胎。", "麗事肯教饒沈謝，談微何必減宗雷。", "還聞擬結東林社，爭奈淵明醉不來。"]'),
('38e20449-dd3f-4148-ab13-f118b4a9253b','奉和襲美夏景無事因懷章來二上人次韻 二','陸龜蒙','唐','唐诗','tang','','[]','忽憶高僧坐夏堂，厭泉聲鬧笑雲忙。',64,'全唐诗/poet.tang.34000.json','["忽憶高僧坐夏堂，厭泉聲鬧笑雲忙。", "山重海澹懷中印，月冷風微宿上方。", "病後書求嵩少藥，定迴衣染貝多香。", "何時更問逍遙義，五粒松陰半石牀。"]'),
('019adac1-985d-4e12-8db7-3e961982b4fa','頃自桐江得一釣車以襲美樂煙波之思因出以爲玩俄辱三篇復抒酬荅 一','陸龜蒙','唐','唐诗','tang','','[]','旋屈金鉤劈翠筠，手中盤作釣魚輪。',64,'全唐诗/poet.tang.34000.json','["旋屈金鉤劈翠筠，手中盤作釣魚輪。", "忘情不效孤醒客，有意閑窺百丈鱗。", "雨似輕埃時一起，雲如高蓋強相親。", "任他華轂低頭笑，此地終無覆敗人。"]'),
('ef56ddd4-d6c1-4ca9-ba42-327d4a8337ec','頃自桐江得一釣車以襲美樂煙波之思因出以爲玩俄辱三篇復抒酬荅 二','陸龜蒙','唐','唐诗','tang','','[]','曾招漁侶下清潯，獨繭初隨一錘深。',64,'全唐诗/poet.tang.34000.json','["曾招漁侶下清潯，獨繭初隨一錘深。", "細輾煙華無轍跡，靜含風力有車音。", "相呼野飯依芳草，迭和山歌逗遠林。", "得失任渠但取樂，不曾生箇是非心。"]'),
('134a317c-5a66-4c9c-bdbe-818b82432e64','頃自桐江得一釣車以襲美樂煙波之思因出以爲玩俄辱三篇復抒酬荅 三','陸龜蒙','唐','唐诗','tang','','[]','病來縣著脆緡絲，獨喜高情爲我持。',64,'全唐诗/poet.tang.34000.json','["病來縣著脆緡絲，獨喜高情爲我持。", "數幅尚凝煙雨態，三篇能賦蕙蘭詞。", "雲深石靜閑眠穩，月上江平放溜遲。", "第一莫教諳此境，倚天功業待君爲。"]'),
('a754f086-31f5-4c2a-a29e-75fb070935eb','奉和襲美吳中書事寄漢南裴尚書','陸龜蒙','唐','唐诗','tang','','[]','風清地古帶前朝，遺事紛紛未寂寥。',64,'全唐诗/poet.tang.34000.json','["風清地古帶前朝，遺事紛紛未寂寥。", "三泖涼波魚蕝動，五茸春草雉媒嬌。", "雲藏野寺分金剎，月在江樓倚玉簫。", "不用懷歸忘此景，吳王看即奉弓招。"]'),
('fd5ad378-7699-4492-b45a-96110cbafc10','奉和襲美夏景沖澹偶作次韻二首 一','陸龜蒙','唐','唐诗','tang','','[]','蟬雀參差在扇紗，竹襟輕利籜冠斜。',64,'全唐诗/poet.tang.34000.json','["蟬雀參差在扇紗，竹襟輕利籜冠斜。", "壚中有酒文園會，琴上無弦靖節家。", "芝畹煙霞全覆穗，橘洲風浪半浮花。", "閑思兩地忘名者，不信人間髪解華。"]'),
('ad55be93-e9dc-4ee8-a0f5-6896930cd892','奉和襲美夏景沖澹偶作次韻二首 二','陸龜蒙','唐','唐诗','tang','','[]','祗於池曲象山幽，便是瀟湘浸石樓。',64,'全唐诗/poet.tang.34000.json','["祗於池曲象山幽，便是瀟湘浸石樓。", "斜拂芡盤輕鶩下，細穿菱線小鯢遊。", "閑開茗焙嘗須徧，醉撥書帷臥始休。", "莫道仙家無好爵，方諸還拜碧琳侯。"]'),
('df43f52e-52ec-4c57-b642-55fc87bd68dc','奉和襲美送李明府之任南海','陸龜蒙','唐','唐诗','tang','','[]','春盡之官直到秋，嶺雲深處凭瀧樓。',64,'全唐诗/poet.tang.34000.json','["春盡之官直到秋，嶺雲深處凭瀧樓。", "居人愛近沈珠浦，候吏多來拾翠洲。", "賨稅盡應輸紫貝，蠻童多學佩金鉤。", "知君不戀南枝久，拋却經冬白罽裘。"]'),
('ed543462-e9fc-469f-90b3-be517207972c','奉和襲美寄題羅浮軒轅先生所居','陸龜蒙','唐','唐诗','tang','','[]','鼎成仙馭入崆峒，百世猶傳至道風。',64,'全唐诗/poet.tang.34000.json','["鼎成仙馭入崆峒，百世猶傳至道風。", "暫應青詞爲穴鳳，却思丹徼伴冥鴻。", "金公的的生爐際，瓊刃時時到夢中。", "預恐浮山歸有日，載將雲室十洲東。"]'),
('3af29797-a15b-4015-9ce4-682121b3ea1e','奉和襲美寄瓊州楊舍人','陸龜蒙','唐','唐诗','tang','','[]','明時非罪謫何偏，鵩鳥巢南更數千。',64,'全唐诗/poet.tang.34000.json','["明時非罪謫何偏，鵩鳥巢南更數千。", "酒滿椰杯消毒霧，風隨蕉葉下瀧船。", "人多藥戶生狂蠱，吏有珠官出俸錢。", "祗以直誠天自信，不勞詩句詠貪泉。"]'),
('a2fa396d-70cd-45f4-8712-8ecdf94a9fab','奉和襲美宿報恩寺水閣','陸龜蒙','唐','唐诗','tang','','[]','峰抱池光曲岸平，月臨虛檻夜何清。',64,'全唐诗/poet.tang.34000.json','["峰抱池光曲岸平，月臨虛檻夜何清。", "僧穿小檜纔分影，魚擲高荷漸有聲。", "因憶故山吟易苦，各橫秋簟夢難成。", "周顒不用裁書勸，自得涼天證道情。"]'),
('532d2568-d1e2-44bd-b718-bba17ccaca10','奉和襲美醉中偶作見寄次韻','陸龜蒙','唐','唐诗','tang','','[]','海鶴飄飄韻莫儕，在公猶與俗情乖。',64,'全唐诗/poet.tang.34000.json','["海鶴飄飄韻莫儕，在公猶與俗情乖。", "初呈酒務求專判，合禱山祠請自差。", "永夜譚玄侵罔象，一生交態忘形骸。", "憐君醉墨風流甚，幾度題詩小謝齋。"]'),
('a46c38a2-3d88-431f-bc89-45e05935d057','奉和襲美寄滑州李副使員外','陸龜蒙','唐','唐诗','tang','','[]','洛生閑詠正抽毫，忽傍旌旗著戰袍。',64,'全唐诗/poet.tang.34000.json','["洛生閑詠正抽毫，忽傍旌旗著戰袍。", "檄下連營皆破膽，劒離孤匣欲吹毛。", "清秋月色臨軍壘，半夜淮聲入賊壕。", "除却征南爲上將，平徐功業更誰高。"]'),
('467bf2f1-bb36-42a2-b5ea-3db404c026c6','奉和襲美吳中言懷寄南海二同年','陸龜蒙','唐','唐诗','tang','','[]','曾見凌風上赤霄，盡將華藻赴嘉招。',64,'全唐诗/poet.tang.34000.json','["曾見凌風上赤霄，盡將華藻赴嘉招。", "城連虎踞山圖麗，路入龍編海舶遙。", "江客漁歌衝白荇，野禽人語映紅蕉。", "庭中必有君遷樹，莫向空臺望漢朝。"]'),
('e0d14540-c7ae-4459-8d6b-ec981019501a','奉和襲美傷史拱山人','陸龜蒙','唐','唐诗','tang','','[]','曾說山棲欲去尋，豈知霜骨葬寒林。',64,'全唐诗/poet.tang.34000.json','["曾說山棲欲去尋，豈知霜骨葬寒林。", "常依淨住師冥目，兼事容成學算心。", "逋客預齋還梵唱，老猨窺祭亦悲吟。", "唯君獨在江雲外，誰誄孤貞置峴岑。"]'),
('24d6db10-6db2-4a32-8d2d-7089da23db47','白鷗詩','陸龜蒙','唐','唐诗','tang','','[]','慣向溪頭漾淺沙，薄煙微雨是生涯。',64,'全唐诗/poet.tang.34000.json','["慣向溪頭漾淺沙，薄煙微雨是生涯。", "時時失伴沈山影，往往爭飛雜浪花。", "晚樹清涼還𪈺鳿，舊巢零落寄蒹葭。", "池塘信美應難戀，針在魚脣劒在蝦。"]'),
('72bb2ea7-b273-4ce1-bc38-422bcbde17e6','懷楊台文楊鼎文二秀才','陸龜蒙','唐','唐诗','tang','','[]','秋早相逢待得春，崇蘭清露小山雲。',64,'全唐诗/poet.tang.34000.json','["秋早相逢待得春，崇蘭清露小山雲。", "寒花獨自愁中見，曙角多同醒後聞。", "釣具每隨輕舸去，詩題閑上小樓分。", "重思醉墨縱橫甚，書破羊欣白練裙。"]'),
('dc453316-379b-49b4-9de2-0396e35ba189','奉和襲美謝友人惠人參','陸龜蒙','唐','唐诗','tang','','[]','五葉初成椵樹陰，紫團峰外即雞林。',64,'全唐诗/poet.tang.34000.json','["五葉初成椵樹陰，紫團峰外即雞林。", "名參鬼蓋須難見，材似人形不可尋。", "品第已聞升碧簡，攜持應合重黃金。", "殷勤潤取相如肺，封禪書成動帝心。"]'),
('f9ad0c6e-d439-4346-bee0-57b83a5af89d','嚴子重以詩遊於名勝間舊矣余晚於江南相遇甚樂不幸且沒襲美作詩序而弔之其名真不朽矣又何戚其死哉余因息悲而爲之和','陸龜蒙','唐','唐诗','tang','','[]','每值江南日落春，十年詩酒愛逢君。',64,'全唐诗/poet.tang.34000.json','["每值江南日落春，十年詩酒愛逢君。", "芙蓉湖上吟船倚，翡翠巖前醉馬分。", "祗有汀洲連舊業，豈無章疏動遺文。", "猶憐未卜佳城處，更斸要離冢畔雲。"]'),
('e21b8768-2d97-429b-92dc-f8befa26acf2','算山','陸龜蒙','唐','唐诗','tang','','[]','水繞蒼山固護來，當時盤踞實雄才。',64,'全唐诗/poet.tang.34000.json','["水繞蒼山固護來，當時盤踞實雄才。", "周郎計策清宵定，曹氏樓船白晝灰。", "五十八年爭虎視，三千餘騎騁龍媒。", "何如今日家天下，閶闔門臨萬國開。"]'),
('f2cff7fa-913e-490e-8365-9e2d3f1f8f23','寄茅山何威儀二首 一','陸龜蒙','唐','唐诗','tang','','[]','大小三峰次九華，靈蹤今盡屬何家。',64,'全唐诗/poet.tang.34000.json','["大小三峰次九華，靈蹤今盡屬何家。", "漢時仙上雲巔鶴，蜀地春開洞底花。", "閑傍積嵐尋瀑眼，便凌殘雪探芝芽。", "年來已奉黃庭教，夕鍊腥魂曉吸霞。"]'),
('5e9180ea-ea08-4dd1-b5c2-c03094b56ca9','寄茅山何威儀二首 二','陸龜蒙','唐','唐诗','tang','','[]','曾向人間拜節旄，乍疑因夢到仙曹。',64,'全唐诗/poet.tang.34000.json','["曾向人間拜節旄，乍疑因夢到仙曹。", "身輕曳羽霞襟狹，髻聳峨煙鹿幘高。", "山暖不葷峰上薤，水寒仍落洞中桃。", "從聞此日搜奇話，轉覺魂飛夜夜勞。"]'),
('d151a909-8bb6-4341-9951-70a672da74e1','早秋吳體寄襲美','陸龜蒙','唐','唐诗','tang','','[]','荒庭古樹只獨倚，敗蟬殘蛩苦相仍。',64,'全唐诗/poet.tang.34000.json','["荒庭古樹只獨倚，敗蟬殘蛩苦相仍。", "雖然詩膽大如斗，爭奈愁腸牽似繩。", "短燭初添蕙幌影，微風漸折蕉衣稜。", "安得彎弓似明月，快箭拂下西飛鵬。"]'),
('9bb032c2-5d1b-41ac-9d6c-d48aa32a2b8c','病中秋懷寄襲美','陸龜蒙','唐','唐诗','tang','','[]','病容愁思苦相兼，清鏡無形未我嫌。',64,'全唐诗/poet.tang.34000.json','["病容愁思苦相兼，清鏡無形未我嫌。", "貪廣異蔬行徑窄，故求偏藥出錢添。", "同人散後休賒酒，雙燕辭來始下簾。", "更有是非齊未得，重憑詹尹拂龜占。"]'),
('0b0d224e-bb8b-4477-bf7b-c980b8206c17','秋賦有期因寄襲美','陸龜蒙','唐','唐诗','tang','','[]','雲似無心水似閑，忽思名在貢書間。',64,'全唐诗/poet.tang.34000.json','["雲似無心水似閑，忽思名在貢書間。", "煙霞鹿弁聊懸著，隣里漁舠暫解還。", "文章病來猶滿篋，藥苗衰後即離山。", "廣寒宮樹枝多少，風送高低便可攀。"]'),
('7b6c0b41-cc48-428d-b9b3-51035ff608f4','和襲美新秋即事次韻三首 一','陸龜蒙','唐','唐诗','tang','','[]','心似孤雲任所之，世塵中更有誰知。',64,'全唐诗/poet.tang.34000.json','["心似孤雲任所之，世塵中更有誰知。", "愁尋冷落驚雙鬢，病得清涼減四支。", "懷舊藥溪終獨往，宿枯杉寺已頻期。", "兼須爲月求高處，即是霜輪殺滿時。"]'),
('b12f24c5-a890-41f7-a3dc-3480b85dcd3c','和襲美新秋即事次韻三首 二','陸龜蒙','唐','唐诗','tang','','[]','帆檝衣裳盡釣徒，往來蹤跡遍三吳。',64,'全唐诗/poet.tang.34000.json','["帆檝衣裳盡釣徒，往來蹤跡遍三吳。", "閑中展卷興亡小，醉後題詩點畫麤。", "松島伴譚多道氣，竹窗孤夢豈良圖。", "還須待致昇平了，即往扁舟放五湖。"]'),
('6c962b38-6bce-4753-b3cf-048bce54a385','和襲美新秋即事次韻三首 三','陸龜蒙','唐','唐诗','tang','','[]','聲利從來解破除，秋灘唯憶下桐廬。',64,'全唐诗/poet.tang.34000.json','["聲利從來解破除，秋灘唯憶下桐廬。", "鸕鷀陣合殘陽少，蜻蛚吟高冷雨疎。", "辯伏南華論指指，才非玄晏借書書。", "當時任使真堪笑，波上三年學炙魚。"]'),
('bb5738ff-f3f7-4f72-b910-a75b2fa7eb8d','和襲美贈南陽潤卿將歸雷平','陸龜蒙','唐','唐诗','tang','','[]','朝市山林隱一般，却歸那減臥雲懽。',64,'全唐诗/poet.tang.34000.json','["朝市山林隱一般，却歸那減臥雲懽。", "墮階紅葉誰收得，半盎清醪客酹乾。", "玉笈詩成吟處曉，金沙泉落夢中寒。", "真仙若降如相問，曾步星罡繞醮壇。"]'),
('2ddb9f06-1635-473c-b3f9-0915f5a1ec71','顧道士亡弟子奉束帛乞銘於襲美因賦戲贈','陸龜蒙','唐','唐诗','tang','','[]','童初真府召爲郎，君與抽毫刻便房。',64,'全唐诗/poet.tang.34000.json','["童初真府召爲郎，君與抽毫刻便房。", "亦謂神仙同許郭，不妨才力似班揚。", "比於黃絹詞尤妙，酬以霜縑價未當。", "唯我有文無賣處，筆鋒銷盡墨池荒。"]'),
('2217476d-c89f-4e95-ad3d-df3bee779244','和訪寂上人不遇','陸龜蒙','唐','唐诗','tang','','[]','芭蕉霜後石欄荒，林下無人閉竹房。',64,'全唐诗/poet.tang.34000.json','["芭蕉霜後石欄荒，林下無人閉竹房。", "經抄未成拋素几，錫環應撼過寒塘。", "蒲團爲拂浮埃散，茶器空懷碧餑香。", "早晚却還宗炳社，夜深風雪對禪牀。"]'),
('e26ff9c6-4ffa-4713-8da6-c39f8be1a5a7','秋夕文宴','陸龜蒙','唐','唐诗','tang','','[]','筆陣初臨夜正清，擊銅遙認小金鉦。',64,'全唐诗/poet.tang.34000.json','["筆陣初臨夜正清，擊銅遙認小金鉦。", "飛觥壯若遊燕市，覓句難於下趙城。", "隔嶺故人因會憶，傍簷棲鳥帶吟驚。", "梁王座上多詞客，五韻甘心第七成。"]'),
('8840cb38-a035-4530-b453-98b784e5e602','南陽廣文欲於荆襄卜居襲美有贈代酬次韻','陸龜蒙','唐','唐诗','tang','','[]','不知天隱在何鄉，且欲煙霞跡暫雙。',64,'全唐诗/poet.tang.34000.json','["不知天隱在何鄉，且欲煙霞跡暫雙。", "鶴廟未能齊月馭，鹿門聊擬竝雲窗。", "蘚銜荒磴移桑屐，花浸春醪挹石缸。", "莫惜查頭容釣伴，也應東印有餘江。"]'),
('e00fd630-3095-4d37-b8b2-61c2171dd00d','和襲美寄毗陵魏處士朴','陸龜蒙','唐','唐诗','tang','','[]','經苑初成墨沼開，何人林下肯尋來。',64,'全唐诗/poet.tang.34000.json','["經苑初成墨沼開，何人林下肯尋來。", "若非宗測圖山後，即是韓康賣藥迴。", "溪籟自吟朱鷺曲，沙雲還作白鷗媒。", "唯應地主公田熟，時送君家麴糵材。"]'),
('96133537-50b0-4887-9246-10761044699c','和襲美初冬偶作寄南陽潤卿次韻','陸龜蒙','唐','唐诗','tang','','[]','逐日生涯敢計冬，可嗟寒事落然空。',64,'全唐诗/poet.tang.34000.json','["逐日生涯敢計冬，可嗟寒事落然空。", "窗憐返照緣書小，庭喜新霜爲橘紅。", "衰柳尚能和月動，敗蘭猶擬倩煙籠。", "不知海上今清淺，試與飛書問洛公。"]'),
('af1c36d0-3132-4e77-b8d8-9cc94fb6852d','和襲美冬曉章上人院','陸龜蒙','唐','唐诗','tang','','[]','山寒偏是曉來多，況值禪窗雪氣和。',64,'全唐诗/poet.tang.34000.json','["山寒偏是曉來多，況值禪窗雪氣和。", "病客功夫經未演，故人書信納新磨。", "閑臨靜案修茶品，獨傍深溪記藥科。", "從此逍遙知有地，更乘清月伴君過。"]'),
('50286144-17d7-4a36-99e9-876194149ee3','和襲美寄題鏡巖周尊師所居','陸龜蒙','唐','唐诗','tang','','[]','見說身輕鶴不如，石房無侶共雲居。',64,'全唐诗/poet.tang.34000.json','["見說身輕鶴不如，石房無侶共雲居。", "清晨自削靈香柹，獨夜空吟碧落書。", "十洞飛精應徧吸，一簪秋髪未曾梳。", "知君便入懸珠會，早晚東騎白鯉魚。"]'),
('2af758bb-6918-4ed7-bebe-d9b23c981c5b','寒夜文宴得驚字','陸龜蒙','唐','唐诗','tang','','[]','各將寒調觸詩情，旋見微澌入硯生。',64,'全唐诗/poet.tang.34000.json','["各將寒調觸詩情，旋見微澌入硯生。", "霜月滿庭人暫起，汀洲半夜雁初驚。", "三秋每爲仙題想，一日多因累句傾。", "千里建康衰草外，含毫誰是憶昭明。"]'),
('3888b080-f059-4c2f-a0b9-251a9796cd20','送潤卿還華陽','陸龜蒙','唐','唐诗','tang','','[]','何事輕舟近臘回，茅家兄弟欲歸來。',64,'全唐诗/poet.tang.34000.json','["何事輕舟近臘回，茅家兄弟欲歸來。", "封題玉洞虛無奏，點檢霜壇沆瀣杯。", "雲肆先生分氣調，山圖公子愛詞才。", "殷勤爲向東鄉薦，灑掃含真雪後臺。"]'),
('4682701c-4aa7-48e5-a603-16f6c3187c9f','和襲美爲新羅弘惠上人撰靈鷲山周禪師碑送歸詩','陸龜蒙','唐','唐诗','tang','','[]','一函迢遞過東瀛，祗爲先生處乞銘。',64,'全唐诗/poet.tang.34000.json','["一函迢遞過東瀛，祗爲先生處乞銘。", "已得雄詞封靜檢，却懷孤影在禪庭。", "春過異國人應寫，夜讀滄洲怪亦聽。", "遙想勒成新塔下，盡望空碧禮文星。"]'),
('5767520f-698f-41f6-b0c9-03ce46dda5ea','和襲美寒日書齋即事三首每篇各用一韻 一','陸龜蒙','唐','唐诗','tang','','[]','不必探幽上鬱岡，公齋吟嘯亦何妨。',64,'全唐诗/poet.tang.34000.json','["不必探幽上鬱岡，公齋吟嘯亦何妨。", "唯求薏苡供僧食，別著氍毹待客牀。", "春近帶煙分短蕙，曉來衝雪撼疎篁。", "餘杭山酒猶封在，遙囑高人未肯嘗。"]'),
('4181c1b1-ffc9-406d-a3e9-36eab8a374e6','和襲美寒日書齋即事三首每篇各用一韻 二','陸龜蒙','唐','唐诗','tang','','[]','已上星津八月槎，文通猶自學丹砂。',64,'全唐诗/poet.tang.34000.json','["已上星津八月槎，文通猶自學丹砂。", "仙經寫得空三洞，隱士招來別九華。", "靜對真圖呼綠齒，偶開神室問黃芽。", "方諸更是憐才子，錫賚於君合有差。"]'),
('44ab42e3-b369-47d2-b409-76fa48f49e1e','和襲美寒日書齋即事三首每篇各用一韻 三','陸龜蒙','唐','唐诗','tang','','[]','名價皆酬百萬餘，尚憐方丈講玄虛。',64,'全唐诗/poet.tang.34000.json','["名價皆酬百萬餘，尚憐方丈講玄虛。", "西都賓問曾成賦，東海人求近著書。", "茅洞煙霞侵寤寐，檀溪風月挂樵漁。", "清朝還要廷臣在，兩地寧容便結廬。"]'),
('4a1c8e76-e87d-432f-8040-4a5735e25ed5','和襲美臘後送內大德從朂遊天台','陸龜蒙','唐','唐诗','tang','','[]','應緣南國盡南宗，欲訪靈溪路暗通。',64,'全唐诗/poet.tang.34000.json','["應緣南國盡南宗，欲訪靈溪路暗通。", "歸思不離雙闕下，去程猶在四明東。", "銅缾淨貯桃花雨，金策閑搖麥穗風。", "若戀吾君先拜疏，爲論台嶽未封公。"]'),
('366c7400-a019-4cce-b576-bac90d4566d2','和襲美寄題玉霄峰葉涵象尊師所居','陸龜蒙','唐','唐诗','tang','','[]','天台一萬八千丈，師在浮雲端掩扉。',64,'全唐诗/poet.tang.34000.json','["天台一萬八千丈，師在浮雲端掩扉。", "永夜祗知星斗大，深秋猶見海山微。", "風前幾降青毛節，雪後應披白羽衣。", "南望煙霞空再拜，欲將飛魄問靈威。"]'),
('0c7a06e7-3b0b-48ce-923b-bae94930cb7b','南陽廣文博士還雷平後寄','陸龜蒙','唐','唐诗','tang','','[]','微微春色染林塘，親撥煙霞坐澗房。',64,'全唐诗/poet.tang.34000.json','["微微春色染林塘，親撥煙霞坐澗房。", "陰洞雪膠知未入，濁醪風破的偷嘗。", "芝臺曉用金鐺煮，星度閑將玉鉿量。", "幾遍侍晨官欲降，曙壇先起獨焚香。"]'),
('ed715843-d7f4-4dd1-b943-37fab8d3bdf0','和襲美題支山南峰僧次韻','陸龜蒙','唐','唐诗','tang','','[]','眉毫霜細欲垂肩，自說初棲海嶽年。',64,'全唐诗/poet.tang.34000.json','["眉毫霜細欲垂肩，自說初棲海嶽年。", "萬壑煙霞秋後到，一林風雨夜深禪。", "時翻貝葉添新藏，間插松枝護小泉。", "好是清冬無外事，匡林齋罷向陽眠。"]'),
('d1897f41-d2ed-4e8c-9a2a-a4ddafc45a5e','送董少卿遊茅山','陸龜蒙','唐','唐诗','tang','','[]','威輦高懸度世名，至今仙裔作公卿。',64,'全唐诗/poet.tang.34000.json','["威輦高懸度世名，至今仙裔作公卿。", "將隨羽節朝珠闕，曾佩魚符管赤城。", "雲凍尚含孤石色，雪乾猶墮古松聲。", "應知四扇靈方在，待取歸時綠髪生。"]'),
('35038eec-a2e7-400a-a17b-f72b2384dcdd','和襲美寄懷南陽潤卿','陸龜蒙','唐','唐诗','tang','','[]','高抱相逢各絕塵，水經山疏不離身。',64,'全唐诗/poet.tang.34000.json','["高抱相逢各絕塵，水經山疏不離身。", "才情未擬湯從事，玄解猶嫌竺道人。", "霞染洞泉渾變紫，雪披江樹半和春。", "誰憐故國無生計，唯種南塘二畝芹。"]'),
('8befe67e-6ebc-480c-9a7c-84abec45ec47','襲美將以綠罽爲贈因成四韻','陸龜蒙','唐','唐诗','tang','','[]','三逕風霜若利刀，襜褕吹斷罥蓬蒿。',64,'全唐诗/poet.tang.34000.json','["三逕風霜若利刀，襜褕吹斷罥蓬蒿。", "病中祗自悲龍具，世上何人識羽袍。", "狐貉近懷珠履貴，薜蘿遙羨白巾高。", "陳王輕煖如相遺，免致衰荷效廣騷。"]'),
('3513bc24-80b0-4d61-b65b-0f5b44d7c34e','和過張祜處士丹陽故居','陸龜蒙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','勝華通子共悲辛，荒逕今爲舊宅鄰。',64,'全唐诗/poet.tang.34000.json','["勝華通子共悲辛，荒逕今爲舊宅鄰。", "一代交遊非不貴，五湖風月合教貧。", "魂應絕地爲才鬼，名與遺編在史臣。", "聞道平生多愛石，至今猶泣洞庭人。"]'),
('be6d3bbc-065a-4034-9a07-e69dc1a38b99','和襲美寄廣文先生','陸龜蒙','唐','唐诗','tang','','[]','忽辭明主事真君，直取姜巴路入雲。',64,'全唐诗/poet.tang.34000.json','["忽辭明主事真君，直取姜巴路入雲。", "龍篆拜時輕誥命，霓襟披後小玄纁。", "峰前北帝三元會，石上東卿九錫文。", "應笑世間名利火，等閑靈府剩先焚。"]'),
('5d8a454d-172a-4d1b-b025-d93d7f2740b1','和襲美先輩悼鶴','陸龜蒙','唐','唐诗','tang','','[]','一夜圓吭絕不鳴，八公虛道得千齡。',64,'全唐诗/poet.tang.34000.json','["一夜圓吭絕不鳴，八公虛道得千齡。", "方添上客雲眠思，忽伴中仙劒解形。", "但掩叢毛穿古堞，永留寒影在空屏。", "君才幸自清如水，更向芝田爲刻銘。"]'),
('906627d5-30e9-4ed3-adeb-3de852f9be50','幽居有白菊一叢因而成詠呈知己','陸龜蒙','唐','唐诗','tang','','[]','還是延年一種材，即將瑤朵冒霜開。',64,'全唐诗/poet.tang.34000.json','["還是延年一種材，即將瑤朵冒霜開。", "不如紅豔臨歌扇，欲伴黃英入酒杯。", "陶令接䍦堪岸著，梁王高屋好欹來。", "月中若有閑田地，爲勸嫦娥作意裁。"]'),
('b8ae32de-dca8-445a-bb0a-ec2d3730c1b3','和襲美傷開元觀顧道士','陸龜蒙','唐','唐诗','tang','','[]','何事神超入杳冥，不騎孤鶴上三清。',64,'全唐诗/poet.tang.34000.json','["何事神超入杳冥，不騎孤鶴上三清。", "多應白簡迎將去，即是朱陵鍊更生。", "藥奠肯同椒醑味，雲謠空替薤歌聲。", "武皇徒有飄飄思，誰問山中宰相名。"]'),
('a8ab151d-4d19-4e8a-a5d3-e5cf10d7165e','和襲美醉中即席贈潤卿博士次韻','陸龜蒙','唐','唐诗','tang','','[]','共是虛皇簡上仙，清詞如羽欲飄然。',64,'全唐诗/poet.tang.34000.json','["共是虛皇簡上仙，清詞如羽欲飄然。", "登山凡著幾緉屐，破浪欲乘千里船。", "遠夢只留丹井畔，閑吟多在酒旗前。", "誰知海上無名者，只記漁歌不記年。"]'),
('d2f36695-b98f-4596-a3e9-505968f80136','送浙東德師侍御罷府西歸','陸龜蒙','唐','唐诗','tang','','[]','王謝遺蹤玉籍仙，三年閑上鄂君船。',64,'全唐诗/poet.tang.34000.json','["王謝遺蹤玉籍仙，三年閑上鄂君船。", "詩懷白閣僧吟苦，俸買青田鶴價偏。", "行次野楓臨遠水，醉中衰菊臥涼煙。", "芙蓉散盡西歸去，唯有山陰九萬牋。"]'),
('b29ab8ef-1fd5-4d03-996f-6954fc59f25e','送羊振文先輩往桂陽歸覲','陸龜蒙','唐','唐诗','tang','','[]','風雅先生去一麾，過庭才子趣歸期。',64,'全唐诗/poet.tang.34000.json','["風雅先生去一麾，過庭才子趣歸期。", "讓王門外開帆葉，義帝城中望戟支。", "郢路漸寒飄雪遠，湘波初暖漲雲遲。", "靈均精魄如能問，又得千年賈傅詞。"]'),
('68c3ca97-cd38-4bea-9d76-449daa688f33','襲美留振文宴龜蒙抱病不赴猥示倡和因次韻酬謝','陸龜蒙','唐','唐诗','tang','','[]','綺席風開照露晴，祗將茶荈代雲觥。',64,'全唐诗/poet.tang.34000.json','["綺席風開照露晴，祗將茶荈代雲觥。", "繁弦似玉紛紛碎，佳妓如鴻一一驚。", "毫健幾多飛藻客，羽寒寥落映花鶯。", "幽人獨自西窗晚，閑凭香檉反照明。"]'),
('c241efaf-36b9-4e77-baba-b79607613cbd','和襲美重送圓載上人歸日本國','陸龜蒙','唐','唐诗','tang','','[]','老思東極舊巖扉，却待秋風泛舶歸。',64,'全唐诗/poet.tang.34000.json','["老思東極舊巖扉，却待秋風泛舶歸。", "曉梵陽烏當石磬，夜禪陰火照田衣。", "見翻經論多盈篋，親植杉松大幾圍。", "遙想到時思魏闕，只應遙拜望斜暉。"]'),
('37ae61f4-2c69-478d-a990-2fc359511130','和襲美褚家林亭','陸龜蒙','唐','唐诗','tang','','[]','一陣西風起浪花，繞欄杆下散瑤華。',64,'全唐诗/poet.tang.34000.json','["一陣西風起浪花，繞欄杆下散瑤華。", "高窗曲檻仙侯府，臥葦荒芹白鳥家。", "孤島待寒凝片月，遠山終日送餘霞。", "若知方外還如此，不要秋乘上海槎。"]'),
('b3fe13c6-a425-41a7-bfa0-496d379024dc','歸雁','陸龜蒙','唐','唐诗','tang','','[]','北走南征象我曹，天涯迢遞翼應勞。',64,'全唐诗/poet.tang.34000.json','["北走南征象我曹，天涯迢遞翼應勞。", "似悲邊雪音猶苦，初背岳雲行未高。", "月島聚栖防暗繳，風灘斜起避驚濤。", "時人不問隨陽意，空拾欄邊翡翠毛。"]'),
('8adf049e-d5b6-4528-a57b-37f25a89ea6c','王先輩草堂','陸龜蒙','唐','唐诗','tang','','[]','松逕隈雲到靜堂，杏花臨澗水流香。',64,'全唐诗/poet.tang.34000.json','["松逕隈雲到靜堂，杏花臨澗水流香。", "身從亂後全家隱，日校人間一倍長。", "金籙漸加新品秩，玉皇偏賜羽衣裳。", "何如聖代彈冠出，方朔曾爲漢侍郎。"]'),
('6b3d9685-5fca-49a7-8271-5222a935607a','傷越','陸龜蒙','唐','唐诗','tang','','[]','越谿自古好風煙，盜束兵纏已半年。',64,'全唐诗/poet.tang.34000.json','["越谿自古好風煙，盜束兵纏已半年。", "訪戴客愁隨水遠，浣紗人泣共埃捐。", "臨焦賴灑王師雨，欲墮重登刺史天。", "早晚山川盡如故，清吟閑上鄂君船。"]'),
('f4dfcf93-708b-46a6-8e25-785fcfaa810e','新定陪太守一百五夜南館玩月','陸龜蒙','唐','唐诗','tang','','[]','風雨教春處處傷，一宵雲盡見滄浪。',64,'全唐诗/poet.tang.34000.json','["風雨教春處處傷，一宵雲盡見滄浪。", "全無片燭侵光彩，只有清灘助雪霜。", "煙蔽櫂歌歸浦潊，露將花影到衣裳。", "却嫌殷浩南樓夕，一帶秋聲入恨長。"]'),
('528aba2d-6a4f-4835-8ca3-00c3f8e726a3','中元夜寄道侶二首 一','陸龜蒙','唐','唐诗','tang','','[]','學餌霜茸骨未輕，每逢真夕夢還清。',64,'全唐诗/poet.tang.34000.json','["學餌霜茸骨未輕，每逢真夕夢還清。", "丁寧獨受金妃約，許與親題玉篆名。", "月苦撼殘臨水珮，風微飄斷繫雲纓。", "須臾枕上桐窗曉，露壓千枝滴滴聲。"]'),
('cd0ffd0d-ece9-4fcf-80d6-6b3492952078','中元夜寄道侶二首 二','陸龜蒙','唐','唐诗','tang','','[]','橘齋風露已清餘，東郭先生病未除。',64,'全唐诗/poet.tang.34000.json','["橘齋風露已清餘，東郭先生病未除。", "孤枕易爲蛩破夢，短簷難得燕傳書。", "廣雲披日君應近，倒影裁花我尚疎。", "唯羨羽人襟似水，平持旄節步空虛。"]'),
('2d9565a1-1447-4ffd-b16d-c9bedd28febc','寄懷華陽道士','陸龜蒙','唐','唐诗','tang','','[]','華陽門外五芝生，飡罷愁君入杳冥。',384,'全唐诗/poet.tang.34000.json','["華陽門外五芝生，飡罷愁君入杳冥。", "遙夜獨栖還有夢，昔年相見便忘形。", "爲分科斗親鉛槧，與說蜉蝣坐竹櫺。", "醮後幾時歸紫閣，別來終日誦黃庭。", "閑教辨藥僮名甲，靜識窺巢鶴姓丁。", "絕澗飲羊春水膩，傍林燒石野煙腥。", "深沈谷響含疎磬，片段嵐光落畫屏。", "休採古書探禹穴，自刊新曆鬬堯蓂。", "珠宮鳳合迎蕭史，玉籍人誰訪蔡經。", "架上黑椽長褐穩，案頭丹篆小符靈。", "霓軒入洞齊初月，羽節升壇拜七星。", "當路獨行衝虎豹，向風孤嘯起雷庭。", "凝神密室多生白，敘事聊編盡殺青。", "匝地山川皆暗寫，隱天竽籟祗閑聽。", "分張火力燒金竈，拂拭苔痕洗酒缾。", "翠壁上吟朝復暮，暖雲邊臥醉還醒。", "倚身長短裁筇杖，倩客高低結草亭。", "直用森嚴朝北帝，愛將清淺問東溟。", "常思近圃看栽杏，擬借鄰峰伴采苓。", "揜樹半扉晴靄靄，背琴殘燭曉熒熒。", "舊來捫虱知王猛，欲去爲龍歎管寧。", "蟾魄幾應臨蕙帳，漁竿猶尚枕楓汀。", "銜煙細草無端綠，冒雨閑花作意馨。", "掠岸驚波沈翡翠，入簷斜照礙蜻蜓。"]'),
('c56db3b4-dc7f-4e8c-962b-954bb76e6954','人日代客子','陸龜蒙','唐','唐诗','tang','','[]','人日兼春日，長懷復短懷。',24,'全唐诗/poet.tang.34000.json','["人日兼春日，長懷復短懷。", "遙知雙綵勝，併在一金釵。"]'),
('fbbde73f-b005-4c1d-a416-01571d9d2ae1','築城詞二首 一','陸龜蒙','唐','唐诗','tang','','[]','城上一培土，手中千萬杵。',24,'全唐诗/poet.tang.34000.json','["城上一培土，手中千萬杵。", "築城畏不堅，堅城在何處。"]'),
('05514976-4289-46d9-b59e-ab088bc3f3e8','築城詞二首 二','陸龜蒙','唐','唐诗','tang','','[]','莫歎將軍逼，將軍要却敵。',24,'全唐诗/poet.tang.34000.json','["莫歎將軍逼，將軍要却敵。", "城高功亦高，爾命何勞惜。"]'),
('21e34d9e-3977-435e-a8ee-f08fd701f8aa','古意','陸龜蒙','唐','唐诗','tang','','[]','君心莫淡薄，妾意正栖託。',24,'全唐诗/poet.tang.34000.json','["君心莫淡薄，妾意正栖託。", "願得雙車輪，一夜生四角。"]'),
('e1dcec84-ca73-4305-a0d2-c5781bb69528','春曉','陸龜蒙','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','春庭曉景別，清露花邐迤。',24,'全唐诗/poet.tang.34000.json','["春庭曉景別，清露花邐迤。", "黃蜂一過慵，夜夜棲香蘂。"]'),
('2c366a49-2b55-4c25-889b-4ea6b9246238','雜興','陸龜蒙','唐','唐诗','tang','','[]','桃李傍簷楹，無人賞春華。',24,'全唐诗/poet.tang.34000.json','["桃李傍簷楹，無人賞春華。", "時情重不見，却憶菖蒲花。"]'),
('f3cce70b-38fa-4fa4-ac91-9971af141f89','鴈','陸龜蒙','唐','唐诗','tang','','[]','南北路何長，中間萬弋張。',24,'全唐诗/poet.tang.34000.json','["南北路何長，中間萬弋張。", "不知煙霧裏，幾隻到衡陽。"]'),
('4b60a6e5-bcc9-4e72-b263-e97994d2f06c','寄遠','陸龜蒙','唐','唐诗','tang','','[]','鬢亂羞雲卷，眉空羨月生。',24,'全唐诗/poet.tang.34000.json','["鬢亂羞雲卷，眉空羨月生。", "中原猶將將，何日重卿卿。"]'),
('d83eca31-7944-46e5-ad98-f3ae9346d860','庭前','陸龜蒙','唐','唐诗','tang','','[]','合歡能解恚，萱草信忘憂。',24,'全唐诗/poet.tang.34000.json','["合歡能解恚，萱草信忘憂。", "盡向庭前種，萋萋特地愁。"]'),
('e51909e1-5abd-4874-b427-e54961f8fcc2','洞房怨','陸龜蒙','唐','唐诗','tang','','[]','玉鍤朝扶鬢，金梯晚下臺。',24,'全唐诗/poet.tang.34000.json','["玉鍤朝扶鬢，金梯晚下臺。", "春衫將別淚，一夜兩難裁。"]'),
('a7e33fda-27ab-4a02-a7b3-d33e6087df71','江行','陸龜蒙','唐','唐诗','tang','','[]','酒旗菰葉外，樓影浪花中。',24,'全唐诗/poet.tang.34000.json','["酒旗菰葉外，樓影浪花中。", "醉帆張數幅，唯待鯉魚風。"]'),
('bb1a2604-5009-406e-8815-51f91aad4005','巫峽','陸龜蒙','唐','唐诗','tang','','[]','巫峽七百里，巫山十二重。',24,'全唐诗/poet.tang.34000.json','["巫峽七百里，巫山十二重。", "年年自雲雨，環佩竟誰逢。"]'),
('be0032a1-e532-423e-b101-d635e589bd38','歸路','陸龜蒙','唐','唐诗','tang','','[]','漸入新豐路，衰紅映小橋。',24,'全唐诗/poet.tang.34000.json','["漸入新豐路，衰紅映小橋。", "渾如七年病，初得一丸銷。"]'),
('2d2f7437-cfba-4fdd-84b1-39f4ef17b59b','南塘曲','陸龜蒙','唐','唐诗','tang','','[]','妾住東湖下，郎居南浦邊。',24,'全唐诗/poet.tang.34000.json','["妾住東湖下，郎居南浦邊。", "閑臨煙水望，認得采菱船。"]'),
('e9e64532-f5b4-4be2-8bf5-4e04894b301b','黃金二首 一','陸龜蒙','唐','唐诗','tang','','[]','自古黃金貴，猶沽駿與才。',24,'全唐诗/poet.tang.34000.json','["自古黃金貴，猶沽駿與才。", "近來簪珥重，無可上高臺。"]'),
('0288676e-e5dd-414d-a192-8da9f35d11d6','黃金二首 二','陸龜蒙','唐','唐诗','tang','','[]','平分從滿篋，醉擲任成堆。',24,'全唐诗/poet.tang.34000.json','["平分從滿篋，醉擲任成堆。", "恰莫持千萬，明明買禍胎。"]'),
('90ce2b59-3788-4e91-9a68-4b5b52ab1e77','夕陽','陸龜蒙','唐','唐诗','tang','','[]','渡口和帆落，城邊帶角收。',24,'全唐诗/poet.tang.34000.json','["渡口和帆落，城邊帶角收。", "如何茂陵客，江上倚危樓。"]'),
('4c62f5a2-a2a6-4684-8a53-393f954230b4','殘雪','陸龜蒙','唐','唐诗','tang','','[]','桂冷微停素，峰乾不徧嵐。',24,'全唐诗/poet.tang.34000.json','["桂冷微停素，峰乾不徧嵐。", "何谿背林處，猶覆定僧庵。"]'),
('2eddd93d-1a7d-460a-bfaa-61192e195c8d','古態','陸龜蒙','唐','唐诗','tang','','[]','古態日漸薄，新妝心更勞。',24,'全唐诗/poet.tang.34000.json','["古態日漸薄，新妝心更勞。", "城中皆一尺，非妾髻鬟高。"]'),
('9cae44f6-ccf9-4932-9cea-41d7344a07da','大堤','陸龜蒙','唐','唐诗','tang','','[]','大堤春日暮，驄馬解鏤衢。',24,'全唐诗/poet.tang.34000.json','["大堤春日暮，驄馬解鏤衢。", "請君留上客，容妾薦彫胡。"]'),
('9d6bba8e-fefd-45f3-9339-d5df10bd87a7','金陵道','陸龜蒙','唐','唐诗','tang','','[]','北鴈行行直，東流澹澹春。',24,'全唐诗/poet.tang.34000.json','["北鴈行行直，東流澹澹春。", "當時六朝客，還道帝鄉人。"]'),
('965a5dde-7b0c-405d-b2a4-2ef4a8a3a508','離騷','陸龜蒙','唐','唐诗','tang','','["\u611f\u6168", "\u5199\u4eba", "\u6000\u53e4", "\u5199\u4eba\u8bd7"]','天問復招魂，無因徹帝閽。',24,'全唐诗/poet.tang.34000.json','["天問復招魂，無因徹帝閽。", "豈知千麗句，不敵一讒言。"]'),
('93b20486-3cd2-437b-9c4b-a6bb24a7e6bc','對酒','陸龜蒙','唐','唐诗','tang','','[]','後代稱歡伯，前賢號聖人。',24,'全唐诗/poet.tang.34000.json','["後代稱歡伯，前賢號聖人。", "且須謀日富，不要道家貧。"]'),
('5d0dc788-c96a-4caf-96b1-c0e886ab267a','寄南岳客乞靈蕪香','陸龜蒙','唐','唐诗','tang','','[]','聞說融峰下，靈香似反魂。',24,'全唐诗/poet.tang.34000.json','["聞說融峰下，靈香似反魂。", "春來正堪采，試爲斸雲根。"]'),
('7721cf9f-6c6c-4f7b-8e29-a72cebb980a5','山陽燕中郊樂錄','陸龜蒙','唐','唐诗','tang','','[]','淮上能無雨，回頭總是情。',24,'全唐诗/poet.tang.34000.json','["淮上能無雨，回頭總是情。", "蒲帆渾未織，爭得一歡成。"]'),
('c9f64981-0035-498e-a4d5-46f827b78f91','偶作','陸龜蒙','唐','唐诗','tang','','[]','雙眉初出繭，兩鬢正藏鴉。',24,'全唐诗/poet.tang.34000.json','["雙眉初出繭，兩鬢正藏鴉。", "自有王昌在，何勞近宋家。"]'),
('df0b225b-e2aa-43f1-883b-5b452c21d6c2','有示','陸龜蒙','唐','唐诗','tang','','[]','相對莫辭貧，蓬蒿任塞門。',24,'全唐诗/poet.tang.34000.json','["相對莫辭貧，蓬蒿任塞門。", "無情是金玉，不報主人恩。"]'),
('9d5b80a9-3acc-447d-bb24-6d7cc7f29b0e','秋思三首 一','陸龜蒙','唐','唐诗','tang','','[]','桐露珪初落，蘭風佩欲衰。',24,'全唐诗/poet.tang.34000.json','["桐露珪初落，蘭風佩欲衰。", "不知能賦客，何似枉刀兒。"]'),
