('0239690b-456f-4a5b-a455-2006802e7865','連昌宮詞二首 階','陸龜蒙','唐','唐诗','tang','','[]','草沒苔封疊翠斜，墜紅千葉擁殘霞。',32,'全唐诗/poet.tang.34000.json','["草沒苔封疊翠斜，墜紅千葉擁殘霞。", "年年直爲秋霖苦，滴陷青珉隱起花。"]'),
('8b374441-66b2-4933-93ab-5b34bfea6461','懷宛陵舊遊','陸龜蒙','唐','唐诗','tang','','[]','陵陽佳地昔年遊，謝朓青山李白樓。',32,'全唐诗/poet.tang.34000.json','["陵陽佳地昔年遊，謝朓青山李白樓。", "唯有日斜溪上思，酒旗風影落春流。"]'),
('50e38d0d-17f1-4345-8f78-bbfc024d1be8','松石曉景圖','陸龜蒙','唐','唐诗','tang','','[]','霜骨雲根慘澹愁，宿煙封著未全收。',32,'全唐诗/poet.tang.34000.json','["霜骨雲根慘澹愁，宿煙封著未全收。", "將歸與說文通後，寫得松江岸上秋。"]'),
('12e5f988-4a76-452a-9733-36167acc0325','釣車','陸龜蒙','唐','唐诗','tang','','[]','小輪輕線妙無雙，曾伴幽人酒一缸。',32,'全唐诗/poet.tang.34000.json','["小輪輕線妙無雙，曾伴幽人酒一缸。", "洛客見詩如有問，輾煙衝雨過桐江。"]'),
('c8b53269-8685-4517-964b-384ea3ea1ac5','漉酒巾','陸龜蒙','唐','唐诗','tang','','[]','靖節高風不可攀，此巾猶墜凍醪間。',32,'全唐诗/poet.tang.34000.json','["靖節高風不可攀，此巾猶墜凍醪間。", "偏宜雪夜山中戴，認取時情與醉顏。"]'),
('aed161f9-9524-40cd-8e40-c5a6aba45589','華陽巾','陸龜蒙','唐','唐诗','tang','','[]','蓮花峰下得佳名，雲褐相兼上鶴翎。',32,'全唐诗/poet.tang.34000.json','["蓮花峰下得佳名，雲褐相兼上鶴翎。", "須是古壇秋霽後，靜焚香炷禮寒星。"]'),
('9788800b-ab08-4c78-9ceb-26d4b7045001','方響','陸龜蒙','唐','唐诗','tang','','[]','擊霜寒玉亂丁丁，花[底]秋風拂坐生。',34,'全唐诗/poet.tang.34000.json','["擊霜寒玉亂丁丁，花[底]秋風拂坐生。", "王母閑看漢天子，滿猗蘭殿佩環聲。"]'),
('6c68e56a-b8ce-4574-ab1d-94a8ea337501','白鷺','陸龜蒙','唐','唐诗','tang','','[]','雪然飛下立蒼苔，應伴江鷗拒我來。',32,'全唐诗/poet.tang.34000.json','["雪然飛下立蒼苔，應伴江鷗拒我來。", "見欲扁舟搖蕩去，倩君先作水雲媒。"]'),
('fbb58f26-6891-4129-a052-5e36a34ae316','溪行','陸龜蒙','唐','唐诗','tang','','[]','晚天寒雨上灘時，他已揚舲我尚遲。',32,'全唐诗/poet.tang.34000.json','["晚天寒雨上灘時，他已揚舲我尚遲。", "自是檣低帆幅少，溪風終不兩般吹。"]'),
('7e1c9f22-a566-451c-b593-1fe9b79b2ab3','太湖叟','陸龜蒙','唐','唐诗','tang','','["\u592a\u6e56"]','細槳輕船賣石歸，酒痕狼籍徧苔衣。',32,'全唐诗/poet.tang.34000.json','["細槳輕船賣石歸，酒痕狼籍徧苔衣。", "攻車戰艦繁如織，不肯回頭問是非。"]'),
('5825c218-af6b-458e-a1ce-c6df37a0049f','荅友人','陸龜蒙','唐','唐诗','tang','','[]','荆卿雄骨化爲塵，燕市應無共飲人。',32,'全唐诗/poet.tang.34000.json','["荆卿雄骨化爲塵，燕市應無共飲人。", "能說鷫鸘來換酒，五湖賒與一年春。"]'),
('ca0b079b-4662-4e48-a67e-7a5fa4a31813','偶作','陸龜蒙','唐','唐诗','tang','','[]','酒信巧爲繰病緒，花音長作嫁愁媒。',32,'全唐诗/poet.tang.34000.json','["酒信巧爲繰病緒，花音長作嫁愁媒。", "也知愁病堪回避，爭奈流鶯喚起來。"]'),
('ea39a073-dec0-45e8-815d-f37beffa2683','春思二首 一','陸龜蒙','唐','唐诗','tang','','[]','竹外麥煙愁漠漠，短翅啼禽飛魄魄。',32,'全唐诗/poet.tang.34000.json','["竹外麥煙愁漠漠，短翅啼禽飛魄魄。", "此時憶著千里人，獨坐支頤看花落。"]'),
('6834ee40-c389-4afa-955e-e786be14e8ab','春思二首 二','陸龜蒙','唐','唐诗','tang','','[]','江南酒熟清明天，高高綠斾當風懸。',32,'全唐诗/poet.tang.34000.json','["江南酒熟清明天，高高綠斾當風懸。", "誰家無事少年子，滿面落花猶醉眠。"]'),
('f36a9435-e418-4cc0-a566-3dd15f627e52','訪僧不遇','陸龜蒙','唐','唐诗','tang','','[]','櫂倚東林欲問禪，遠公飛錫未應還。',32,'全唐诗/poet.tang.34000.json','["櫂倚東林欲問禪，遠公飛錫未應還。", "蒙莊弟子相看笑，何事空門亦有關。"]'),
('fe5ff721-0983-4095-8feb-38859a60f902','謝山泉','陸龜蒙','唐','唐诗','tang','','[]','決決春泉出洞霞，石壜封寄野人家。',32,'全唐诗/poet.tang.34000.json','["決決春泉出洞霞，石壜封寄野人家。", "草堂盡日留僧坐，自向前溪摘茗芽。"]'),
('f254a579-91a2-4a36-a182-8e1a83eb17fe','洞宮夕','陸龜蒙','唐','唐诗','tang','','[]','月午山空桂花落，華陽道士雲衣薄。',32,'全唐诗/poet.tang.34000.json','["月午山空桂花落，華陽道士雲衣薄。", "石壇香散步虛聲，杉雲清泠滴栖鶴。"]'),
('3cc34dc5-462a-40b5-8b31-d1cc7cadd337','峽客行','陸龜蒙','唐','唐诗','tang','','[]','萬仞峰排千劒束，孤舟夜繫峰頭宿。',32,'全唐诗/poet.tang.34000.json','["萬仞峰排千劒束，孤舟夜繫峰頭宿。", "蠻溪雪壞蜀江傾，灩澦朝來大如屋。"]'),
('516a8e61-5285-4666-82be-7a93c75496c8','江邊','陸龜蒙','唐','唐诗','tang','','[]','江邊日晚潮煙上，樹裏鴉鴉桔槔響。',32,'全唐诗/poet.tang.34000.json','["江邊日晚潮煙上，樹裏鴉鴉桔槔響。", "無因得似灌園翁，十畝春蔬一藜杖。"]'),
('90400319-f6a6-4456-9f52-90993e0ae093','簾','陸龜蒙','唐','唐诗','tang','','[]','枕映疎容晚向欹，秋煙脉脉雨微微。',32,'全唐诗/poet.tang.34000.json','["枕映疎容晚向欹，秋煙脉脉雨微微。", "逆風障燕尋常事，不學人前當妓衣。"]'),
('56b6ff3e-ede2-4ee0-9447-04ded6408cfd','開元雜題七首 玉龍子','陸龜蒙','唐','唐诗','tang','','[]','何代奇工碾玉英，細髯纖角盡雕成。',32,'全唐诗/poet.tang.34000.json','["何代奇工碾玉英，細髯纖角盡雕成。", "煙乾霧悄君心苦，風雨長隨一擲聲。"]'),
('f348129a-f81d-4b9f-aabf-c542aa390e67','開元雜題七首 照夜白','陸龜蒙','唐','唐诗','tang','','[]','雪蚪輕駿步如飛，一練騰光透月旗。',32,'全唐诗/poet.tang.34000.json','["雪蚪輕駿步如飛，一練騰光透月旗。", "應笑穆王拋萬乘，踏風鞭露向瑤池。"]'),
('8391aa6d-002b-4672-89f4-eb38328b7066','開元雜題七首 舞馬','陸龜蒙','唐','唐诗','tang','','[]','月窟龍孫四百蹄，驕驤輕步應金鞞。',32,'全唐诗/poet.tang.34000.json','["月窟龍孫四百蹄，驕驤輕步應金鞞。", "曲終似要君王寵，回望紅樓不敢嘶。"]'),
('ae79ebe6-e7e0-4166-9bb5-31759dacd172','開元雜題七首 雜伎','陸龜蒙','唐','唐诗','tang','','[]','拜象馴犀角觝豪，星丸霜劒出花高。',32,'全唐诗/poet.tang.34000.json','["拜象馴犀角觝豪，星丸霜劒出花高。", "六宮爭近乘輿望，珠翠三千擁赭袍。"]'),
('56577b6e-7fd0-41eb-8285-a0e768a3461f','開元雜題七首 雪衣女','陸龜蒙','唐','唐诗','tang','','[]','嫩紅鉤曲雪花攢，月殿棲時片影殘。',32,'全唐诗/poet.tang.34000.json','["嫩紅鉤曲雪花攢，月殿棲時片影殘。", "自說夜來春夢惡，學持金偈玉欄干。"]'),
('64dde076-4d4f-45e3-af90-a352676fc1f9','開元雜題七首 繡嶺宮','陸龜蒙','唐','唐诗','tang','','[]','繡嶺花殘翠倚空，碧窗瑤砌舊行宮。',32,'全唐诗/poet.tang.34000.json','["繡嶺花殘翠倚空，碧窗瑤砌舊行宮。", "閑乘小駟濃陰下，時舉金鞭半袖風。"]'),
('75683a4f-d948-41ac-bd9a-19453c96f94e','開元雜題七首 湯泉','陸龜蒙','唐','唐诗','tang','','[]','暖殿流湯數十間，玉渠香細浪回環。',32,'全唐诗/poet.tang.34000.json','["暖殿流湯數十間，玉渠香細浪回環。", "上皇初解雲衣浴，珠櫂時敲瑟瑟山。"]'),
('8fd6aba6-7ec2-4258-854b-462afc8abed8','題杜秀才水亭','陸龜蒙','唐','唐诗','tang','','[]','曉和風露立晴煙，秖恐腥魂涴洞天。',32,'全唐诗/poet.tang.34000.json','["曉和風露立晴煙，秖恐腥魂涴洞天。", "雲肆有龍君若買，便敲初日鑄金錢。"]'),
('625dc6c3-7f7c-42c4-b034-c30a993fa3b6','翠碧','陸龜蒙','唐','唐诗','tang','','[]','紅襟翠翰兩參差，徑拂煙華上細枝。',32,'全唐诗/poet.tang.34000.json','["紅襟翠翰兩參差，徑拂煙華上細枝。", "春水漸生魚易得，莫辭風雨坐多時。"]'),
('185d244a-7c99-4ff9-851b-a3b35db552fa','水國詩','陸龜蒙','唐','唐诗','tang','','[]','水國不堪旱，斯民生甚微。',56,'全唐诗/poet.tang.34000.json','["水國不堪旱，斯民生甚微。", "直至葭菼少，敢言魚蟹肥。", "我到荒村無食啗，對案又非梁謝覽。", "況是乾苗結子疎，歸時祗得藜羹糝。"]'),
('5c060870-df3e-43d8-b8fa-3920a66d6470','井上桐','陸龜蒙','唐','唐诗','tang','','[]','美人傷別離，汲井長待曉。',36,'全唐诗/poet.tang.34000.json','["美人傷別離，汲井長待曉。", "愁因轆轤轉，驚起雙棲鳥。", "獨立傍銀牀，碧桐風嫋嫋。"]'),
('b715c3ca-9306-4c64-a487-34456199d6b4','門前路','陸龜蒙','唐','唐诗','tang','','[]','門前向城路，一直復一曲。',36,'全唐诗/poet.tang.34000.json','["門前向城路，一直復一曲。", "曲去日中還，直行日暮宿。", "何必日中還，曲途荆棘間。"]'),
('c807f0fa-06da-43fa-a014-3ebf8a3cdb48','彼農二章 一','陸龜蒙','唐','唐诗','tang','','[]','世路澆險，淳風蕩除。',110,'全唐诗/poet.tang.34000.json','["世路澆險，淳風蕩除。", "彼農家流，猶存厥初。", "藁焉而席，茨焉而居。", "首亂如葆，形枯若腒。", "大耋既鮐，童子未𪘯。", "以負以載，悉薅悉鉏。", "我慕聖道，我躭古書。", "小倦於學，時遊汝廬。", "有飯一盛，莫鹽莫蔬。", "有繻一緹，不襟不袪。", "所謂飢寒，汝何逭歟。"]'),
('d4f9553e-a574-4a16-9432-f5e3b9db0844','彼農二章 二','陸龜蒙','唐','唐诗','tang','','[]','禹貢厥田，上下各異。',90,'全唐诗/poet.tang.34000.json','["禹貢厥田，上下各異。", "善人爲邦，民受其賜。", "去年西成，野有遺穗。", "今夏南畝，旱氣赤地。", "遭其豐凶，概歛無二。", "退輸弗供，進訴弗視。", "號于旻天，以血爲淚。", "孟子有言，王無罪歲。", "詩以窮辭，以嫉悍吏。"]'),
('fcf27b6c-aa71-4894-827b-a476752b3105','奉酬襲美苦雨見寄','陸龜蒙','唐','唐诗','tang','','[]','松篁交加午陰黑，別是江南煙靄國。',386,'全唐诗/poet.tang.34000.json','["松篁交加午陰黑，別是江南煙靄國。", "頑雲猛雨更相欺，聲似虓號色如墨。", "茅茨裛爛簷生衣，夜夜化爲螢火飛。", "螢飛漸多屋漸薄，一注愁霖當面落。", "愁霖愁霖爾何錯，滅頂於余奚所作。", "既不能賦似陳思王，又不能詩似謝康樂。", "昔年嘗過杜子美，亦得高歌破印紙。", "慣曾掀攪大筆多，爲我才情也如此。", "高揖愁霖詞未已，披文忽自皮夫子。", "哀弦怨柱合爲吟，㤞我窮棲蓬藋裏。", "初悲濕翼何由起，末欲牋天叩天耳。", "其如玉女正投壺，笑電霏霏作天喜。", "我本曾無一稜田，平生嘯傲空漁船。", "有時赤腳弄明月，踏破五湖光底天。", "去歲王師東下急，輸兵粟盡民相泣。", "伊予不戰不耕人，敢怨烝黎無糝粒。", "不然受性圓如規，千姿萬態分毫釐。", "唾壺虎子盡能執，舐痔折枝無所辭。", "有頭強方心強直，撐拄頹風不量力。", "自愛垂名野史中，寧論抱困荒城側。", "唯君浩歎非庸人，分衣輟飲來相親。", "橫眠木榻忘華薦，對食露葵輕八珍。", "欲窮玄，鳳未白，欲懷仙，鯨尚隔。", "不如驅入醉鄉中，只恐醉鄉田地窄。"]'),
('bfbf97c4-9382-4157-bf56-24737be61dfe','夏日閑居作四聲詩寄襲美 平聲','陸龜蒙','唐','唐诗','tang','','[]','荒池菰蒲深，閑階莓苔平。',48,'全唐诗/poet.tang.34000.json','["荒池菰蒲深，閑階莓苔平。", "江邊松篁多，人家簾櫳清。", "爲書凌遺編，調弦夸新聲。", "求歡雖殊途，探幽聊怡情。"]'),
('1a23e103-053b-482e-a6e9-61d45a316af3','夏日閑居作四聲詩寄襲美 平上聲','陸龜蒙','唐','唐诗','tang','','[]','朝煙淹樓臺，晚雨染島嶼。',48,'全唐诗/poet.tang.34000.json','["朝煙淹樓臺，晚雨染島嶼。", "漁童驚狂歌，艇子喜野語。", "山容堪停杯，柳影好隱暑。", "年華如飛鴻，斗酒幸且舉。"]'),
('50eb6d3d-42a2-4e2d-a745-ee07fd602abb','夏日閑居作四聲詩寄襲美 平去聲','陸龜蒙','唐','唐诗','tang','','[]','新開窗猶偏，自種蕙未徧。',48,'全唐诗/poet.tang.34000.json','["新開窗猶偏，自種蕙未徧。", "書籤風搖聞，釣榭霧破見。", "耕耘閑之資，嘯詠性最便。", "希夷全天真，詎要問貴賤。"]'),
('777c723b-849d-42ab-9aca-d6543f475e6b','夏日閑居作四聲詩寄襲美 平入聲','陸龜蒙','唐','唐诗','tang','','[]','端居愁無涯，一夕髪欲白。',48,'全唐诗/poet.tang.34000.json','["端居愁無涯，一夕髪欲白。", "因爲鸞章吟，忽憶鶴骨客。", "手披丹臺文，脚著赤玉舃。", "如蒙清音酬，若渴吸月液。"]'),
('2d5bfbdc-0498-4094-a17c-fbd2ecac01b7','奉酬襲美苦雨四聲重寄三十二句 平聲','陸龜蒙','唐','唐诗','tang','','[]','幽棲眠疎窗，豪居憑高樓。',48,'全唐诗/poet.tang.34000.json','["幽棲眠疎窗，豪居憑高樓。", "浮漚驚跳丸，寒聲思重裘。", "牀前垂文竿，巢邊登輕舟。", "雖無東臯田，還生魚乎憂。"]'),
('16c747e9-33c3-43ec-a59e-cd5c2ab1a9fa','奉酬襲美苦雨四聲重寄三十二句 平上聲','陸龜蒙','唐','唐诗','tang','','[]','層雲愁天低，久雨倚檻冷。',48,'全唐诗/poet.tang.34000.json','["層雲愁天低，久雨倚檻冷。", "絲禽藏荷香，錦鯉繞島影。", "心將時人乖，道與隱者靜。", "桐陰無深泉，所以逞短綆。"]'),
('c34b667a-2284-40ad-9639-74e61ed6ea9b','奉酬襲美苦雨四聲重寄三十二句 平去聲','陸龜蒙','唐','唐诗','tang','','[]','烏蟾俱沈光，晝夜恨暗度。',48,'全唐诗/poet.tang.34000.json','["烏蟾俱沈光，晝夜恨暗度。", "何當乘雲螭，面見上帝愬。", "臣言陰雲欺，詔用利劒付。", "迴車誅羣姦，自散萬籟怒。"]'),
('0e30d332-309d-43af-8ac6-3351954a8101','奉酬襲美苦雨四聲重寄三十二句 平入聲','陸龜蒙','唐','唐诗','tang','','[]','危簷仍空堦，十日滴不歇。',48,'全唐诗/poet.tang.34000.json','["危簷仍空堦，十日滴不歇。", "青莎看成狂，白菊即欲沒。", "吳王荒金尊，越妾挾玉瑟。", "當時雖愁霖，亦若惜落月。"]'),
('78693577-76f1-44cb-b44f-dbe1de507d3b','曉起即事因成迴文寄襲美','陸龜蒙','唐','唐诗','tang','','[]','平波落月吟閑景，暗幌浮煙思起人。',64,'全唐诗/poet.tang.34000.json','["平波落月吟閑景，暗幌浮煙思起人。", "清露曉垂花謝半，遠風微動蕙抽新。", "城荒上處樵童小，石蘚分來宿鷺馴。", "晴寺野尋同去好，古碑苔字細書勻。"]'),
('3de4e1c3-9b08-49c3-9df3-26d4895fecbe','回文','陸龜蒙','唐','唐诗','tang','','[]','靜煙臨碧樹，殘雪背晴樓。',24,'全唐诗/poet.tang.34000.json','["靜煙臨碧樹，殘雪背晴樓。", "冷天侵極戍，寒月對行舟。"]'),
('ea9cd1bb-826a-4d94-b177-3036b7475599','疊韻山中吟','陸龜蒙','唐','唐诗','tang','','[]','瓊英輕明生，石脉滴瀝碧。',24,'全唐诗/poet.tang.34000.json','["瓊英輕明生，石脉滴瀝碧。", "玄鉛仙偏憐，白幘客亦惜。"]'),
('c136e8f5-02dc-472b-ada7-97c60588b0ac','雙聲溪上思','陸龜蒙','唐','唐诗','tang','','[]','溪空唯容雲，木密不隕雨。',24,'全唐诗/poet.tang.34000.json','["溪空唯容雲，木密不隕雨。", "迎漁隱映間，安問謳鴉樐。"]'),
('eca1a684-5e75-4435-aa73-8b6745b5e2f1','疊韻吳宮詞二首 一','陸龜蒙','唐','唐诗','tang','','[]','膚愉吳都姝，眷戀便殿宴。',24,'全唐诗/poet.tang.34000.json','["膚愉吳都姝，眷戀便殿宴。", "逡巡新春人，轉面見戰箭。"]'),
('ee4ae0a7-d6ff-4196-b042-eb06f8c9d519','疊韻吳宮詞二首 二','陸龜蒙','唐','唐诗','tang','','[]','紅櫳通東風，翠珥醉易墜。',24,'全唐诗/poet.tang.34000.json','["紅櫳通東風，翠珥醉易墜。", "平明兵盈城，棄置遂至地。"]'),
('bd8916ad-9f2b-4012-bd24-6ba97b6789e7','和胥口即事 一','陸龜蒙','唐','唐诗','tang','','[]','雨後山容若動，天寒樹色如消。',56,'全唐诗/poet.tang.34000.json','["雨後山容若動，天寒樹色如消。", "目送迴汀隱隱，心隨挂鹿搖搖。", "白蔣知秋露裛，青楓欲暮煙饒。", "莫問吳趨行樂，酒旗竿倚河橋。"]'),
('56e8c10c-e6ee-42ae-ab72-96e09894da25','和胥口即事 二','陸龜蒙','唐','唐诗','tang','','[]','把釣絲隨浪遠，采蓮衣染香濃。',59,'全唐诗/poet.tang.34000.json','["把釣絲隨浪遠，采蓮衣染香濃。", "綠倒紅飄欲盡，風斜雨細相逢。", "斷岸沈漁𦋥𦊲，鄰村送客𦪽{舟卭}。", "即是清霜剖野，乘閑莫厭來重。"]'),
('807f3ad3-1df4-43dd-857f-f944fc7c2921','齊梁怨別','陸龜蒙','唐','唐诗','tang','','[]','寥寥缺月看將落，簷外霜華染羅幕。',32,'全唐诗/poet.tang.34000.json','["寥寥缺月看將落，簷外霜華染羅幕。", "不知蘭櫂到何山，應倚相思樹邊泊。"]'),
('3273a61f-c50d-4dd0-a8af-309ad228d869','閑居雜題五首 鳴蜩早','陸龜蒙','唐','唐诗','tang','','[]','閑來倚杖柴門口，鳥下深枝啄晚蟲。',32,'全唐诗/poet.tang.34000.json','["閑來倚杖柴門口，鳥下深枝啄晚蟲。", "周步一池銷半日，十年聽此鬢如蓬。"]'),
('a28f68d4-2cfa-46f9-9bd4-55e0fb9eae2a','閑居雜題五首 野態真','陸龜蒙','唐','唐诗','tang','','[]','君如有意躭田里，予亦無機向藝能。',32,'全唐诗/poet.tang.34000.json','["君如有意躭田里，予亦無機向藝能。", "心跡所便唯是直，人間聞道最先憎。"]'),
('ee26e12e-b0e8-423b-9852-eebbe27c2385','閑居雜題五首 松間斟','陸龜蒙','唐','唐诗','tang','','[]','子山園靜憐幽木，公幹詞清詠蓽門。',32,'全唐诗/poet.tang.34000.json','["子山園靜憐幽木，公幹詞清詠蓽門。", "月上風微蕭灑甚，斗醪何惜置盈尊。"]'),
('e5ed5d8c-b7a4-401c-ba13-248b9eec4c12','閑居雜題五首 飲巖泉','陸龜蒙','唐','唐诗','tang','','[]','已甘茅洞三君食，欠買桐江一朵山。',32,'全唐诗/poet.tang.34000.json','["已甘茅洞三君食，欠買桐江一朵山。", "嚴子瀨高秋浪白，水禽飛盡釣舟還。"]'),
('097c8634-6299-430a-9c02-ce4ecca68b5a','閑居雜題五首 當軒鶴','陸龜蒙','唐','唐诗','tang','','[]','自笑與人乖好尚，田家山客共柴車。',32,'全唐诗/poet.tang.34000.json','["自笑與人乖好尚，田家山客共柴車。", "干時未似棲廬雀，鳥道閑攜相爾書。"]'),
('1bcd5975-60f6-4a37-819c-a163bc824b36','藥名離合夏日即事三首 一','陸龜蒙','唐','唐诗','tang','','[]','乘屐著來幽砌滑，石甖煎得遠泉甘。',32,'全唐诗/poet.tang.34000.json','["乘屐著來幽砌滑，石甖煎得遠泉甘。", "草堂祗待新秋景，天色微涼酒半酣。"]'),
('6726a84b-1506-4d8b-84f9-0e7836c9a639','藥名離合夏日即事三首 二','陸龜蒙','唐','唐诗','tang','','[]','避暑最須從樸野，葛巾筠席更相當。',32,'全唐诗/poet.tang.34000.json','["避暑最須從樸野，葛巾筠席更相當。", "歸來又好乘涼釣，藤蔓陰陰著雨香。"]'),
('4d717d5a-440e-4126-a86c-b3fc63a7b1a2','藥名離合夏日即事三首 三','陸龜蒙','唐','唐诗','tang','','[]','窗外曉簾還自卷，柏煙蘭露思晴空。',32,'全唐诗/poet.tang.34000.json','["窗外曉簾還自卷，柏煙蘭露思晴空。", "青箱有意終須續，斷簡遺編一半通。"]'),
('cbe3432c-649b-4caa-a8ed-b09f44fc3346','和襲美懷錫山藥名離合二首 一','陸龜蒙','唐','唐诗','tang','','[]','鶴伴前溪栽白杏，人來陰洞寫枯松。',32,'全唐诗/poet.tang.34000.json','["鶴伴前溪栽白杏，人來陰洞寫枯松。", "蘿深境靜日欲落，石上未眠聞遠鐘。"]'),
('0104af5c-11d7-4187-aaeb-15c74a543981','和襲美懷錫山藥名離合二首 二','陸龜蒙','唐','唐诗','tang','','[]','佳句成來誰不伏，神丹偷去亦須防。',32,'全唐诗/poet.tang.34000.json','["佳句成來誰不伏，神丹偷去亦須防。", "風前莫怪攜詩藁，本是吳吟蕩槳郎。"]'),
('a95f90d2-6817-4810-8db5-e5ec8901062a','和襲美懷鹿門縣名離合二首 一','陸龜蒙','唐','唐诗','tang','','[]','雲容覆枕無非白，水色侵磯直是藍。',32,'全唐诗/poet.tang.34000.json','["雲容覆枕無非白，水色侵磯直是藍。", "田種紫芝餐可壽，春來何事戀江南。"]'),
('8cf2b140-3b34-4225-bb4b-61784e90a90e','和襲美懷鹿門縣名離合二首 二','陸龜蒙','唐','唐诗','tang','','[]','竹溪深處猿同宿，松閣秋來客共登。',32,'全唐诗/poet.tang.34000.json','["竹溪深處猿同宿，松閣秋來客共登。", "封逕古苔侵石鹿，城中誰解訪山僧。"]'),
('10d48c99-ce50-476f-b794-51b36685d814','寒日古人名','陸龜蒙','唐','唐诗','tang','','[]','初寒朗詠裴回立，欲謝玄關早晚開。',32,'全唐诗/poet.tang.34000.json','["初寒朗詠裴回立，欲謝玄關早晚開。", "昨日登樓望江色，魚梁鴻雁幾多來。"]'),
('abf1d337-0015-4290-8f89-baab9ff81ace','句','陸龜蒙','唐','唐诗','tang','','[]','幾點社翁雨，一番花信風。',104,'全唐诗/poet.tang.34000.json','["幾點社翁雨，一番花信風。", "水鳥歌婦女，衣襟便佞舌。", "溪山自是清涼國，松竹合封蕭灑侯。", "山上花明水上曛，一橈青翰破霞文。", "白帝霜輿欲御秋，但說漱流幷枕石。", "不辭蟬腹與龜腸，頭方不會王門事。", "塵土空緇白苧衣，秋來嬾上向吳亭。"]'),
('57129e3e-10f9-4ab2-b911-dd7cca65a624','旅泊吳門','張賁','唐','唐诗','tang','','[]','一舸吳江晚，堪憂病廣文。',48,'全唐诗/poet.tang.34000.json','["一舸吳江晚，堪憂病廣文。", "鱸魚誰與伴，鷗鳥自成羣。", "反照縱橫水，斜空斷續雲。", "異鄉無限思，盡付酒醺醺。"]'),
('2e30a622-74ae-45e9-80a6-9446cead945a','賁中間有吳門旅泊之什蒙魯望垂和更作一章以伸詶謝','張賁','唐','唐诗','tang','','[]','偶發陶匏響，皆蒙組繡文。',48,'全唐诗/poet.tang.34000.json','["偶發陶匏響，皆蒙組繡文。", "清秋將落帽，子夏正離羣。", "有恨書燕雁，無聊賦郢雲。", "徧看心自醉，不是酒能醺。"]'),
('fdf0988e-4e02-4515-b868-ea7217af50de','酬襲美先見寄倒來韻','張賁','唐','唐诗','tang','','[]','尋疑天意喪斯文，故選茅峰寄白雲。',64,'全唐诗/poet.tang.34000.json','["尋疑天意喪斯文，故選茅峰寄白雲。", "酒後只留滄海客，香前唯見紫陽君。", "近年已絕詩書癖，今日兼將筆硯焚。", "爲有此身猶苦患，不知何者是玄纁。"]'),
('a7b100c8-843d-48a0-8670-2e933691d636','奉和襲美醉中即席見贈次韻','張賁','唐','唐诗','tang','','[]','桂枝新下月中仙，學海詞鋒譽藹然。',64,'全唐诗/poet.tang.34000.json','["桂枝新下月中仙，學海詞鋒譽藹然。", "文陣已推忠信甲，窮波猶認孝廉船。", "清標稱住羊車上，俗韻慚居鶴氅前。", "共許逢蒙快弓箭，再穿楊葉在明年。"]'),
('89ac8f5c-8a4f-461d-a472-d943b2434eff','奉和襲美題褚家林亭','張賁','唐','唐诗','tang','','[]','疎野林亭震澤西，朗吟閑步喜相攜。',64,'全唐诗/poet.tang.34000.json','["疎野林亭震澤西，朗吟閑步喜相攜。", "時時風折蘆花亂，處處霜摧稻穗低。", "百本敗荷魚不動，一枝寒菊蝶空迷。", "今朝偶得高陽伴，從放山翁醉似泥。"]'),
('8b5a94d1-9d72-4b8b-84cb-3c537cb906ae','奉和襲美傷開元觀顧道士','張賁','唐','唐诗','tang','','[]','鳳麟膠盡夜如何，共歎先生劒解多。',64,'全唐诗/poet.tang.34000.json','["鳳麟膠盡夜如何，共歎先生劒解多。", "幾度弔來唯白鶴，此時乘去必青騾。", "圖中含景隨殘照，琴裏流泉寄逝波。", "惆悵真靈又空返，玉書誰授紫微歌。"]'),
('4c09aa73-453f-4edb-953d-0f72a14a1e5c','和魯望白菊','張賁','唐','唐诗','tang','','[]','雪彩冰姿號女華，寄身多是地仙家。',64,'全唐诗/poet.tang.34000.json','["雪彩冰姿號女華，寄身多是地仙家。", "有時南國和霜立，幾處東籬伴月斜。", "謝客瓊枝空貯恨，袁郎金鈿不成誇。", "自知終古清香在，更出梅粧弄晚霞。"]'),
('c441adbc-85b9-4657-8beb-99578b8c9694','奉和襲美先輩悼鶴','張賁','唐','唐诗','tang','','[]','池塘蕭索掩空籠，玉樹同嗟一土中。',64,'全唐诗/poet.tang.34000.json','["池塘蕭索掩空籠，玉樹同嗟一土中。", "莎徑罷鳴唯泣露，松軒休舞但悲風。", "丹臺舊氅難重緝，紫府新書豈更通。", "雲減霧消無處問，只留華髪與衰翁。"]'),
('cd90c1b8-1fc1-45d2-a271-7bf75d00ed91','偶約道流終乖文會荅皮陸','張賁','唐','唐诗','tang','','[]','僊侶無何訪蔡經，兩煩韶濩出彤庭。',32,'全唐诗/poet.tang.34000.json','["僊侶無何訪蔡經，兩煩韶濩出彤庭。", "人間若有登樓望，應怪文星近客星。"]'),
('b442473d-d223-4395-b96d-f03b8a654147','和襲美寒夜見訪','張賁','唐','唐诗','tang','','[]','雲孤鶴獨且相親，倣効從它折角巾。',32,'全唐诗/poet.tang.34000.json','["雲孤鶴獨且相親，倣効從它折角巾。", "不用吳江歎留滯，風姿俱是玉清人。"]'),
('d4a251de-a717-42fd-89e9-f280c842b76d','和襲美醉中先起次韻','張賁','唐','唐诗','tang','','[]','何事桃源路忽迷，惟留雲雨怨空閨。',32,'全唐诗/poet.tang.34000.json','["何事桃源路忽迷，惟留雲雨怨空閨。", "僊郎共許多情調，莫遣重歌濁水泥。"]'),
('bb1ba039-5aec-4134-8ff6-d725283a3661','和皮陸酒病偶作','張賁','唐','唐诗','tang','','[]','白編椰席鏤冰明，應助楊青解宿酲。',32,'全唐诗/poet.tang.34000.json','["白編椰席鏤冰明，應助楊青解宿酲。", "難繼二賢金玉唱，可憐空作斷猿聲。"]'),
('2c12f0d1-54d9-4333-8e5c-ed76e5f4d35a','送浙東德師侍御罷府西歸','張賁','唐','唐诗','tang','','[]','孤雲獨鳥本無依，江海重逢故舊稀。',32,'全唐诗/poet.tang.34000.json','["孤雲獨鳥本無依，江海重逢故舊稀。", "楊柳漸疏蘆葦白，可憐斜日送君歸。"]'),
('cad6eee4-da47-45db-b543-8c78aea16a34','以青䭀飯分送襲美魯望因成一絕','張賁','唐','唐诗','tang','','[]','誰屑瓊瑤事青䭀，舊傳名品出華陽。',32,'全唐诗/poet.tang.34000.json','["誰屑瓊瑤事青䭀，舊傳名品出華陽。", "應宜仙子胡麻拌，因送劉郎與阮郎。"]'),
('6125ff1b-4d83-4c92-96fd-5344c5159797','玩金鸂鶒和陸魯望','張賁','唐','唐诗','tang','','[]','翠羽紅襟鏤彩雲，雙飛常笑白鷗羣。',32,'全唐诗/poet.tang.34000.json','["翠羽紅襟鏤彩雲，雙飛常笑白鷗羣。", "誰憐化作彫金質，從倩沈檀十里聞。"]'),
('c4d65a3a-d979-4192-8cf5-d5f3032963f4','悼鶴和襲美','張賁','唐','唐诗','tang','','[]','渥頂鮮毛品格馴，莎庭閑暇重難羣。',32,'全唐诗/poet.tang.34000.json','["渥頂鮮毛品格馴，莎庭閑暇重難羣。", "無端日暮東風起，飄散春空一片雲。"]'),
('7001442d-0f58-4800-a025-b65f78bcc03d','覽皮先輩盛製因作十韻以寄用伸欵仰','崔璐','唐','唐诗','tang','','[]','河嶽挺靈異，星辰精氣殊。',131,'全唐诗/poet.tang.34000.json','["河嶽挺靈異，星辰精氣殊。", "在人爲英傑，與國作禎符。", "襄陽得奇士，俊邁真龍駒。", "勇果魯仲由，文賦蜀相如。", "渾浩江海廣，葩華桃李敷。", "小言入無間，大言塞空虛。", "幾人游赤水，夫子得玄珠。", "鬼神爭奧秘，天地惜洪鑪。", "既有曾參行，仍兼君子儒。", "吾知上帝意，將使居黃樞。", "好保千金體須爲萬姓謨。"]'),
('791dd72a-e767-4777-a4f2-6e67ff1c194f','浙東罷府西歸酬別張廣文皮先輩陸秀才','李縠','唐','唐诗','tang','','[]','豈有頭風筆下痊，浪成蠻語向初筵。',64,'全唐诗/poet.tang.34000.json','["豈有頭風筆下痊，浪成蠻語向初筵。", "蘭亭舊趾雖曾見，柯笛遺音更不傳。", "照曜文星吳分野，留連花月晉名賢。", "相逢只恨相知晚，一曲驪歌又幾年。"]'),
('0ee9ec1c-d9d7-4071-b15f-c345c7af94d3','和皮日休悼鸖 一','李縠','唐','唐诗','tang','','[]','才子襟期本上清，陸雲家鸖伴閑情。',64,'全唐诗/poet.tang.34000.json','["才子襟期本上清，陸雲家鸖伴閑情。", "猶憐反顧五六里，何意忽歸十二城。", "露滴誰聞高葉墜，月沈休藉半階明。", "人聞華表堪留語，剩向秋風寄一聲。"]'),
('1b706a48-98a7-4885-8e6d-0d171601bddf','和皮日休悼鸖 二','李縠','唐','唐诗','tang','','[]','道林曾放雪翎飛，應悔庭除閉羽衣。',32,'全唐诗/poet.tang.34000.json','["道林曾放雪翎飛，應悔庭除閉羽衣。", "料得王恭披鶴氅，倚吟猶待月中歸。"]'),
('4888f87e-e982-4290-8f21-4d4daceffeda','醉中襲美先月中歸','李縠','唐','唐诗','tang','','[]','休文雖即逃瓊液，阿鶩還須掩玉閨。',32,'全唐诗/poet.tang.34000.json','["休文雖即逃瓊液，阿鶩還須掩玉閨。", "月落金雞一聲後，不知誰悔醉如泥。"]'),
('fbc64d79-0672-454c-9255-e48d063e44f6','奉酬皮先輩霜菊見贈','崔璞','唐','唐诗','tang','','[]','菊花開晚過秋風，聞道芳香正滿叢。',32,'全唐诗/poet.tang.34000.json','["菊花開晚過秋風，聞道芳香正滿叢。", "爭奈病夫難強飲，應須速自召車公。"]'),
('f10352a8-0550-4d3c-84eb-2d827df74664','蒙恩除替將還京洛偶敘所懷因成六韻呈軍事院諸公郡中一二秀才','崔璞','唐','唐诗','tang','','[]','兩載求人瘼，三春受代歸。',72,'全唐诗/poet.tang.34000.json','["兩載求人瘼，三春受代歸。", "務繁多簿籍，才短乏恩威。", "共理乖天獎，分憂值歲饑。", "遽蒙交郡印，安敢整朝衣。", "作牧慙爲政，思鄉念式微。", "儻容還故里，高臥掩柴扉。"]'),
('4bc57590-dfe1-4b77-8c07-9602fee81d15','和皮日休悼鶴 一','魏朴','唐','唐诗','tang','','[]','直欲裁詩問杳冥，豈教靈化亦浮生。',64,'全唐诗/poet.tang.34000.json','["直欲裁詩問杳冥，豈教靈化亦浮生。", "風林月動疑留魄，沙島香愁似蘊情。", "雪骨夜封蒼蘚冷，練衣寒在碧塘輕。", "人間飛去猶堪恨，況是泉臺遠玉京。"]'),
('029ea817-db6d-4bc7-ba4a-c41ac89f1906','和皮日休悼鶴 二','魏朴','唐','唐诗','tang','','[]','經秋宋玉已悲傷，況報胎禽昨夜亡。',32,'全唐诗/poet.tang.34000.json','["經秋宋玉已悲傷，況報胎禽昨夜亡。", "霜曉起來無問處，伴僧彈指遶荷塘。"]'),
('7c30208b-3ac6-4db4-b192-5c8fba086632','皮襲美見留小讌次韻','羊昭業','唐','唐诗','tang','','[]','澤國春來少遇晴，有花開日且飛觥。',64,'全唐诗/poet.tang.34000.json','["澤國春來少遇晴，有花開日且飛觥。", "王戎似電休推病，周顗纔醒衆却驚。", "芳景漸濃偏屬酒，煖風初暢欲調鶯。", "知君不肯然官燭，爭得華筵徹夜明。"]'),
('52f8fbad-d2ff-4a46-bfe9-2f6edb420a5e','送羊振文歸覲桂陽','顏萱','唐','唐诗','tang','','[]','高掛吳帆喜動容，問安歸去指湘峯。',64,'全唐诗/poet.tang.34000.json','["高掛吳帆喜動容，問安歸去指湘峯。", "懸魚庭內芝蘭秀，馭鶴門前薜荔封。", "紅斾正憐棠影茂，綵衣偏帶桂香濃。", "臨岐獨有霑襟戀，南巷當年共化龍。"]'),
('0d7f7e19-b14c-4c13-82f1-57183806eb6f','送圓載上人','顏萱','唐','唐诗','tang','','[]','師來一世恣經行，却泛滄波問去程。',64,'全唐诗/poet.tang.34000.json','["師來一世恣經行，却泛滄波問去程。", "心靜已能防渴鹿，鼙喧時爲駭長鯨。", "禪林幾結金桃重，梵室重修鐵瓦輕。", "料得還鄉無別利，只應先見日華生。"]'),
('9becd08a-f601-41fd-89f9-8525bc304752','過張祜處士丹陽故居','顏萱','唐','唐诗','tang','','[]','憶昔爲兒逐我兄，曾拋竹馬拜先生。',64,'全唐诗/poet.tang.34000.json','["憶昔爲兒逐我兄，曾拋竹馬拜先生。", "書齋已換當時主，詩壁空題故友名。", "豈是爭權留怨敵，可憐當路盡公卿。", "柴扉草屋無人問，猶向荒田責地征。"]'),
('b02fa792-0e36-435c-a10c-03a63da22044','和襲美傷顧道士','鄭璧','唐','唐诗','tang','','[]','斜漢銀瀾一夜東，飄飄何處五雲中。',64,'全唐诗/poet.tang.34000.json','["斜漢銀瀾一夜東，飄飄何處五雲中。", "空留華表千年約，纔畢丹爐九轉功。", "形蛻遠山孤壙月，影寒深院曉松風。", "門人不覩飛昇去，猶與浮生哭恨同。"]'),
('ecec8663-2b01-4419-9fdd-9627999cac71','奉和陸魯望白菊','鄭璧','唐','唐诗','tang','','[]','白豔輕明帶露痕，始知佳色重難羣。',64,'全唐诗/poet.tang.34000.json','["白豔輕明帶露痕，始知佳色重難羣。", "終朝疑笑梁王雪，盡日慵飛蜀帝魂。", "燕雨似翻瑤渚浪，雁風疑卷玉綃紋。", "瓊妃若會寬裁剪，堪作蟾宮夜舞裙。"]'),
('01c5bb29-e46d-4ba8-804f-f5cb33797a97','和襲美索友人酒','鄭璧','唐','唐诗','tang','','[]','乘興閑來小謝家，便裁詩句乞榴花。',32,'全唐诗/poet.tang.34000.json','["乘興閑來小謝家，便裁詩句乞榴花。", "邴原雖不無端醉，也愛臨風從鹿車。"]'),
('cb3e1096-96d8-42f2-b280-0d9752865453','文燕潤卿不至','鄭璧','唐','唐诗','tang','','[]','已知羽駕朝金闕，不用燒蘭望玉京。',32,'全唐诗/poet.tang.34000.json','["已知羽駕朝金闕，不用燒蘭望玉京。", "應是易遷明月好，玉皇留看舞雙成。"]'),
('0a021c72-51ec-44f4-9e77-54ca743e6828','塞上','司空圖','唐','唐诗','tang','','[]','萬里隋城在，三邊虜氣衰。',48,'全唐诗/poet.tang.34000.json','["萬里隋城在，三邊虜氣衰。", "沙填孤障角，燒斷故關碑。", "馬色經寒慘，鵰聲帶晚悲。", "將軍正閑暇，留客換歌辭。"]'),
('7d64b6b4-e16e-45a5-a0aa-2735a4f8e215','寄永嘉崔道融','司空圖','唐','唐诗','tang','','[]','旅寓雖難定，乘閑是勝遊。',48,'全唐诗/poet.tang.34000.json','["旅寓雖難定，乘閑是勝遊。", "碧雲蕭寺霽，紅樹謝邨秋。", "戍鼓和潮暗，船燈照島幽。", "詩家多滯此，風景似相留。"]'),
('4b00e90b-87ca-4af0-9d8e-67a84e99e1f0','下方','司空圖','唐','唐诗','tang','','[]','三十年來往，中間京洛塵。',48,'全唐诗/poet.tang.34000.json','["三十年來往，中間京洛塵。", "倦行今白首，歸臥已清神。", "坡暖冬抽筍，松涼夏健人。", "更慚徵詔起，避世迹非真。"]'),
('bdf3942c-5309-4e6c-b68b-4afc31727a30','華下','司空圖','唐','唐诗','tang','','[]','日炙旱雲裂，迸爲千道血。',48,'全唐诗/poet.tang.34000.json','["日炙旱雲裂，迸爲千道血。", "天地沸一鑊，竟自烹妖孽。", "堯湯遇災數，災數還中輟。", "何事姦與邪，古來難撲滅。"]'),
('37aef846-ba0c-4581-a27b-647f0ed6dd46','僧舍貽友','司空圖','唐','唐诗','tang','','[]','笑破人間事，吾徒莫自欺。',48,'全唐诗/poet.tang.34000.json','["笑破人間事，吾徒莫自欺。", "解吟僧亦俗，愛舞鶴終卑。", "竹上題幽夢，溪邊約敵棋。", "舊山歸有阻，不是故遲遲。"]'),
('ab6916a7-d810-4493-bac0-8c5011d97b9d','下方','司空圖','唐','唐诗','tang','','[]','昏旦松軒下，怡然對一瓢。',48,'全唐诗/poet.tang.34000.json','["昏旦松軒下，怡然對一瓢。", "雨微吟思足，花落夢無聊。", "細事當棋遣，衰容喜鏡饒。", "溪僧有深趣，書至又相邀。"]'),
('7cf5461f-d960-4d7a-8a73-ceeca751aba9','華下送文浦','司空圖','唐','唐诗','tang','','[]','郊居謝名利，何事最相親。',48,'全唐诗/poet.tang.34000.json','["郊居謝名利，何事最相親。", "漸與論詩久，皆知得句新。", "川明虹照雨，樹密鳥衝人。", "應念從今去，還來嶽下頻。"]'),
('4ca42972-dd6a-4289-9f4e-342f57724d9e','自誡','司空圖','唐','唐诗','tang','','[]','我祖銘座右，嘉謀貽厥孫。',72,'全唐诗/poet.tang.34000.json','["我祖銘座右，嘉謀貽厥孫。", "勤此苟不怠，令名日可存。", "媒衒士所耻，慈儉道所尊。", "松柏豈不茂，桃李亦自繁。", "衆人皆察察，而我獨昏昏。", "取訓於老氏，大辯欲訥言。"]'),
('f54663fd-b928-46f0-bb5d-bd1945944b9c','效陳拾遺子昂感遇二首 一','司空圖','唐','唐诗','tang','','[]','高燕飛何捷，啄害恣羣雛。',48,'全唐诗/poet.tang.34000.json','["高燕飛何捷，啄害恣羣雛。", "人豈玩其暴，華軒容爾居。", "強欺自天稟，剛吐信吾徒。", "乃知不平者，矯世道終孤。"]'),
('3bdd9b51-383d-432b-a92d-186f6c2dfffa','效陳拾遺子昂感遇二首 二','司空圖','唐','唐诗','tang','','[]','陽和含煦潤，卉木競紛華。',48,'全唐诗/poet.tang.34000.json','["陽和含煦潤，卉木競紛華。", "當爲衆所悅，私已汝何誇。", "北里祕穠豔，東園鎖名花。", "豪奪乃常理，笑君徒咄嗟。"]'),
('d00d47e5-01b3-4f6d-aca4-4fd98ad42ff6','效陳拾遺子昂','司空圖','唐','唐诗','tang','','[]','醜婦競簪花，花多映愈醜。',48,'全唐诗/poet.tang.34000.json','["醜婦競簪花，花多映愈醜。", "鄰女恃其姿，掇之不盈手。", "量已苟自私，招損乃誰咎。", "寵祿既非安，於吾竟何有。"]'),
('c6030294-408d-4a87-97e1-09351beea88c','感時','司空圖','唐','唐诗','tang','','[]','好鳥無惡聲，仁獸肯狂噬。',48,'全唐诗/poet.tang.34000.json','["好鳥無惡聲，仁獸肯狂噬。", "寧教鸚鵡啞，不遣麒麟細。", "人人語與默，唯觀利與勢。", "愛毀亦自遭，掩謗終失計。"]'),
('87c3f808-d989-4378-8294-5cbea8c14dd9','秋思','司空圖','唐','唐诗','tang','','[]','身病時亦危，逢秋多慟哭。',48,'全唐诗/poet.tang.34000.json','["身病時亦危，逢秋多慟哭。", "風波一搖蕩，天地幾翻覆。", "孤螢出荒池，落葉穿破屋。", "勢利長草草，何人訪幽獨。"]'),
('79b1ff3a-4f6f-4fbf-8c44-8bba127d9f66','早春','司空圖','唐','唐诗','tang','','[]','傷懷同客處，病眼却花朝。',48,'全唐诗/poet.tang.34000.json','["傷懷同客處，病眼却花朝。", "草嫩侵沙短，冰輕著雨消。", "風光知可愛，容髪不相饒。", "早晚丹丘去，飛書肯見招。"]'),
('f03d611e-5d89-4095-9eac-6a385e0fb095','上陌梯寺懷舊僧二首 一','司空圖','唐','唐诗','tang','','[]','雲根禪客居，皆說舊無廬。',48,'全唐诗/poet.tang.34000.json','["雲根禪客居，皆說舊無廬。", "松日明金像，山風嚮木魚。", "依棲應不阻，名利本來疎。", "縱有人相問，林間懶拆書。"]'),
('d94c5527-f273-49a9-82dc-73ed7fb42a62','上陌梯寺懷舊僧二首 二','司空圖','唐','唐诗','tang','','[]','高鴉隔谷見，路轉寺西門。',48,'全唐诗/poet.tang.34000.json','["高鴉隔谷見，路轉寺西門。", "塔影蔭泉脉，山苗侵燒痕。", "鐘疎含杳靄，閤迥亙黃昏。", "更待他僧到，長如前信存。"]'),
('efcfa628-fff4-437f-a738-c9b1fe44a009','寄懷元秀上人','司空圖','唐','唐诗','tang','','[]','悠悠干祿利，草草廢漁樵。',48,'全唐诗/poet.tang.34000.json','["悠悠干祿利，草草廢漁樵。", "身世堪惆悵，風騷頓寂寥。", "高秋期步野，積雨放趨朝。", "得句如相憶，莎齋且見招。"]'),
('66fea6aa-a90c-4a06-bdad-c83c241ddbcb','次韻和秀上人遊南五臺','司空圖','唐','唐诗','tang','','[]','中峰曾到處，題記沒蒼苔。',48,'全唐诗/poet.tang.34000.json','["中峰曾到處，題記沒蒼苔。", "振錫傳深谷，翻經想舊臺。", "危松臨砌偃，驚鹿驀溪來。", "內殿御詩切，身迴心未迴。"]'),
('7c151dd4-1277-4d8d-a593-ca7051f16f93','贈圓昉公','司空圖','唐','唐诗','tang','','[]','天階讓紫衣，冷格鶴猶卑。',48,'全唐诗/poet.tang.34000.json','["天階讓紫衣，冷格鶴猶卑。", "道勝嫌名出，身閑覺老遲。", "曉香延宿火，寒磬度高枝。", "每說長松寺，他年與我期。"]'),
('6200f915-f9f1-4e37-b582-3e3257312600','贈信美寺岑上人','司空圖','唐','唐诗','tang','','[]','巡禮諸方遍，湘南頻有緣。',48,'全唐诗/poet.tang.34000.json','["巡禮諸方遍，湘南頻有緣。", "焚香老山寺，乞食向江船。", "紗碧籠名畫，燈寒照淨禪。", "我來能永日，蓮漏滴寒泉。"]'),
('66dd272d-28ba-4a9e-ab1f-c782204ba6e8','江行二首 一','司空圖','唐','唐诗','tang','','[]','地闊分吳塞，楓高映楚天。',48,'全唐诗/poet.tang.34000.json','["地闊分吳塞，楓高映楚天。", "曲塘春盡雨，方響夜深船。", "行紀添新夢，羇愁甚往年。", "何時京洛路，馬上見人煙。"]'),
('324bdea3-0134-40ec-919b-f634e53db080','江行二首 二','司空圖','唐','唐诗','tang','','[]','初程風信好，迴望失津樓。',48,'全唐诗/poet.tang.34000.json','["初程風信好，迴望失津樓。", "日帶潮聲晚，煙含楚色秋。", "戍旗當遠客，島樹轉驚鷗。", "此去非名利，孤帆任白頭。"]'),
('928167f0-6d43-49ce-b79e-430769b40442','長安贈王注','司空圖','唐','唐诗','tang','','[]','正下搜賢詔，多君獨避名。',48,'全唐诗/poet.tang.34000.json','["正下搜賢詔，多君獨避名。", "客來當意愜，花發遇歌成。", "樂地留高趣，權門讓後生。", "東方御閑駟，園外好同行。"]'),
('3dc69017-db2e-4c60-b6c3-241fd9eb1450','贈步寄李員外','司空圖','唐','唐诗','tang','','[]','危橋轉溪路，經雨石叢荒。',48,'全唐诗/poet.tang.34000.json','["危橋轉溪路，經雨石叢荒。", "幽瀑下仙果，孤巢懸夕陽。", "病辭青瑣祕，心在紫芝房。", "更喜諧招隱，詩家有望郎。"]'),
('e0b73496-a4d7-4fbf-8dc8-765978255e84','寄鄭仁規','司空圖','唐','唐诗','tang','','[]','清才鄭小戎，標的貴遊中。',48,'全唐诗/poet.tang.34000.json','["清才鄭小戎，標的貴遊中。", "萬里雲無侶，三山鶴不籠。", "香和丹地暖，晚着綵衣風。", "榮路期經濟，唯應在至公。"]'),
('54395fd2-5b20-4b7e-88c8-8b9086fc8059','寄考功王員外','司空圖','唐','唐诗','tang','','[]','喜聞三字耗，閑客是陪遊。',48,'全唐诗/poet.tang.34000.json','["喜聞三字耗，閑客是陪遊。", "白鳥閑疎索，青山日滯留。", "琴如高韻稱，詩愧逸才酬。", "更勉匡君志，論思在獻謀。"]'),
('0b076717-ce79-4aa5-bf69-1b9e8e1562d4','雜言','司空圖','唐','唐诗','tang','','[]','鳥飛飛，兔蹶蹶，朝來暮去驅時節。',32,'全唐诗/poet.tang.34000.json','["鳥飛飛，兔蹶蹶，朝來暮去驅時節。", "女媧只解補青天，不解煎膠黏日月。"]'),
('5256e95b-1288-4a1b-934b-253319c6eba1','陳疾','司空圖','唐','唐诗','tang','','[]','自憐旅舍亦酣歌，世路無機奈爾何。',64,'全唐诗/poet.tang.34000.json','["自憐旅舍亦酣歌，世路無機奈爾何。", "霄漢逼來心不動，鬢毛白盡興猶多。", "殘陽暫照鄉關近，遠鳥因投嶽廟過。", "閑得此身歸未得，磬聲深夏隔煙蘿。"]'),
('2d31c75c-98e3-45f4-bd77-25b52e6534db','淅上 一','司空圖','唐','唐诗','tang','','[]','華下支離已隔河，又來此地避干戈。',64,'全唐诗/poet.tang.34000.json','["華下支離已隔河，又來此地避干戈。", "山田漸廣猨時到，邨舍新添燕亦多。", "丹桂石楠宜並長，秦雲楚雨暗相和。", "兒童栗熟迷歸路，歸得仍隨牧豎歌。"]'),
('05d9f2e3-da4c-4e13-959d-22bd7b6a6565','淅上 二','司空圖','唐','唐诗','tang','','[]','西北鄉關近帝京，煙塵一片正傷情。',64,'全唐诗/poet.tang.34000.json','["西北鄉關近帝京，煙塵一片正傷情。", "愁看地色連空色，靜聽歌聲似哭聲。", "紅蓼滿邨人不在，青山遶檻路難平。", "從他煙棹更南去，休向津頭問去程。"]');
